# ══════════════════════════════════════════════════════════════════════════════
# REMOTE MARKS ENTRY  ·  iQ School Systems v4.0
# ─────────────────────────────────────────────────────────────────────────────
# Three modes, in priority order:
#   1. CLOUD MODE  — iQ_Cloud_Server deployed on Render/Railway (free tier).
#                    Works 24/7 even when the school PC is OFF.
#                    Teachers anywhere in the world can submit marks.
#                    Desktop app syncs marks ↔ cloud on demand.
#   2. STANDALONE  — iQ_Remote_Server.py running as a separate process with
#                    ngrok tunnel.  PC must be on; app can be closed.
#   3. IN-PROCESS  — Embedded Flask server + optional ngrok tunnel.
#                    PC must stay on AND app must stay open.
#
# Dependencies: pip install flask pyngrok requests
# ══════════════════════════════════════════════════════════════════════════════
import threading as _rmt_threading
import secrets   as _rmt_secrets
import socket    as _rmt_socket
import pathlib   as _pathlib

_RMT_TOKENS: dict         = {}
_RMT_SERVER_STARTED       = False
_RMT_PORT                 = 5050
_RMT_FLASK_THREAD         = None
_RMT_NGROK_AUTHTOKEN: str = ""
_RMT_NGROK_RECONNECT      = False
_RMT_NGROK_URL: str       = ""
_RMT_CLOUD_URL: str       = ""     # set when cloud server URL is configured
_RMT_CLOUD_TOKEN: str     = ""     # admin token for the cloud server

_RMT_URL_FILE  = str(_pathlib.Path(__file__).parent / "iq_remote_url.txt")
_RMT_PID_FILE  = str(_pathlib.Path(__file__).parent / "iq_remote_server.pid")
_RMT_CLOUD_CFG = str(_pathlib.Path(__file__).parent / "iq_cloud.json")

# ── token helpers ─────────────────────────────────────────────────────────────
def _rmt_make_token(section: str) -> str:
    tok = _rmt_secrets.token_urlsafe(24)
    _RMT_TOKENS[section] = tok
    return tok

def _rmt_check_token(tok: str, section=None) -> bool:
    if section:
        return _rmt_secrets.compare_digest(tok or "", _RMT_TOKENS.get(section, ""))
    return any(_rmt_secrets.compare_digest(tok or "", t) for t in _RMT_TOKENS.values())

def _rmt_get_local_ip() -> str:
    try:
        s = _rmt_socket.socket(_rmt_socket.AF_INET, _rmt_socket.SOCK_DGRAM)
        s.connect(("8.8.8.8", 80)); ip = s.getsockname()[0]; s.close(); return ip
    except Exception:
        return "127.0.0.1"

def _rmt_find_free_port(preferred=5050) -> int:
    for port in [preferred] + list(range(5051, 5080)):
        try:
            with _rmt_socket.socket(_rmt_socket.AF_INET, _rmt_socket.SOCK_STREAM) as s:
                s.bind(("0.0.0.0", port)); return port
        except OSError:
            continue
    return preferred

# ── cloud config persistence ──────────────────────────────────────────────────
def _rmt_save_cloud_cfg(url: str, token: str):
    try:
        with open(_RMT_CLOUD_CFG, "w", encoding="utf-8") as f:
            json.dump({"cloud_url": url, "cloud_token": token}, f, indent=2)
    except Exception:
        pass

def _rmt_load_cloud_cfg() -> tuple:
    """Returns (url, token) from saved cloud config or CFG."""
    try:
        with open(_RMT_CLOUD_CFG, "r", encoding="utf-8") as f:
            d = json.load(f)
            return d.get("cloud_url", ""), d.get("cloud_token", "")
    except Exception:
        pass
    # Fall back to main config
    try:
        return CFG.get("cloud_url", ""), CFG.get("cloud_token", "")
    except Exception:
        return "", ""

# ── standalone server detection ───────────────────────────────────────────────
def _rmt_standalone_running() -> bool:
    try:
        with open(_RMT_PID_FILE, "r") as f:
            pid = int(f.read().strip())
        import psutil; return psutil.pid_exists(pid)
    except Exception:
        try:
            import subprocess
            out = subprocess.check_output(
                ["tasklist", "/FI", "IMAGENAME eq python.exe", "/FO", "CSV"],
                stderr=subprocess.DEVNULL, text=True)
            return "iQ_Remote_Server" in out
        except Exception:
            return False

def _rmt_load_standalone_url() -> dict:
    try:
        with open(_RMT_URL_FILE, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {}

# ── ngrok helpers ─────────────────────────────────────────────────────────────
def _rmt_ngrok_available() -> bool:
    try:
        import pyngrok; return True  # noqa
    except ImportError:
        return False

def _rmt_start_ngrok(port=5050, authtoken: str = "") -> str:
    global _RMT_NGROK_AUTHTOKEN
    from pyngrok import ngrok as _ngrok, conf as _ngconf
    if authtoken:
        _RMT_NGROK_AUTHTOKEN = authtoken
        try: _ngconf.get_default().auth_token = authtoken
        except Exception:
            try: _ngrok.set_auth_token(authtoken)
            except Exception: pass
    try:
        for t in _ngrok.get_tunnels():
            addr = t.config.get("addr","") if isinstance(t.config, dict) else getattr(t,"addr","")
            if str(port) in str(addr): _ngrok.disconnect(t.public_url)
    except Exception: pass
    try:    tunnel = _ngrok.connect(addr=port, proto="http")
    except TypeError: tunnel = _ngrok.connect(port, "http")
    pub = getattr(tunnel, "public_url", None) or str(tunnel)
    return pub.replace("http://", "https://")

def _rmt_stop_ngrok():
    global _RMT_NGROK_URL
    try:
        from pyngrok import ngrok as _ngrok; _ngrok.kill()
    except Exception: pass
    _RMT_NGROK_URL = ""

# ── CBC grade → section helper ────────────────────────────────────────────────
def _rmt_grade_section(g: str) -> str:
    g2 = g.lower().replace(" ","").replace("-","")
    if g2 in {"pp1","pp2","nursery","preprimary1","preprimary2"}: return "preprimary"
    try:
        n = int(g2.replace("grade",""))
        if 1<=n<=3: return "lower"
        if 4<=n<=6: return "upper"
    except Exception: pass
    return "junior"

# ── link generator ────────────────────────────────────────────────────────────
def _rmt_generate_links(port=5050, base_url=None) -> dict:
    ip  = _rmt_get_local_ip()
    pub = base_url or f"http://{ip}:{port}"
    links = {}
    for sec in ("junior","upper","lower","preprimary"):
        tok = _rmt_make_token(sec)
        links[sec] = f"{pub}/enter/{sec}?token={tok}"
    return links

