_LIC_SALT     = "iQTimCheruiyot2025EMS"
_LIC_EDITIONS = ["TRIAL", "STANDARD", "PROFESSIONAL", "ENTERPRISE"]
_LIC_EPOCH    = date(2024, 1, 1)
_LIC_ALPHA    = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789"

def _lic_to_chars(data, n):
    val = int.from_bytes(data, "big"); chars = []
    for _ in range(n):
        chars.append(_LIC_ALPHA[val & 0x1F]); val >>= 5
    return "".join(reversed(chars))

def _lic_from_chars(s):
    val = 0
    for ch in s.upper():
        idx = _LIC_ALPHA.find(ch)
        if idx < 0: raise ValueError(f"Invalid character: {ch!r}")
        val = (val << 5) | idx
    return val

def lic_generate_key(school_id, expiry, edition):
    edition = edition.upper(); school_id = school_id.upper().strip()
    s_hash = int.from_bytes(hashlib.md5(school_id.encode()).digest()[:2], "big")
    expiry_days = 0xFFFFFF if expiry == "9999-12-31" else max(0, (
        datetime.strptime(expiry, "%Y-%m-%d").date() - _LIC_EPOCH).days)
    ed_idx = _LIC_EDITIONS.index(edition)
    payload = struct.pack(">H", s_hash) + expiry_days.to_bytes(3, "big") + bytes([ed_idx])
    msg = f"HASH:{s_hash:04X}|{expiry}|{edition}".encode()
    sig = hmac.new(_LIC_SALT.encode(), msg, hashlib.sha256).digest()[:4]
    body = _lic_to_chars(payload + sig, 16)
    return "IQ-" + "-".join(body[i:i+4] for i in range(0, 16, 4))

def lic_validate(key):
    bad = lambda r: {"valid": False, "reason": r, "school_id": "", "expiry": "", "edition": ""}
    key = key.strip().upper()
    if not key.startswith("IQ-"): return bad("Invalid format (must start with IQ-)")
    body = key[3:].replace("-", "")
    if len(body) != 16: return bad(f"Wrong key length (got {len(body)}, need 16)")
    try: val = _lic_from_chars(body)
    except ValueError as e: return bad(str(e))
    raw = val.to_bytes(10, "big")
    s_hash = struct.unpack(">H", raw[0:2])[0]
    expiry_days = int.from_bytes(raw[2:5], "big")
    ed_idx = raw[5]; given_sig = raw[6:10]
    if ed_idx >= len(_LIC_EDITIONS): return bad("Unknown edition in key")
    edition = _LIC_EDITIONS[ed_idx]
    expiry = "9999-12-31" if expiry_days == 0xFFFFFF else (
        _LIC_EPOCH + timedelta(days=expiry_days)).strftime("%Y-%m-%d")
    msg = f"HASH:{s_hash:04X}|{expiry}|{edition}".encode()
    expected = hmac.new(_LIC_SALT.encode(), msg, hashlib.sha256).digest()[:4]
    if not hmac.compare_digest(given_sig, expected):
        return bad("Signature invalid — key is forged or tampered")
    if expiry != "9999-12-31":
        if date.today() > datetime.strptime(expiry, "%Y-%m-%d").date():
            return {"valid": False, "reason": f"License expired on {expiry}",
                    "school_id": f"#{s_hash:04X}", "expiry": expiry, "edition": edition}
    return {"valid": True, "reason": "OK",
            "school_id": f"#{s_hash:04X}", "expiry": expiry, "edition": edition}

def _lic_path():
    # Uses the same BASE_DIR already computed for DB/config — correct in both
    # normal script mode and PyInstaller frozen .exe
    try:
        return os.path.join(BASE_DIR, "iq_license.dat")
    except NameError:
        import sys as _s
        base = os.path.dirname(_s.executable) if getattr(_s, "frozen", False) \
               else os.path.dirname(os.path.abspath(__file__))
        return os.path.join(base, "iq_license.dat")

def lic_save(key):
    try:
        # Plain text — more robust than JSON across platforms/encodings
        with open(_lic_path(), "w", encoding="utf-8") as f:
            f.write(key.strip().upper())
        return True
    except OSError:
        return False

def lic_load():
    p = _lic_path()
    if not os.path.exists(p):
        return None
    try:
        with open(p, "r", encoding="utf-8") as f:
            raw = f.read().strip().upper()
        # Support legacy JSON format if present
        if raw.startswith("{"):
            import json as _j
            raw = _j.loads(raw).get("key", "")
        return raw if raw else None
    except Exception:
        return None

def lic_check():
    key = lic_load()
    if not key:
        return {"valid": False, "reason": "No license found",
                "school_id": "", "expiry": "", "edition": ""}
    return lic_validate(key)

