def safe_tbl_style(extra_cmds=None):
    """Produce a TableStyle without using the invalid 'all' shorthand."""
    cmds = [
        ("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),
        ("FONTNAME",(0,1),(-1,-1),"Helvetica"),
        ("FONTSIZE",(0,0),(-1,-1),8),
        ("BACKGROUND",(0,0),(-1,0),rl_colors.HexColor("#0d2844")),
        ("TEXTCOLOR",(0,0),(-1,0),rl_colors.white),
        ("GRID",(0,0),(-1,-1),0.5,rl_colors.HexColor("#888888")),
        ("ALIGN",(0,0),(-1,-1),"CENTER"),
        ("VALIGN",(0,0),(-1,-1),"MIDDLE"),
        ("TOPPADDING",(0,0),(-1,-1),3),
        ("BOTTOMPADDING",(0,0),(-1,-1),3),
    ]
    if extra_cmds:
        cmds.extend(extra_cmds)
    return TableStyle(cmds)

def zebra(n):
    """Return zebra-stripe background commands for n data rows."""
    s = []
    for i in range(n):
        bg = rl_colors.white if i % 2 == 0 else rl_colors.HexColor("#f0f7ff")
        s.append(("BACKGROUND",(0,i+1),(-1,i+1),bg))
    return s

def _make_subj_mean_bar_chart(numeric_means, chart_width=None):
    """
    Build a ReportLab Drawing bar chart of subject means.
    Drawing is itself a Platypus Flowable — append directly to elems list.

    Parameters
    ----------
    numeric_means : list of (code: str, mean: float)
    chart_width   : float in points (default 190 mm)
    """
    from reportlab.graphics.shapes import Drawing, Rect, String, Line

    if chart_width is None:
        chart_width = 190 * mm

    PAD_L  = 28 * mm
    PAD_R  = 6  * mm
    PAD_T  = 14 * mm
    PAD_B  = 16 * mm
    HEIGHT = 65 * mm

    plot_w = chart_width - PAD_L - PAD_R
    plot_h = HEIGHT - PAD_T - PAD_B

    # Y-axis: fixed scale 0-10 with gridlines at 2,4,6,8,10
    y_max    = 10.0
    y_ticks  = [2, 4, 6, 8, 10]

    n_bars    = len(numeric_means)
    gap       = 4.0
    bar_w     = max(4.0, (plot_w - gap * (n_bars + 1)) / n_bars)

    d = Drawing(chart_width, HEIGHT)

    d.add(Rect(0, 0, chart_width, HEIGHT,
               fillColor=rl_colors.HexColor("#f8fbff"),
               strokeColor=rl_colors.HexColor("#cccccc"), strokeWidth=0.5))

    d.add(String(chart_width / 2, HEIGHT - PAD_T + 4,
                 "SUBJECT MEAN SCORES",
                 fontSize=8, fontName="Helvetica-Bold",
                 fillColor=rl_colors.HexColor("#0d1b2a"),
                 textAnchor="middle"))

    # Gridlines + y-axis labels at 2, 4, 6, 8, 10
    for val in y_ticks:
        y_px = PAD_B + (val / y_max) * plot_h
        d.add(Line(PAD_L, y_px, PAD_L + plot_w, y_px,
                   strokeColor=rl_colors.HexColor("#dddddd"), strokeWidth=0.4))
        d.add(String(PAD_L - 3, y_px - 3, str(val),
                     fontSize=6, fontName="Helvetica",
                     fillColor=rl_colors.HexColor("#555555"),
                     textAnchor="end"))

    # Axis lines
    d.add(Line(PAD_L, PAD_B, PAD_L, PAD_B + plot_h,
               strokeColor=rl_colors.HexColor("#0d1b2a"), strokeWidth=0.8))
    d.add(Line(PAD_L, PAD_B, PAD_L + plot_w, PAD_B,
               strokeColor=rl_colors.HexColor("#0d1b2a"), strokeWidth=0.8))

    PALETTE = [
        "#1565C0", "#2E7D32", "#6A1B9A", "#C62828",
        "#00838F", "#E65100", "#37474F", "#AD1457",
        "#558B2F", "#4527A0",
    ]
    for bi, (code, mean_val) in enumerate(numeric_means):
        # Clamp display to y_max so a bar never overflows the plot area
        display_val = min(float(mean_val), y_max)
        bx    = PAD_L + gap * (bi + 1) + bar_w * bi
        bh    = max(1.0, (display_val / y_max) * plot_h)
        color = rl_colors.HexColor(PALETTE[bi % len(PALETTE)])
        d.add(Rect(bx, PAD_B, bar_w, bh,
                   fillColor=color,
                   strokeColor=rl_colors.HexColor("#ffffff"), strokeWidth=0.3))
        d.add(String(bx + bar_w / 2, PAD_B + bh + 2,
                     f"{mean_val:.1f}",
                     fontSize=5.5, fontName="Helvetica-Bold",
                     fillColor=rl_colors.HexColor("#0d1b2a"),
                     textAnchor="middle"))
        d.add(String(bx + bar_w / 2, PAD_B - 11,
                     code,
                     fontSize=5.5, fontName="Helvetica-Bold",
                     fillColor=rl_colors.HexColor("#0d1b2a"),
                     textAnchor="middle"))

    return d

