def load_cfg():
    if os.path.exists(CFG_PATH):
        try:
            with open(CFG_PATH) as f:
                d = json.load(f)
                # merge missing keys
                for k,v in DEFAULT_CFG.items():
                    if k not in d: d[k] = v
                return d
        except (json.JSONDecodeError, OSError): pass
    return dict(DEFAULT_CFG)

def save_cfg(cfg):
    with open(CFG_PATH, "w") as f:
        json.dump(cfg, f, indent=2)

CFG = load_cfg()

