# SMS — Africa's Talking Integration
# ══════════════════════════════════════════════════════════════════════════════

def _at_normalize_phone(phone):
    """Normalize a Kenyan phone number to +254XXXXXXXXX format."""
    p = str(phone).strip().replace(" ", "").replace("-", "")
    if p.startswith("0") and len(p) == 10:
        return "+254" + p[1:]
    if p.startswith("254") and len(p) == 12:
        return "+" + p
    if p.startswith("+254"):
        return p
    return p  # return as-is if unrecognized

def sms_send(phone, message):
    """
    Send a single SMS via Africa's Talking API.
    Returns (True, "Sent") or (False, "error reason").
    """
    import urllib.request, urllib.parse
    api_key  = CFG.get("sms_api_key", "").strip()
    username = CFG.get("sms_username", "").strip()
    sender   = CFG.get("sms_sender_id", "iQEMS").strip() or "iQEMS"
    if not api_key or not username:
        return False, "SMS not configured. Go to Settings → 📱 SMS to enter your Africa's Talking credentials."
    phone = _at_normalize_phone(phone)
    url = "https://api.africastalking.com/version1/messaging"
    data = urllib.parse.urlencode({
        "username": username,
        "to":       phone,
        "message":  message,
        "from":     sender,
    }).encode()
    req = urllib.request.Request(url, data=data, method="POST")
    req.add_header("apiKey", api_key)
    req.add_header("Accept", "application/json")
    req.add_header("Content-Type", "application/x-www-form-urlencoded")
    try:
        with urllib.request.urlopen(req, timeout=15) as resp:
            body = resp.read().decode()
            if '"status":"Success"' in body or '"Status":"Success"' in body:
                return True, "Sent"
            return False, body
    except Exception as e:
        return False, str(e)

def sms_build_message(lrn, rows, term="", year="", position="", total_learners=""):
    """Build the SMS text for a learner's results."""
    tmpl = CFG.get("sms_template",
        "Dear Parent, {learner} results for {term} {year}: {subjects}. Total: {total}. Position: {position}. -{school}")
    # Build subject summary: "Math:85 Eng:78 Sci:90"
    subj_parts = []
    total_marks = 0
    total_max   = 0
    for r in rows:
        code  = r.get("subject_code") or r.get("code") or ""
        marks = r.get("marks") or r.get("score") or ""
        max_m = r.get("max_marks") or r.get("out_of") or 100
        if marks != "" and marks is not None:
            try:
                subj_parts.append(f"{code}:{int(float(marks))}")
                total_marks += float(marks)
                total_max   += float(max_m)
            except (ValueError, TypeError):
                pass
    subjects_str = " ".join(subj_parts) if subj_parts else "N/A"
    total_str    = f"{int(total_marks)}/{int(total_max)}" if total_max else "N/A"
    pos_str      = f"{position}/{total_learners}" if position and total_learners else (str(position) if position else "N/A")
    learner_name = f"{lrn.get('first_name','')} {lrn.get('last_name','')}".strip()
    msg = tmpl.format(
        learner=learner_name,
        term=term or "Term",
        year=year or str(datetime.now().year),
        subjects=subjects_str,
        total=total_str,
        position=pos_str,
        school=school_name() or "School",
    )
    return msg


