def is_primary_grade(grade_str):
    """Return True if grade string is Grade 1-6 (Primary section) or Pre-Primary."""
    if not grade_str:
        return False
    g = str(grade_str).strip().lower().replace(" ", "").replace("-", "")
    if g in {"pp1", "pp2", "nursery", "preprimary1", "preprimary2"}:
        return True
    for n in ["1","2","3","4","5","6"]:
        if g == f"grade{n}":
            return True
    return False

def is_pre_primary_grade(grade_str):
    """Return True if grade string is PP1, PP2, or Nursery (Pre-Primary)."""
    if not grade_str:
        return False
    g = str(grade_str).strip().lower().replace(" ", "").replace("-", "")
    return g in {"pp1", "pp2", "nursery", "preprimary1", "preprimary2"}

def is_lower_primary_grade(grade_str):
    """Return True if grade string is Grade 1, 2, or 3 (Lower Primary)."""
    if not grade_str:
        return False
    g = str(grade_str).strip().lower().replace(" ", "")
    for n in ["1","2","3"]:
        if g == f"grade{n}":
            return True
    return False

def is_upper_primary_grade(grade_str):
    """Return True if grade string is Grade 4, 5, or 6 (Upper Primary)."""
    if not grade_str:
        return False
    g = str(grade_str).strip().lower().replace(" ", "")
    for n in ["4","5","6"]:
        if g == f"grade{n}":
            return True
    return False

# Subject display order for each section
# Pre-Primary: PP1, PP2, Nursery
PRE_PRIMARY_SUBJECT_ORDER = [
    "language activities",
    "mathematical activities",
    "environmental activities",
    "psychomotor and creative activities",
    "religious education activities",
]
# Junior: Grade 7-9
JUNIOR_SUBJECT_ORDER = [
    "mathematics",
    "english",
    "kiswahili",
    "integrated science",
    "pre-technical studies",
    "pre technical studies",
    "religious education",
    "agriculture and nutrition",
    "creative arts and sports",
    "social studies",
]
# Upper Primary: Grade 4-6
UPPER_PRIMARY_SUBJECT_ORDER = [
    "mathematics",
    "english",
    "kiswahili",
    "science and technology",
    "creative arts",
    "agriculture",
    "social studies",
    "religious education",
]
# Lower Primary: Grade 1-3
LOWER_PRIMARY_SUBJECT_ORDER = [
    "mathematics activities",
    "english activities",
    "kiswahili activities",
    "creative arts",
    "environmental activities",
    "religious education",
]

def subject_sort_key(subj_name, grade_str):
    """Return sort key using the section-specific order lists (exact match)."""
    name = str(subj_name).strip().lower()
    if is_pre_primary_grade(grade_str):
        order = PRE_PRIMARY_SUBJECT_ORDER
    elif is_lower_primary_grade(grade_str):
        order = LOWER_PRIMARY_SUBJECT_ORDER
    elif is_upper_primary_grade(grade_str):
        order = UPPER_PRIMARY_SUBJECT_ORDER
    else:
        order = JUNIOR_SUBJECT_ORDER
    for i, s in enumerate(order):
        if s == name:
            return i
    return 99

# Section sort_order ranges in the subjects table:
#   Junior      (Gr 7-9):  sort_order 0 – 9
#   Upper Prim  (Gr 4-6):  sort_order 10 – 19
#   Lower Prim  (Gr 1-3):  sort_order 20 – 29
#   Pre-Primary (PP/Nurs): sort_order 30 – 39
JUNIOR_SORT_MIN,      JUNIOR_SORT_MAX      =  0,  9
UPPER_SORT_MIN,       UPPER_SORT_MAX       = 10, 19
LOWER_SORT_MIN,       LOWER_SORT_MAX       = 20, 29
PRE_PRIMARY_SORT_MIN, PRE_PRIMARY_SORT_MAX = 30, 39

def _grade_sort_range(grade_str):
    """Return (min, max) sort_order range for the grade's section."""
    if is_pre_primary_grade(grade_str):
        return PRE_PRIMARY_SORT_MIN, PRE_PRIMARY_SORT_MAX
    if is_lower_primary_grade(grade_str):
        return LOWER_SORT_MIN, LOWER_SORT_MAX
    if is_upper_primary_grade(grade_str):
        return UPPER_SORT_MIN, UPPER_SORT_MAX
    return JUNIOR_SORT_MIN, JUNIOR_SORT_MAX  # Junior default

def get_section_subjects(grade_str, conn):
    """Return active subjects for grade_str's section for Marksheet / Enter Marks.

    Rules:
      • Standalone subjects (not composite, no parent) → included as-is.
      • Composite PARENT subjects → EXCLUDED; replaced by their sub-subjects.
      • Sub-subjects → included immediately after their parent's position.

    This means the marksheet shows the real mark columns (sub-subjects)
    instead of the derived total column (composite parent), giving teachers
    one entry cell per actual component. Sub-subjects are ordered after
    their parent's sort_order position so the column order stays logical.
    """
    lo, hi = _grade_sort_range(grade_str)
    parents = conn.execute(
        "SELECT id, code, name, max_marks, sort_order, "
        "COALESCE(is_composite,0) AS is_composite, "
        "COALESCE(composite_parent_id,NULL) AS composite_parent_id, "
        "COALESCE(composite_weight,1.0) AS composite_weight "
        "FROM subjects WHERE is_active=1 AND sort_order BETWEEN ? AND ? "
        "AND COALESCE(composite_parent_id,0)=0 "
        "ORDER BY sort_order, name",
        (lo, hi)
    ).fetchall()
    sub_map = {}
    if parents:
        parent_ids = [r["id"] for r in parents]
        ph = ",".join("?" * len(parent_ids))
        subs = conn.execute(
            "SELECT id, code, name, max_marks, sort_order, "
            "COALESCE(is_composite,0) AS is_composite, "
            "COALESCE(composite_parent_id,NULL) AS composite_parent_id, "
            "COALESCE(composite_weight,1.0) AS composite_weight "
            f"FROM subjects WHERE is_active=1 AND composite_parent_id IN ({ph}) "
            "ORDER BY composite_parent_id, sort_order, name",
            parent_ids
        ).fetchall()
        for s in subs:
            sub_map.setdefault(s["composite_parent_id"], []).append(s)
    result = []
    for p in parents:
        subs_of_p = sub_map.get(p["id"], [])
        if subs_of_p:
            # Composite parent: add its sub-subjects only (skip the parent itself)
            result.extend(subs_of_p)
        else:
            # Standalone subject: add normally
            result.append(p)
    return result


def get_broadsheet_subjects(grade_str, conn):
    """Return subjects visible in broadsheet & report forms:
    • Standalone subjects (not composite parents, not sub-subjects)
    • Composite PARENT subjects (they represent the merged total)
    Sub-subjects (composite_parent_id IS NOT NULL) are excluded.
    """
    lo, hi = _grade_sort_range(grade_str)
    rows = conn.execute(
        "SELECT id, code, name, max_marks, sort_order, "
        "COALESCE(is_composite,0) AS is_composite, "
        "COALESCE(composite_parent_id,NULL) AS composite_parent_id, "
        "COALESCE(composite_weight,1.0) AS composite_weight "
        "FROM subjects WHERE is_active=1 AND sort_order BETWEEN ? AND ? "
        "AND (COALESCE(composite_parent_id,0)=0) "
        "ORDER BY sort_order, name",
        (lo, hi)
    ).fetchall()
    return rows


def get_sub_subjects(parent_id, conn):
    """Return sub-subjects that belong to a composite parent subject."""
    rows = conn.execute(
        "SELECT id, code, name, max_marks, sort_order, "
        "COALESCE(composite_weight,1.0) AS composite_weight "
        "FROM subjects WHERE is_active=1 AND composite_parent_id=? "
        "ORDER BY sort_order, name",
        (parent_id,)
    ).fetchall()
    return rows

# Keep subj_allowed_for_grade for backward compat with _report_card_elements row filter.
# Uses sort_order stored at index 9 of the row tuple when available,
# otherwise falls back to the name-based order lists (exact match only).
PRIMARY_EXCLUDE_SUBJECTS    = {"pre-technical studies", "pre technical studies", "pts", "integrated science"}
LOWER_PRIMARY_ONLY_SUBJECTS = {"environmental activities", "mathematics activities", "english activities", "kiswahili activities"}
UPPER_PRIMARY_ONLY_SUBJECTS = {"science and technology"}
PRE_PRIMARY_ONLY_SUBJECTS   = set(PRE_PRIMARY_SUBJECT_ORDER)

def subj_allowed_for_grade(name, grade_str, sort_order=None):
    """Return True if this subject belongs to grade_str's section.
    When sort_order is passed (integer), uses the reliable range check.
    Otherwise falls back to exact name matching.
    """
    if sort_order is not None:
        try:
            so = int(sort_order)
            lo, hi = _grade_sort_range(grade_str)
            return lo <= so <= hi
        except (TypeError, ValueError):
            pass
    # Exact name fallback (no substring matching)
    nm = str(name).strip().lower()
    pre_prim  = is_pre_primary_grade(grade_str)
    lower_prim = is_lower_primary_grade(grade_str)
    upper_prim = is_upper_primary_grade(grade_str)
    if pre_prim:
        return nm in PRE_PRIMARY_ONLY_SUBJECTS
    if lower_prim:
        return nm in set(LOWER_PRIMARY_SUBJECT_ORDER)
    if upper_prim:
        if nm in PRIMARY_EXCLUDE_SUBJECTS:
            return False
        if nm in LOWER_PRIMARY_ONLY_SUBJECTS:
            return False
        if nm in PRE_PRIMARY_ONLY_SUBJECTS:
            return False
        return True
    # Junior
    if nm in LOWER_PRIMARY_ONLY_SUBJECTS:
        return False
    if nm in UPPER_PRIMARY_ONLY_SUBJECTS:
        return False
    if nm in PRE_PRIMARY_ONLY_SUBJECTS:
        return False
    return True

