def section_classes(section, formatted=True):
    """Return classes belonging to a section.
    section: 'junior' | 'upper' | 'lower' | 'preprimary'
    formatted=True → list of 'id|Name (Grade)' strings for Combobox.
    formatted=False → list of sqlite3.Row objects.
    """
    conn = get_conn()
    all_cls = conn.execute(
        "SELECT id, name, grade FROM classes ORDER BY grade, name"
    ).fetchall()
    conn.close()
    if section == "junior":
        rows = [c for c in all_cls if not is_primary_grade(c["grade"])]
    elif section == "upper":
        rows = [c for c in all_cls if is_upper_primary_grade(c["grade"])]
    elif section == "lower":
        rows = [c for c in all_cls if is_lower_primary_grade(c["grade"])]
    elif section == "preprimary":
        rows = [c for c in all_cls if is_pre_primary_grade(c["grade"])]
    else:
        rows = list(all_cls)
    if formatted:
        return [f"{r['id']}|{r['name']} ({r['grade']})" for r in rows]
    return rows


def total_max_points():
    """Max points if learner scores top level (EE1) in all subjects."""
    conn = get_conn()
    n_subjects = conn.execute("SELECT COUNT(*) FROM subjects WHERE is_active=1").fetchone()[0]
    conn.close()
    top_pts = get_cbc_levels()[0]["points"]  # EE1 = 8
    return top_pts * n_subjects

