def get_conn():
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    conn.execute("PRAGMA foreign_keys = ON")
    return conn

def init_db():
    conn = get_conn(); c = conn.cursor()
    # Migration: add sort_order if missing (for existing databases)
    try:
        c.execute("ALTER TABLE subjects ADD COLUMN sort_order INTEGER DEFAULT 99")
        conn.commit()
    except sqlite3.OperationalError: pass
    # Migration: add photo_path if missing
    try:
        c.execute("ALTER TABLE learners ADD COLUMN photo_path TEXT")
        conn.commit()
    except sqlite3.OperationalError: pass
    # Migration: add section_key column to subjects if missing
    try:
        c.execute("ALTER TABLE subjects ADD COLUMN section_key TEXT DEFAULT 'junior'")
        conn.commit()
    except sqlite3.OperationalError: pass
    # Migration: add composite/sub-subject support columns
    try:
        c.execute("ALTER TABLE subjects ADD COLUMN is_composite INTEGER DEFAULT 0")
        conn.commit()
    except sqlite3.OperationalError: pass
    try:
        c.execute("ALTER TABLE subjects ADD COLUMN composite_parent_id INTEGER DEFAULT NULL")
        conn.commit()
    except sqlite3.OperationalError: pass
    try:
        c.execute("ALTER TABLE subjects ADD COLUMN composite_weight REAL DEFAULT 1.0")
        conn.commit()
    except sqlite3.OperationalError: pass
    # Migration: assessment logistics tables
    try:
        c.execute("""CREATE TABLE IF NOT EXISTS exam_schedules (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            title TEXT NOT NULL,
            exam_type TEXT DEFAULT 'END_TERM',
            class_id INTEGER REFERENCES classes(id),
            subject_id INTEGER REFERENCES subjects(id),
            exam_date TEXT,
            start_time TEXT,
            end_time TEXT,
            venue TEXT,
            invigilator TEXT,
            term TEXT,
            academic_year TEXT,
            status TEXT DEFAULT 'Scheduled',
            notes TEXT
        )""")
        conn.commit()
    except sqlite3.OperationalError:
        pass
    try:
        c.execute("""CREATE TABLE IF NOT EXISTS marking_assignments (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            teacher_id INTEGER REFERENCES staff(id),
            subject_id INTEGER REFERENCES subjects(id),
            class_id INTEGER REFERENCES classes(id),
            assessment_type TEXT DEFAULT 'END_TERM',
            term TEXT,
            academic_year TEXT,
            scripts_count INTEGER DEFAULT 0,
            marked_count INTEGER DEFAULT 0,
            deadline TEXT,
            status TEXT DEFAULT 'Pending',
            notes TEXT,
            UNIQUE(teacher_id, subject_id, class_id, term, academic_year, assessment_type)
        )""")
        conn.commit()
    except sqlite3.OperationalError:
        pass
    c.executescript("""
    CREATE TABLE IF NOT EXISTS schools (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL, code TEXT UNIQUE,
        level TEXT DEFAULT 'Junior School (Gr 7-9)',
        county TEXT, sub_county TEXT, principal TEXT
    );
    CREATE TABLE IF NOT EXISTS classes (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL, grade TEXT NOT NULL,
        school_id INTEGER REFERENCES schools(id),
        teacher TEXT, academic_year TEXT
    );
    CREATE TABLE IF NOT EXISTS subjects (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        code TEXT UNIQUE NOT NULL, name TEXT NOT NULL,
        strand TEXT, level TEXT DEFAULT 'Junior School (Gr 7-9)',
        sort_order INTEGER DEFAULT 99,
        max_marks REAL DEFAULT 100, is_active INTEGER DEFAULT 1
    );
    CREATE TABLE IF NOT EXISTS learners (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        admission_no TEXT UNIQUE NOT NULL,
        first_name TEXT NOT NULL, last_name TEXT NOT NULL,
        other_name TEXT, gender TEXT, nemis_no TEXT UNIQUE,
        class_id INTEGER REFERENCES classes(id),
        parent_name TEXT, parent_phone TEXT,
        photo_path TEXT,
        status TEXT DEFAULT 'Active',
        enroll_date TEXT DEFAULT (date('now'))
    );
    CREATE TABLE IF NOT EXISTS assessments (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL, type TEXT DEFAULT 'CATS',
        class_id INTEGER REFERENCES classes(id),
        subject_id INTEGER REFERENCES subjects(id),
        term TEXT, academic_year TEXT, date TEXT,
        max_marks REAL DEFAULT 100, status TEXT DEFAULT 'Scheduled'
    );
    CREATE TABLE IF NOT EXISTS staff (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL, initials TEXT,
        subject_id INTEGER REFERENCES subjects(id),
        email TEXT
    );
    CREATE TABLE IF NOT EXISTS results (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        learner_id INTEGER REFERENCES learners(id),
        assessment_id INTEGER REFERENCES assessments(id),
        marks REAL, performance_level TEXT, points INTEGER,
        is_absent INTEGER DEFAULT 0, teacher_comment TEXT,
        entry_date TEXT DEFAULT (date('now')),
        UNIQUE(learner_id, assessment_id)
    );
    """)
    conn.commit()   # BUG FIX: commit CREATE TABLE statements

    c.execute("SELECT COUNT(*) FROM schools")
    if c.fetchone()[0] == 0:
        c.execute("""INSERT INTO schools (name,code,level,county,principal)
            VALUES ('My School','SCH001','Junior School (Gr 7-9)','','')""")

    c.execute("SELECT COUNT(*) FROM subjects")
    if c.fetchone()[0] == 0:
        subjs = [
            # sort_order, code, name, strand, max_marks, section_key
            # ── Junior School (Grade 7-9)  sort_order 0-9 ──
            (0,  "MTH",   "MATHEMATICS",              "Core",       100, "junior"),
            (1,  "ENG",   "ENGLISH",                  "Core",       100, "junior"),
            (2,  "KIS",   "KISWAHILI",                "Core",       100, "junior"),
            (3,  "ISCI",  "INTEGRATED SCIENCE",        "Core",       100, "junior"),
            (4,  "PTS",   "PRE-TECHNICAL STUDIES",     "Technical",  100, "junior"),
            (5,  "CRE",   "RELIGIOUS EDUCATION",       "Values",     100, "junior"),
            (6,  "AAN",   "AGRICULTURE AND NUTRITION", "Applied",    100, "junior"),
            (7,  "CAS",   "CREATIVE ARTS AND SPORTS",  "Creative",   100, "junior"),
            (8,  "SST",   "SOCIAL STUDIES",            "Humanities", 100, "junior"),
            # ── Upper Primary (Grade 4-6)  sort_order 10-19 ──
            (10, "SNT",   "SCIENCE AND TECHNOLOGY",    "Core",       100, "upper"),
            (11, "CAUP",  "CREATIVE ARTS",             "Creative",   100, "upper"),
            (12, "AGR",   "AGRICULTURE",               "Applied",    100, "upper"),
            (13, "SSTUP", "SOCIAL STUDIES",            "Humanities", 100, "upper"),
            (14, "CREUP", "RELIGIOUS EDUCATION",       "Values",     100, "upper"),
            (15, "MTHUP", "MATHEMATICS",               "Core",       100, "upper"),
            (16, "ENGUP", "ENGLISH",                   "Core",       100, "upper"),
            (17, "KISUP", "KISWAHILI",                 "Core",       100, "upper"),
            # ── Lower Primary (Grade 1-3)  sort_order 20-29 ──
            (20, "MTHA",  "MATHEMATICS ACTIVITIES",            "Core",       100, "lower"),
            (21, "ENGA",  "ENGLISH ACTIVITIES",                "Core",       100, "lower"),
            (22, "KISA",  "KISWAHILI ACTIVITIES",              "Core",       100, "lower"),
            (23, "CRAL",  "CREATIVE ARTS",                     "Creative",   100, "lower"),
            (24, "ENVA",  "ENVIRONMENTAL ACTIVITIES",          "Core",       100, "lower"),
            (25, "CREL",  "RELIGIOUS EDUCATION",               "Values",     100, "lower"),
            # ── Pre-Primary (PP1/PP2/Nursery)  sort_order 30-39 ──
            (30, "LANG",  "LANGUAGE ACTIVITIES",               "Core",       100, "preprimary"),
            (31, "MATH",  "MATHEMATICAL ACTIVITIES",           "Core",       100, "preprimary"),
            (32, "ENPP",  "ENVIRONMENTAL ACTIVITIES",          "Core",       100, "preprimary"),
            (33, "PSYC",  "PSYCHOMOTOR AND CREATIVE ACTIVITIES","Creative",  100, "preprimary"),
            (34, "REPP",  "RELIGIOUS EDUCATION ACTIVITIES",    "Values",     100, "preprimary"),
        ]
        c.executemany(
            "INSERT INTO subjects (sort_order,code,name,strand,max_marks,section_key) VALUES (?,?,?,?,?,?)",
            subjs)
        conn.commit()   # BUG FIX: commit seeded subjects
    else:
        # Migration: stamp section_key and fix sort_order ranges for existing rows
        # Subjects seeded with sort_order 0-9 are Junior, 10-19 Upper, 20-29 Lower
        c.execute("UPDATE subjects SET section_key='junior' WHERE sort_order BETWEEN 0  AND 9")
        c.execute("UPDATE subjects SET section_key='upper'  WHERE sort_order BETWEEN 10 AND 19")
        c.execute("UPDATE subjects SET section_key='lower'  WHERE sort_order BETWEEN 20 AND 29")
        c.execute("UPDATE subjects SET section_key='preprimary' WHERE sort_order BETWEEN 30 AND 39")
        conn.commit()
        # Normalise sort_order: if all are 99 (legacy), assign sequential order
        all_99 = c.execute(
            "SELECT COUNT(*) FROM subjects WHERE sort_order != 99").fetchone()[0] == 0
        if all_99:
            rows_fix = c.execute(
                "SELECT id FROM subjects ORDER BY name").fetchall()
            for idx, r in enumerate(rows_fix):
                c.execute("UPDATE subjects SET sort_order=? WHERE id=?",
                          (idx, r["id"]))

    c.execute("SELECT COUNT(*) FROM classes")
    if c.fetchone()[0] == 0:
        c.execute("INSERT INTO classes (name,grade,school_id,teacher,academic_year) VALUES ('Grade 7A','Grade 7',1,'Mr. Kamau','2025')")
        c.execute("INSERT INTO classes (name,grade,school_id,teacher,academic_year) VALUES ('Grade 8B','Grade 8',1,'Ms. Achieng','2025')")

    # Migration: ensure all sub-subjects have sort_order=99 so they are never
    # accidentally excluded by the BETWEEN range filter in get_section_subjects.
    c.execute("""UPDATE subjects SET sort_order=99
                 WHERE COALESCE(composite_parent_id,0)!=0
                   AND sort_order != 99""")

    conn.commit(); conn.close()

