FONT_TITLE = ("Segoe UI", 20, "bold")
FONT_MED   = ("Segoe UI", 13, "bold")
FONT_H     = ("Segoe UI", 10, "bold")
FONT_B     = ("Segoe UI", 10)
FONT_S     = ("Segoe UI",  9)

def mk_btn(parent, text, cmd, color=None, fg=None, **kw):
    c = color or T("ACCENT"); f = fg or T("BG")
    b = tk.Button(parent, text=text, command=cmd, bg=c, fg=f,
                  font=FONT_H, relief="flat", cursor="hand2",
                  activebackground=T("ACCENT2"), activeforeground=T("BG"),
                  padx=12, pady=6, **kw)
    return b

def mk_lbl(parent, text, size=10, bold=False, color=None, **kw):
    fg = color or T("TEXT")
    font = ("Segoe UI", size, "bold" if bold else "normal")
    return tk.Label(parent, text=text, bg=parent["bg"], fg=fg, font=font, **kw)

def apply_theme_to_widget(widget):
    """Recursively apply current theme bg/fg to all widgets."""
    try:
        cls = widget.winfo_class()
        if cls in ("Frame","Toplevel","Canvas"):
            widget.configure(bg=T("BG"))
        elif cls == "Label":
            widget.configure(bg=widget.master["bg"])
    except tk.TclError: pass

# ─────────────────────────────────────────────────────────────
# STYLED TABLE
# ─────────────────────────────────────────────────────────────
class StyledTable(tk.Frame):
    def __init__(self, parent, columns, col_widths=None, on_double_click=None,
                 context_menu=None, **kw):
        """
        context_menu: list of (label, callback) tuples shown on right-click.
                      Pass None as the label for a separator line.
        """
        super().__init__(parent, bg=kw.pop("bg", T("PANEL")))
        style = ttk.Style()
        style.theme_use("clam")
        style.configure("IQ.Treeview",
            background=T("CARD"), foreground=T("TEXT"), rowheight=30,
            fieldbackground=T("CARD"), borderwidth=0, font=FONT_B)
        style.configure("IQ.Treeview.Heading",
            background=T("BORDER"), foreground=T("ACCENT"),
            font=FONT_H, relief="flat")
        style.map("IQ.Treeview",
            background=[("selected", T("ACCENT"))],
            foreground=[("selected", T("BG"))])
        self.tree = ttk.Treeview(self, columns=columns, show="headings", style="IQ.Treeview",
                                  selectmode="extended")
        vsb = ttk.Scrollbar(self, orient="vertical",   command=self.tree.yview)
        hsb = ttk.Scrollbar(self, orient="horizontal", command=self.tree.xview)
        self.tree.configure(yscrollcommand=vsb.set, xscrollcommand=hsb.set)
        self.tree.grid(row=0, column=0, sticky="nsew")
        vsb.grid(row=0, column=1, sticky="ns")
        hsb.grid(row=1, column=0, sticky="ew")
        self.columnconfigure(0, weight=1); self.rowconfigure(0, weight=1)
        for i,col in enumerate(columns):
            w = col_widths[i] if col_widths and i < len(col_widths) else 110
            self.tree.heading(col, text=col)
            self.tree.column(col, width=w, anchor="w", minwidth=50)
        # level colour tags
        for lv in get_cbc_levels():
            self.tree.tag_configure(lv["level"], foreground=cbc_color(lv["level"]))
        self.tree.tag_configure("AB", foreground=T("SUBTEXT"))
        if on_double_click:
            self.tree.bind("<Double-1>", on_double_click)
        # ── Right-click context menu ──────────────────────────────
        self._ctx_defs = context_menu or []
        self._ctx_menu = None
        if self._ctx_defs:
            self._build_ctx()
            self.tree.bind("<Button-3>",         self._show_ctx)
            self.tree.bind("<Control-Button-1>", self._show_ctx)  # macOS

    def _build_ctx(self):
        self._ctx_menu = tk.Menu(self.tree, tearoff=0,
                                 bg=T("CARD"), fg=T("TEXT"),
                                 activebackground=T("ACCENT"),
                                 activeforeground=T("BG"),
                                 font=FONT_S, relief="flat")
        for item in self._ctx_defs:
            if item is None or item[0] is None:
                self._ctx_menu.add_separator()
            else:
                lbl, cb = item
                self._ctx_menu.add_command(label=lbl, command=cb)

    def set_context_menu(self, menu_defs):
        """Replace the context menu at runtime."""
        self._ctx_defs = menu_defs or []
        if self._ctx_menu:
            self._ctx_menu.destroy(); self._ctx_menu = None
        if self._ctx_defs:
            self._build_ctx()
            self.tree.bind("<Button-3>",         self._show_ctx)
            self.tree.bind("<Control-Button-1>", self._show_ctx)
        else:
            self.tree.unbind("<Button-3>")
            self.tree.unbind("<Control-Button-1>")

    def _show_ctx(self, event):
        iid = self.tree.identify_row(event.y)
        if iid and iid not in self.tree.selection():
            self.tree.selection_set(iid)
        if self._ctx_menu:
            try:
                self._ctx_menu.tk_popup(event.x_root, event.y_root)
            finally:
                self._ctx_menu.grab_release()

    def clear(self):
        for r in self.tree.get_children(): self.tree.delete(r)

    def insert(self, values, tag=""):
        self.tree.insert("", "end", values=values, tags=(tag,) if tag else ())

    def autofit_columns(self, min_w=50, max_w=400, padding=16):
        """
        Resize every column to fit the widest content (header or data).
        Uses tkinter.font to measure actual pixel widths.
        After fitting, if total is narrower than the widget, the last
        column absorbs the extra space so no blank gap remains.
        """
        import tkinter.font as tkfont
        heading_font = tkfont.Font(font=("Segoe UI", 9, "bold"))
        cell_font    = tkfont.Font(font=("Segoe UI", 9))

        cols = self.tree["columns"]
        col_min = {}
        # Measure headers
        for col in cols:
            hdr_text = self.tree.heading(col, "text") or col
            col_min[col] = heading_font.measure(hdr_text) + padding

        # Measure each data cell
        for iid in self.tree.get_children():
            vals = self.tree.item(iid, "values")
            for ci, col in enumerate(cols):
                text = str(vals[ci]) if ci < len(vals) and vals[ci] is not None else ""
                w = cell_font.measure(text) + padding
                if w > col_min[col]:
                    col_min[col] = w

        # Clamp widths
        widths = {col: max(min_w, min(max_w, col_min[col])) for col in cols}

        # Stretch last column to fill widget width if there is extra space
        self.tree.update_idletasks()
        avail = self.tree.winfo_width()
        if avail and avail > 1:
            total = sum(widths.values())
            if total < avail:
                last = cols[-1]
                widths[last] += avail - total

        for col, w in widths.items():
            self.tree.column(col, width=w, minwidth=min_w)

    def get_selected(self):
        sel = self.tree.selection()
        return self.tree.item(sel[0])["values"] if sel else None

    def get_all_selected(self):
        """Return list of value-tuples for all selected rows."""
        return [self.tree.item(iid)["values"] for iid in self.tree.selection()]

    def get_all_rows(self):
        """Return list of value-tuples for every row."""
        return [self.tree.item(iid)["values"] for iid in self.tree.get_children()]

# ─────────────────────────────────────────────────────────────
# LABELED FIELD
# ─────────────────────────────────────────────────────────────
class LF(tk.Frame):
    def __init__(self, parent, label, wtype="entry", values=None, caps=False, **kw):
        super().__init__(parent, bg=kw.pop("bg", T("CARD")))
        self.caps = caps
        tk.Label(self, text=label, bg=self["bg"], fg=T("SUBTEXT"), font=FONT_S, anchor="w").pack(anchor="w")
        self.var = tk.StringVar()
        if wtype == "combo":
            w = ttk.Combobox(self, textvariable=self.var, values=values or [],
                             font=FONT_B, state="readonly", width=32)
        elif wtype == "text":
            w = tk.Text(self, height=3, bg=T("CARD"), fg=T("TEXT"), font=FONT_B,
                        insertbackground=T("ACCENT"), relief="flat",
                        highlightthickness=1, highlightbackground=T("BORDER"))
            self.widget = w; w.pack(fill="x", pady=(2,0)); return
        else:
            w = tk.Entry(self, textvariable=self.var, font=FONT_B,
                         bg=T("CARD"), fg=T("TEXT"), insertbackground=T("ACCENT"),
                         relief="flat", highlightthickness=1,
                         highlightbackground=T("BORDER"), highlightcolor=T("ACCENT"), width=32)
            if caps:
                self.var.trace_add("write", self._force_caps)
        w.pack(fill="x", pady=(2,0)); self.widget = w

    def _force_caps(self, *_):
        v = self.var.get()
        upper = v.upper()
        if v != upper:
            pos = self.widget.index(tk.INSERT) if hasattr(self.widget, "index") else 0
            self.var.set(upper)
            try: self.widget.icursor(pos)
            except tk.TclError: pass

    def get(self):
        # Text widgets don't use self.var; detect by widget class
        try:
            if isinstance(self.widget, tk.Text):
                return self.widget.get("1.0", "end-1c").strip()
        except AttributeError:
            pass
        return self.var.get().strip()
    def set(self, v):
        if hasattr(self,"var"): self.var.set(v)
        else: self.widget.delete("1.0","end"); self.widget.insert("1.0",v)
    def clear(self): self.set("")

# ─────────────────────────────────────────────────────────────
# TOUCH / MOUSE-WHEEL SCROLL HELPER
# Attach to any tk.Canvas to enable: mouse-wheel (Win/Mac),
# Button-4/5 (Linux/X11), and finger/stylus drag (touch screens).
# ─────────────────────────────────────────────────────────────
def _attach_touch_scroll(canvas, x_canvas=None):
    """Add mouse-wheel, Linux scroll-button, and touch-drag to *canvas*.
    Uses canvas.bind() only — never bind_all/unbind_all — so it cannot
    interfere with any global keyboard shortcuts (e.g. Ctrl+S).
    """
    # ── Mouse-wheel: bind directly on canvas (not on root) ──────
    # Works when the canvas widget itself has the pointer over it.
    canvas.bind("<MouseWheel>",
        lambda e: canvas.yview_scroll(-1*(e.delta//120), "units"))
    canvas.bind("<Shift-MouseWheel>",
        lambda e: canvas.xview_scroll(-1*(e.delta//120), "units"))
    canvas.bind("<Button-4>",       lambda e: canvas.yview_scroll(-1, "units"))
    canvas.bind("<Button-5>",       lambda e: canvas.yview_scroll(1,  "units"))
    canvas.bind("<Shift-Button-4>", lambda e: canvas.xview_scroll(-1, "units"))
    canvas.bind("<Shift-Button-5>", lambda e: canvas.xview_scroll(1,  "units"))

    # ── Touch / stylus drag-to-scroll ───────────────────────────
    _t = {"x": 0, "y": 0}
    def _press(e):  _t["x"] = e.x; _t["y"] = e.y
    def _drag(e):
        dx = _t["x"] - e.x; dy = _t["y"] - e.y
        _t["x"] = e.x;       _t["y"] = e.y
        if dy:
            canvas.yview_scroll(int(dy / 4) or (1 if dy > 0 else -1), "units")
        if dx:
            canvas.xview_scroll(int(dx / 4) or (1 if dx > 0 else -1), "units")
    canvas.bind("<ButtonPress-1>", _press)
    canvas.bind("<B1-Motion>",     _drag)


# ─────────────────────────────────────────────────────────────
# SCROLLABLE FRAME
# ─────────────────────────────────────────────────────────────
class ScrollFrame(tk.Frame):
    def __init__(self, parent, **kw):
        super().__init__(parent, bg=kw.pop("bg", T("PANEL")))
        canvas = tk.Canvas(self, bg=self["bg"], highlightthickness=0)
        vsb = ttk.Scrollbar(self, orient="vertical", command=canvas.yview)
        self.inner = tk.Frame(canvas, bg=self["bg"])
        self.inner.bind("<Configure>",
            lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
        win_id = canvas.create_window((0,0), window=self.inner, anchor="nw")
        canvas.configure(yscrollcommand=vsb.set)
        canvas.bind("<Configure>",
            lambda e: canvas.itemconfig(win_id, width=e.width))

        _attach_touch_scroll(canvas)
        # Propagate touch drag from inner frame to canvas
        self.inner.bind("<ButtonPress-1>",
            lambda e: canvas.event_generate("<ButtonPress-1>", x=e.x, y=e.y))
        self.inner.bind("<B1-Motion>",
            lambda e: canvas.event_generate("<B1-Motion>", x=e.x, y=e.y))

        canvas.pack(side="left", fill="both", expand=True)
        vsb.pack(side="right", fill="y")
        self._canvas = canvas

        # ── Propagate mouse-wheel from every child widget to this canvas ──
        # Bind on <Enter>/<Leave> so the active canvas tracks the pointer.
        def _bind_scroll(widget):
            """Recursively bind mousewheel on widget and all descendants."""
            widget.bind("<MouseWheel>",
                lambda e: canvas.yview_scroll(-1*(e.delta//120), "units"), add="+")
            widget.bind("<Button-4>",
                lambda e: canvas.yview_scroll(-1, "units"), add="+")
            widget.bind("<Button-5>",
                lambda e: canvas.yview_scroll(1,  "units"), add="+")
            for child in widget.winfo_children():
                _bind_scroll(child)

        # Re-run binding whenever new child widgets are added to inner
        def _on_inner_configure(e):
            canvas.configure(scrollregion=canvas.bbox("all"))
            _bind_scroll(self.inner)

        self.inner.bind("<Configure>", _on_inner_configure, add="+")
        _bind_scroll(self.inner)

