# ─────────────────────────────────────────────────────────────
# DASHBOARD
# ─────────────────────────────────────────────────────────────
class SectionPanel(tk.Frame):
    """
    A compact card shown on the Dashboard for each section.
    Clicking the header opens a full-screen overlay with a back arrow.
    """
    def __init__(self, parent, app, sec_key, **kw):
        super().__init__(parent, bg=kw.pop("bg", T("BG")))
        self.app      = app
        self.sec_key  = sec_key
        self.meta     = SECTIONS[sec_key]
        self._expanded = False   # kept for API compat; not used for inline expand
        self._body    = None
        self._nb      = None
        self._build_header()

    # ── rich card design ──────────────────────────────────────
    def _build_header(self):
        m = self.meta
        conn = get_conn()
        cls_rows = section_classes(self.sec_key, formatted=False)
        n_cls    = len(cls_rows)
        cids     = [c["id"] for c in cls_rows]
        n_lrn    = 0
        if cids:
            ph = ",".join("?" * len(cids))
            n_lrn = conn.execute(
                f"SELECT COUNT(*) FROM learners WHERE class_id IN ({ph}) AND status='Active'",
                cids).fetchone()[0]
        n_res = 0
        if cids:
            n_res = conn.execute(
                f"SELECT COUNT(*) FROM results r "
                f"JOIN assessments a ON r.assessment_id=a.id "
                f"WHERE a.class_id IN ({ph})", cids).fetchone()[0]
        n_boys = 0
        n_girls = 0
        if cids:
            n_boys = conn.execute(
                f"SELECT COUNT(*) FROM learners WHERE class_id IN ({ph}) AND status='Active' AND gender='Male'",
                cids).fetchone()[0]
            n_girls = conn.execute(
                f"SELECT COUNT(*) FROM learners WHERE class_id IN ({ph}) AND status='Active' AND gender='Female'",
                cids).fetchone()[0]
        conn.close()

        # ── Card frame ────────────────────────────────────────
        self.hdr = tk.Frame(self, bg=m["color"],
                            highlightthickness=2,
                            highlightbackground=m["accent"],
                            cursor="hand2")
        self.hdr.pack(fill="both", expand=True)

        # Top accent stripe
        tk.Frame(self.hdr, bg=m["accent"], height=5).pack(fill="x")

        # Large icon in glowing ring
        icon_area = tk.Frame(self.hdr, bg=m["color"], pady=14)
        icon_area.pack(fill="x")
        ring = tk.Frame(icon_area, bg=m["accent"], padx=2, pady=2)
        ring.pack()
        tk.Label(ring, text=m["icon"],
                 bg=m["accent"], fg=m["color"],
                 font=("Segoe UI Emoji", 32), padx=20, pady=10).pack()

        # Section name + grade range
        tk.Label(self.hdr, text=m["label"],
                 bg=m["color"], fg=m["accent"],
                 font=("Segoe UI", 12, "bold")).pack(pady=(4, 0))
        tk.Label(self.hdr, text=m["sub"],
                 bg=m["color"], fg="#999999",
                 font=("Segoe UI", 8)).pack()

        # Divider
        tk.Frame(self.hdr, bg=m["accent"], height=1).pack(fill="x", padx=18, pady=(10, 4))

        # Stats row — 5 equal columns
        stats_row = tk.Frame(self.hdr, bg=m["color"])
        stats_row.pack(fill="x", padx=12, pady=(0, 8))
        for ico, val, lbl, val_color in [
            ("🏫", n_cls,   "Classes",  m["accent"]),
            ("🎒", n_lrn,   "Learners", m["accent"]),
            ("👦", n_boys,  "Boys",     "#38bdf8"),
            ("👧", n_girls, "Girls",    "#f472b6"),
            ("📊", n_res,   "Results",  m["accent"]),
        ]:
            sf = tk.Frame(stats_row, bg=m["color"])
            sf.pack(side="left", expand=True)
            tk.Label(sf, text=ico, bg=m["color"],
                     font=("Segoe UI Emoji", 12)).pack()
            tk.Label(sf, text=str(val), bg=m["color"],
                     fg=val_color, font=("Segoe UI", 14, "bold")).pack()
            tk.Label(sf, text=lbl, bg=m["color"],
                     fg="#888888", font=("Segoe UI", 7)).pack()

        # Divider
        tk.Frame(self.hdr, bg=m["accent"], height=1).pack(fill="x", padx=18, pady=(2, 0))

        # Open button spanning full card width
        btn_bar = tk.Frame(self.hdr, bg=m["color"], pady=8)
        btn_bar.pack(fill="x")
        self._toggle_lbl = tk.Label(btn_bar,
                                    text="  ▶  OPEN SECTION  ",
                                    bg=m["accent"], fg=m["color"],
                                    font=("Segoe UI", 9, "bold"),
                                    cursor="hand2", pady=8, relief="flat")
        self._toggle_lbl.pack(fill="x", padx=14)

        # Hover glow effect
        def _enter(e): self.hdr.configure(highlightthickness=3)
        def _leave(e): self.hdr.configure(highlightthickness=2)

        all_w = [self.hdr, icon_area, ring, stats_row, btn_bar, self._toggle_lbl]
        all_w += list(stats_row.winfo_children())
        for w in all_w:
            try:
                w.bind("<Button-1>", lambda e: self.toggle())
                w.bind("<Enter>",    _enter)
                w.bind("<Leave>",    _leave)
            except Exception:
                pass


    def toggle(self):
        """Open the full-screen section view."""
        self.app.open_section_fullscreen(self.sec_key)

    # ── collapse / expand kept for internal tab use ────────────
    def _collapse(self):
        self._expanded = False
        if self._body:
            self._body.destroy()
            self._body = None
            self._nb   = None

    # ── expand ────────────────────────────────────────────────
    def _expand(self, parent_frame):
        """Build section tabs inside parent_frame (used by fullscreen overlay)."""
        self._expanded = True
        m = self.meta

        self._body = tk.Frame(parent_frame, bg=T("BG"))
        self._body.pack(fill="both", expand=True)

        nb = ttk.Notebook(self._body)
        nb.pack(fill="both", expand=True, padx=8, pady=6)
        style = ttk.Style(); style.theme_use("clam")
        style.configure("TNotebook",     background=T("BG"),   borderwidth=0)
        style.configure("TNotebook.Tab", background=T("CARD"), foreground=T("TEXT"),
                        padding=[12, 5], font=("Segoe UI", 9, "bold"))
        style.map("TNotebook.Tab",
                  background=[("selected", m["color"])],
                  foreground=[("selected", m["accent"])])
        self._nb = nb

        self._tab_classes(nb)
        self._tab_learners(nb)
        self._tab_subjects(nb)
        self._tab_marks(nb)
        self._tab_reports(nb)

    # ══════════════════════════════════════════════════════════
    # TAB 1 — CLASSES
    # ══════════════════════════════════════════════════════════
    def _tab_classes(self, nb):
        frm = tk.Frame(nb, bg=T("BG")); nb.add(frm, text="🏫 Classes")
        m = self.meta

        top = tk.Frame(frm, bg=T("BG"), pady=6); top.pack(fill="x", padx=12)
        mk_lbl(top, f"Classes — {m['label']} ({m['sub']})", 12, True).pack(side="left")
        mk_btn(top, "＋ Add Class", lambda: self._add_class(tbl), m["accent"], T("BG")
               ).pack(side="right", padx=4)
        mk_btn(top, "✏ Edit", lambda: self._edit_class(tbl), T("ORANGE"), T("BG")
               ).pack(side="right", padx=4)
        mk_btn(top, "🗑 Delete", lambda: self._del_class(tbl), T("RED"), T("WHITE")
               ).pack(side="right", padx=4)

        tbl_f = tk.Frame(frm, bg=T("BG")); tbl_f.pack(fill="both", expand=True, padx=12, pady=4)
        tbl = StyledTable(tbl_f,
                          ["ID","Class Name","Grade","Teacher","Year","Learners"],
                          col_widths=[40,140,80,150,70,80],
                          context_menu=[
                              ("➕ Add Class",   lambda: self._add_class(tbl)),
                              ("✏ Edit Class",   lambda: self._edit_class(tbl)),
                              (None, None),
                              ("🗑 Delete Class", lambda: self._del_class(tbl)),
                          ])
        tbl.pack(fill="both", expand=True)
        self._reload_classes(tbl)

    def _reload_classes(self, tbl):
        tbl.clear()
        cls_rows = section_classes(self.sec_key, formatted=False)
        cids = {c["id"] for c in cls_rows}
        conn = get_conn()
        for r in conn.execute("""
            SELECT c.id,c.name,c.grade,COALESCE(c.teacher,'—'),
                   COALESCE(c.academic_year,'—'),COUNT(l.id)
            FROM classes c
            LEFT JOIN learners l ON l.class_id=c.id
            GROUP BY c.id ORDER BY c.grade,c.name""").fetchall():
            if r[0] in cids:
                tbl.insert(list(r))
        conn.close()

    def _add_class(self, tbl):
        self._class_form(tbl, edit=False)

    def _edit_class(self, tbl):
        sel = tbl.get_selected()
        if not sel: messagebox.showwarning("Select","Select a class first."); return
        self._class_form(tbl, edit=True, sel=sel)

    def _del_class(self, tbl):
        sel = tbl.get_selected()
        if not sel: messagebox.showwarning("Select","Select a class."); return
        if not messagebox.askyesno("Confirm",
                f"Delete class '{sel[1]}'?\n\nThis will also delete all assessments and results for this class."): return
        conn = get_conn()
        try:
            asms = [r[0] for r in conn.execute(
                "SELECT id FROM assessments WHERE class_id=?", (sel[0],)).fetchall()]
            for aid in asms:
                conn.execute("DELETE FROM results WHERE assessment_id=?", (aid,))
            conn.execute("DELETE FROM assessments WHERE class_id=?", (sel[0],))
            conn.execute("UPDATE learners SET class_id=NULL WHERE class_id=?", (sel[0],))
            conn.execute("DELETE FROM classes WHERE id=?", (sel[0],))
            conn.commit()
            messagebox.showinfo("Deleted", f"Class '{sel[1]}' deleted.")
        except Exception as ex:
            conn.rollback()
            messagebox.showerror("Error", str(ex))
        finally:
            conn.close()
        self._reload_classes(tbl)

    def _class_form(self, tbl, edit=False, sel=None):
        m = self.meta
        win = tk.Toplevel(); win.title("Edit Class" if edit else "Add Class")
        win.configure(bg=T("PANEL")); win.geometry("460x340"); win.grab_set()
        mk_lbl(win, "Edit Class" if edit else f"Add Class — {m['label']}", 13, True, m["accent"]).pack(pady=(14,6))

        frm = tk.Frame(win, bg=T("PANEL"), padx=28); frm.pack(fill="both", expand=True)

        if self.sec_key == "junior":
            grade_opts, def_grade = ["Grade 7","Grade 8","Grade 9"], "Grade 7"
        elif self.sec_key == "upper":
            grade_opts, def_grade = ["Grade 4","Grade 5","Grade 6"], "Grade 4"
        elif self.sec_key == "preprimary":
            grade_opts, def_grade = ["PP1","PP2","Nursery"], "PP1"
        else:
            grade_opts, def_grade = ["Grade 1","Grade 2","Grade 3"], "Grade 1"

        conn = get_conn()
        schools = [f"{r['id']}|{r['name']}" for r in
                   conn.execute("SELECT id,name FROM schools").fetchall()]
        conn.close()

        f_nm = LF(frm, "Class Name *", bg=T("PANEL")); f_nm.pack(fill="x", pady=4)
        f_gr = LF(frm, "Grade *", "combo", grade_opts, bg=T("PANEL")); f_gr.pack(fill="x", pady=4)
        f_tc = LF(frm, "Class Teacher", bg=T("PANEL")); f_tc.pack(fill="x", pady=4)
        f_yr = LF(frm, "Academic Year", bg=T("PANEL"))
        f_yr.set(str(datetime.now().year)); f_yr.pack(fill="x", pady=4)
        f_sc = LF(frm, "School", "combo", schools, bg=T("PANEL")); f_sc.pack(fill="x", pady=4)

        if not edit:
            f_gr.set(def_grade)
        else:
            conn = get_conn()
            row = conn.execute("SELECT * FROM classes WHERE id=?", (sel[0],)).fetchone()
            conn.close()
            if row:
                f_nm.set(row["name"]); f_gr.set(row["grade"] or "")
                f_tc.set(row["teacher"] or ""); f_yr.set(row["academic_year"] or "")
                for s in schools:
                    if s.startswith(str(row["school_id"])+"|"): f_sc.set(s); break

        def save():
            nm = f_nm.get(); gr = f_gr.get()
            if not nm or not gr:
                messagebox.showerror("Required","Class Name and Grade required.", parent=win); return
            sc_v = f_sc.get()
            sc_id = int(sc_v.split("|")[0]) if sc_v and "|" in sc_v else None
            conn = get_conn()
            try:
                if edit and sel:
                    conn.execute("UPDATE classes SET name=?,grade=?,school_id=?,teacher=?,academic_year=? WHERE id=?",
                                 (nm,gr,sc_id,f_tc.get(),f_yr.get(),sel[0]))
                else:
                    conn.execute("INSERT INTO classes (name,grade,school_id,teacher,academic_year) VALUES (?,?,?,?,?)",
                                 (nm,gr,sc_id,f_tc.get(),f_yr.get()))
                conn.commit()
                messagebox.showinfo("Saved","Class saved!", parent=win)
                win.destroy(); self._reload_classes(tbl)
            except Exception as ex:
                conn.rollback()
                messagebox.showerror("Error", str(ex), parent=win)
            finally: conn.close()

        bot = tk.Frame(win, bg=T("PANEL"), pady=8); bot.pack(side="bottom", fill="x", padx=28)
        mk_btn(bot, "💾 Save", save, m["accent"], T("BG")).pack(side="left", padx=4)
        tk.Button(bot, text="✖ Cancel", command=win.destroy, bg=T("BORDER"), fg=T("TEXT"),
                  font=FONT_H, relief="flat", padx=10, pady=5).pack(side="left", padx=4)

    # ══════════════════════════════════════════════════════════
    # TAB 2 — LEARNERS
    # ══════════════════════════════════════════════════════════
    def _tab_learners(self, nb):
        frm = tk.Frame(nb, bg=T("BG")); nb.add(frm, text="🎒 Learners")
        m = self.meta

        top = tk.Frame(frm, bg=T("BG"), pady=6); top.pack(fill="x", padx=12)
        mk_lbl(top, f"Learners — {m['label']}", 12, True).pack(side="left")

        sf = tk.Frame(frm, bg=T("BG")); sf.pack(fill="x", padx=12, pady=2)
        sv = tk.StringVar()
        tk.Entry(sf, textvariable=sv, font=FONT_B, bg=T("CARD"), fg=T("TEXT"),
                 insertbackground=T("ACCENT"), relief="flat",
                 highlightthickness=1, highlightbackground=T("BORDER"), width=30).pack(side="left")

        tbl_f = tk.Frame(frm, bg=T("BG")); tbl_f.pack(fill="both", expand=True, padx=12, pady=2)
        tbl = StyledTable(tbl_f,
                          ["ID","Adm No","First Name","Last Name","Gender","Class","Status"],
                          col_widths=[40,80,120,120,70,110,70],
                          context_menu=[
                              ("➕ Add Learner",     lambda: self._lrn_form(tbl, reload, edit=False)),
                              ("✏ Edit Learner",    lambda: self._lrn_form(tbl, reload, edit=True)),
                              ("📋 Report Card",    lambda: self._lrn_report(tbl)),
                              ("📱 Send Results SMS", lambda: self._lrn_sms(tbl)),
                              (None, None),
                              ("🗑 Delete",          lambda: self._lrn_del(tbl, reload)),
                              ("🗑 Delete Selected", lambda: self._lrn_del_selected(tbl, reload)),
                          ])
        tbl.pack(fill="both", expand=True)

        def reload():
            tbl.clear()
            q = sv.get().strip(); like = f"%{q}%"
            cls_rows = section_classes(self.sec_key, formatted=False)
            cids = [c["id"] for c in cls_rows]
            if not cids: return
            ph = ",".join("?"*len(cids))
            conn = get_conn()
            for r in conn.execute(f"""
                SELECT l.id,l.admission_no,UPPER(l.first_name),UPPER(l.last_name),
                       COALESCE(l.gender,'—'),COALESCE(c.name,'—'),l.status
                FROM learners l LEFT JOIN classes c ON l.class_id=c.id
                WHERE l.class_id IN ({ph})
                  AND (l.admission_no LIKE ? OR l.first_name LIKE ?
                       OR l.last_name LIKE ? OR c.name LIKE ?)
                ORDER BY l.last_name,l.first_name
            """, (*cids, like, like, like, like)).fetchall():
                tbl.insert(list(r))
            conn.close()

        sv.trace_add("write", lambda *_: reload())

        ab = tk.Frame(frm, bg=T("BG")); ab.pack(fill="x", padx=12, pady=(0,4))
        mk_btn(ab, "＋ Add",    lambda: self._lrn_form(tbl, reload, edit=False), m["accent"], T("BG")).pack(side="left", padx=3)
        mk_btn(ab, "✏ Edit",   lambda: self._lrn_form(tbl, reload, edit=True),  T("ORANGE"), T("BG")).pack(side="left", padx=3)
        mk_btn(ab, "🗑 Delete", lambda: self._lrn_del(tbl, reload),              T("RED"),    T("WHITE")).pack(side="left", padx=3)
        mk_btn(ab, "🗑 Del. Selected", lambda: self._lrn_del_selected(tbl, reload), "#dc2626", T("WHITE")).pack(side="left", padx=3)
        mk_btn(ab, "🗑 Delete ALL",    lambda: self._lrn_del_all(tbl, reload),       "#7f1d1d", T("WHITE")).pack(side="left", padx=3)
        mk_btn(ab, "📋 Report Card", lambda: self._lrn_report(tbl),             "#a855f7",   T("WHITE")).pack(side="left", padx=3)
        mk_btn(ab, "📱 Send SMS",    lambda: self._lrn_sms(tbl),                "#0ea5e9",   T("WHITE")).pack(side="left", padx=3)
        tk.Label(ab, text="  Ctrl/Shift+click = multi-select",
                 bg=T("BG"), fg=T("SUBTEXT"), font=("Segoe UI",7)).pack(side="left", padx=4)
        reload()

    def _lrn_del(self, tbl, reload):
        sel = tbl.get_selected()
        if not sel: messagebox.showwarning("Select","Select a learner."); return
        name = f"{sel[2]} {sel[3]}" if len(sel) > 3 else str(sel[1])
        if messagebox.askyesno("Confirm", f"Delete learner '{name}'?\n\nThis will also remove all their results."):
            conn = get_conn()
            try:
                conn.execute("DELETE FROM results WHERE learner_id=?", (sel[0],))
                conn.execute("DELETE FROM learners WHERE id=?", (sel[0],))
                conn.commit()
                messagebox.showinfo("Deleted", f"Learner '{name}' deleted.")
            except Exception as ex:
                conn.rollback()
                messagebox.showerror("Error", str(ex))
            finally:
                conn.close()
            reload()

    def _lrn_del_selected(self, tbl, reload):
        """Delete all selected learners (multi-select) from this section's panel."""
        rows = tbl.get_all_selected()
        if not rows:
            messagebox.showwarning("Select", "Select one or more learners.\n\n"
                                             "Tip: Use Ctrl+click or Shift+click to select multiple.")
            return
        names = "\n".join(f"  • {r[2]} {r[3]}" for r in rows[:10])
        if len(rows) > 10:
            names += f"\n  … and {len(rows)-10} more"
        if not messagebox.askyesno("Confirm Delete",
                f"Delete {len(rows)} learner(s)?\n\n{names}\n\n"
                "This will also remove ALL their results. Cannot be undone.",
                icon="warning"):
            return
        conn = get_conn(); deleted = 0
        try:
            for r in rows:
                conn.execute("DELETE FROM results WHERE learner_id=?", (r[0],))
                conn.execute("DELETE FROM learners WHERE id=?", (r[0],))
                deleted += 1
            conn.commit()
            messagebox.showinfo("Deleted", f"✅ {deleted} learner(s) deleted.")
        except Exception as ex:
            conn.rollback()
            messagebox.showerror("Error", str(ex))
        finally:
            conn.close()
        reload()

    def _lrn_del_all(self, tbl, reload):
        """Delete ALL learners in this section after double confirmation."""
        m = self.meta
        cls_rows = section_classes(self.sec_key, formatted=False)
        cids = [c["id"] for c in cls_rows]
        if not cids:
            messagebox.showinfo("Empty", "No classes in this section."); return
        conn = get_conn()
        ph = ",".join("?"*len(cids))
        count = conn.execute(
            f"SELECT COUNT(*) FROM learners WHERE class_id IN ({ph})", cids).fetchone()[0]
        conn.close()
        if count == 0:
            messagebox.showinfo("Empty", "No learners found in this section."); return
        if not messagebox.askyesno("⚠ Delete ALL Learners",
                f"Permanently delete ALL {count} learner(s) in\n"
                f"{m['label']} ({m['sub']})?\n\n"
                "All results will also be deleted. This cannot be undone.",
                icon="warning"):
            return
        # Second confirmation window
        cwin = tk.Toplevel(); cwin.title("⚠ Confirm Delete All")
        cwin.configure(bg=T("PANEL")); cwin.geometry("400x195"); cwin.grab_set(); cwin.resizable(False,False)
        tk.Label(cwin, text="⚠ FINAL WARNING", bg=T("PANEL"), fg=T("RED"),
                 font=("Segoe UI",13,"bold")).pack(pady=(14,4))
        tk.Label(cwin, text=f"Type DELETE to confirm removing all {count} learner(s):",
                 bg=T("PANEL"), fg=T("TEXT"), font=FONT_B).pack()
        cv = tk.StringVar()
        tk.Entry(cwin, textvariable=cv, font=FONT_H, bg=T("CARD"), fg=T("RED"),
                 justify="center", insertbackground=T("RED"), relief="flat",
                 highlightthickness=1, highlightbackground=T("RED"), width=20).pack(pady=8)
        def _confirm():
            if cv.get().strip().upper() != "DELETE":
                messagebox.showerror("Wrong","Type DELETE (capitals) to confirm.", parent=cwin); return
            cwin.destroy()
            conn2 = get_conn()
            try:
                lids = [r[0] for r in conn2.execute(
                    f"SELECT id FROM learners WHERE class_id IN ({ph})", cids).fetchall()]
                for lid in lids:
                    conn2.execute("DELETE FROM results WHERE learner_id=?", (lid,))
                conn2.execute(f"DELETE FROM learners WHERE class_id IN ({ph})", cids)
                conn2.commit()
                messagebox.showinfo("Deleted", f"✅ All {len(lids)} learner(s) deleted from {m['label']}.")
            except Exception as ex:
                conn2.rollback()
                messagebox.showerror("Error", str(ex))
            finally:
                conn2.close()
            reload()
        bot = tk.Frame(cwin, bg=T("PANEL"), pady=6); bot.pack()
        mk_btn(bot, "🗑 Confirm DELETE ALL", _confirm, "#7f1d1d", T("WHITE")).pack(side="left", padx=4)
        tk.Button(bot, text="✖ Cancel", command=cwin.destroy, bg=T("BORDER"), fg=T("TEXT"),
                  font=FONT_H, relief="flat", padx=10, pady=5).pack(side="left", padx=4)

    def _lrn_report(self, tbl):
        sel = tbl.get_selected()
        if not sel: messagebox.showwarning("Select","Select a learner."); return
        ReportCardWindow(self.app, sel[0], f"{sel[2]} {sel[3]}")

    def _lrn_sms(self, tbl):
        """Send results as SMS to the selected learner's parent."""
        sel = tbl.get_selected()
        if not sel:
            messagebox.showwarning("Select", "Select a learner to send SMS."); return
        learner_id = sel[0]
        conn = get_conn()
        lrn = conn.execute("SELECT * FROM learners WHERE id=?", (learner_id,)).fetchone()
        if not lrn:
            conn.close(); messagebox.showerror("Error", "Learner not found."); return

        phone = (lrn["parent_phone"] or "").strip()
        lrn_name = f"{lrn['first_name']} {lrn['last_name']}".strip()

        # Fetch latest results
        rows = conn.execute("""
            SELECT s.code AS subject_code, r.marks, s.max_marks
            FROM results r
            JOIN subjects s ON r.subject_id = s.id
            WHERE r.learner_id = ?
            ORDER BY s.code
        """, (learner_id,)).fetchall()
        conn.close()

        # ── SMS Compose Dialog ──
        m = self.meta
        win = tk.Toplevel(); win.title(f"Send Results SMS — {lrn_name}")
        win.configure(bg=T("PANEL")); win.geometry("540x520"); win.grab_set()
        mk_lbl(win, f"📱  Send Results via SMS", 13, True, "#0ea5e9").pack(pady=(12,4))
        mk_lbl(win, f"Learner: {lrn_name}", 10, color=T("TEXT")).pack()

        card = tk.Frame(win, bg=T("CARD"), padx=20, pady=16); card.pack(fill="both", expand=True, padx=16, pady=8)

        # Phone
        tk.Label(card, text="Parent Phone:", bg=T("CARD"), fg=T("SUBTEXT"), font=FONT_B, anchor="w").pack(fill="x")
        phone_var = tk.StringVar(value=phone)
        tk.Entry(card, textvariable=phone_var, font=FONT_B, bg=T("BG"), fg=T("TEXT"),
                 insertbackground=T("ACCENT"), relief="flat",
                 highlightthickness=1, highlightbackground=T("BORDER")).pack(fill="x", pady=(2,10), ipady=6)

        # Term / Year
        tf = tk.Frame(card, bg=T("CARD")); tf.pack(fill="x", pady=(0,6))
        tk.Label(tf, text="Term:", bg=T("CARD"), fg=T("SUBTEXT"), font=FONT_B).pack(side="left")
        term_var = tk.StringVar(value="Term 1")
        ttk.Combobox(tf, textvariable=term_var, values=["Term 1","Term 2","Term 3"],
                     width=10, state="readonly", font=FONT_B).pack(side="left", padx=(4,16))
        tk.Label(tf, text="Year:", bg=T("CARD"), fg=T("SUBTEXT"), font=FONT_B).pack(side="left")
        year_var = tk.StringVar(value=str(datetime.now().year))
        tk.Entry(tf, textvariable=year_var, width=8, font=FONT_B, bg=T("BG"), fg=T("TEXT"),
                 insertbackground=T("ACCENT"), relief="flat",
                 highlightthickness=1, highlightbackground=T("BORDER")).pack(side="left", padx=4)

        # Position
        pf = tk.Frame(card, bg=T("CARD")); pf.pack(fill="x", pady=(0,10))
        tk.Label(pf, text="Position:", bg=T("CARD"), fg=T("SUBTEXT"), font=FONT_B).pack(side="left")
        pos_var = tk.StringVar(value="")
        tk.Entry(pf, textvariable=pos_var, width=6, font=FONT_B, bg=T("BG"), fg=T("TEXT"),
                 insertbackground=T("ACCENT"), relief="flat",
                 highlightthickness=1, highlightbackground=T("BORDER")).pack(side="left", padx=(4,12))
        tk.Label(pf, text="out of:", bg=T("CARD"), fg=T("SUBTEXT"), font=FONT_B).pack(side="left")
        total_var = tk.StringVar(value="")
        tk.Entry(pf, textvariable=total_var, width=6, font=FONT_B, bg=T("BG"), fg=T("TEXT"),
                 insertbackground=T("ACCENT"), relief="flat",
                 highlightthickness=1, highlightbackground=T("BORDER")).pack(side="left", padx=4)

        # Message preview
        tk.Label(card, text="Message Preview:", bg=T("CARD"), fg=T("SUBTEXT"), font=FONT_B, anchor="w").pack(fill="x", pady=(6,2))
        msg_box = tk.Text(card, height=5, font=("Segoe UI", 9), bg=T("BG"), fg=T("TEXT"),
                          insertbackground=T("ACCENT"), relief="flat",
                          highlightthickness=1, highlightbackground=T("BORDER"), wrap="word")
        msg_box.pack(fill="both", expand=True, pady=(0,6))

        char_lbl = tk.Label(card, text="0 chars", bg=T("CARD"), fg=T("SUBTEXT"), font=("Segoe UI",8), anchor="e")
        char_lbl.pack(fill="x")

        lrn_dict = dict(lrn)
        rows_list = [dict(r) for r in rows]

        def _refresh_preview(*_):
            msg = sms_build_message(lrn_dict, rows_list,
                                    term=term_var.get(), year=year_var.get(),
                                    position=pos_var.get(), total_learners=total_var.get())
            msg_box.delete("1.0", "end"); msg_box.insert("1.0", msg)
            char_lbl.configure(text=f"{len(msg)} chars  ({'1 SMS' if len(msg)<=160 else str((len(msg)-1)//160+1)+' SMS'})")

        term_var.trace_add("write", _refresh_preview)
        year_var.trace_add("write", _refresh_preview)
        pos_var.trace_add("write",  _refresh_preview)
        total_var.trace_add("write",_refresh_preview)
        _refresh_preview()

        status_lbl = tk.Label(card, text="", bg=T("CARD"), fg=T("GREEN"), font=("Segoe UI",9), anchor="w")
        status_lbl.pack(fill="x", pady=(4,0))

        def _send():
            ph = phone_var.get().strip()
            if not ph:
                status_lbl.configure(text="⚠  No phone number entered.", fg=T("ORANGE")); return
            msg = msg_box.get("1.0","end").strip()
            if not msg:
                status_lbl.configure(text="⚠  Message is empty.", fg=T("ORANGE")); return
            status_lbl.configure(text="⏳  Sending…", fg=T("SUBTEXT")); win.update_idletasks()
            ok, reason = sms_send(ph, msg)
            if ok:
                status_lbl.configure(text=f"✅  SMS sent to {ph} successfully!", fg=T("GREEN"))
            else:
                status_lbl.configure(text=f"❌  Failed: {reason}", fg=T("RED"))

        bot = tk.Frame(win, bg=T("PANEL"), pady=8); bot.pack(side="bottom", fill="x", padx=16)
        mk_btn(bot, "📤 Send SMS", _send, "#0ea5e9", T("WHITE")).pack(side="left", padx=4)
        tk.Button(bot, text="✖ Close", command=win.destroy, bg=T("BORDER"), fg=T("TEXT"),
                  font=FONT_H, relief="flat", padx=10, pady=5).pack(side="left", padx=4)

    def _lrn_form(self, tbl, reload, edit=False):
        sel = tbl.get_selected() if edit else None
        if edit and not sel: messagebox.showwarning("Select","Select a learner."); return
        m = self.meta
        win = tk.Toplevel(); win.title("Edit Learner" if edit else "Add Learner")
        win.configure(bg=T("PANEL")); win.geometry("520x520"); win.grab_set()
        mk_lbl(win, "Edit Learner" if edit else f"Add Learner — {m['label']}", 13, True, m["accent"]).pack(pady=(12,6))

        sf = ScrollFrame(win, bg=T("PANEL")); sf.pack(fill="both", expand=True, padx=20)
        frm = sf.inner

        # Class list filtered to this section
        cls_rows = section_classes(self.sec_key)
        f_cl = LF(frm,"Class *","combo", cls_rows, bg=T("PANEL")); f_cl.pack(fill="x",pady=3)
        f_ad = LF(frm,"Admission No *",       bg=T("PANEL")); f_ad.pack(fill="x",pady=3)
        f_fn = LF(frm,"First Name *",          bg=T("PANEL")); f_fn.pack(fill="x",pady=3)
        f_ln = LF(frm,"Last Name *",           bg=T("PANEL")); f_ln.pack(fill="x",pady=3)
        f_on = LF(frm,"Other Name",            bg=T("PANEL")); f_on.pack(fill="x",pady=3)
        f_gn = LF(frm,"Gender","combo",["Male","Female","Other"],bg=T("PANEL")); f_gn.pack(fill="x",pady=3)
        f_nm = LF(frm,"Assessment No",              bg=T("PANEL")); f_nm.pack(fill="x",pady=3)
        f_pp = LF(frm,"Parent Name",           bg=T("PANEL")); f_pp.pack(fill="x",pady=3)
        f_ph = LF(frm,"Parent Phone",          bg=T("PANEL")); f_ph.pack(fill="x",pady=3)
        f_st = LF(frm,"Status","combo",["Active","Inactive","Transferred"],bg=T("PANEL"))
        f_st.set("Active"); f_st.pack(fill="x",pady=3)

        if edit and sel:
            conn = get_conn()
            row = conn.execute("SELECT * FROM learners WHERE id=?", (sel[0],)).fetchone()
            conn.close()
            if row:
                f_ad.set(row["admission_no"]); f_fn.set(row["first_name"])
                f_ln.set(row["last_name"]); f_on.set(row["other_name"] or "")
                f_gn.set(row["gender"] or ""); f_nm.set(row["nemis_no"] or "")
                f_pp.set(row["parent_name"] or ""); f_ph.set(row["parent_phone"] or "")
                f_st.set(row["status"] or "Active")
                for opt in cls_rows:
                    if opt.startswith(str(row["class_id"])+"|"): f_cl.set(opt); break

        def save():
            adm=f_ad.get(); fn=f_fn.get(); ln=f_ln.get()
            if not adm or not fn or not ln:
                messagebox.showerror("Required","Adm No, First & Last Name required.",parent=win); return
            cl_v = f_cl.get()
            cl_id = int(cl_v.split("|")[0]) if cl_v and "|" in cl_v else None
            conn = get_conn()
            try:
                if edit and sel:
                    conn.execute("""UPDATE learners SET admission_no=?,first_name=?,last_name=?,
                        other_name=?,gender=?,nemis_no=?,class_id=?,parent_name=?,parent_phone=?,status=?
                        WHERE id=?""",
                        (adm,fn,ln,f_on.get(),f_gn.get(),f_nm.get() or None,
                         cl_id,f_pp.get(),f_ph.get(),f_st.get(),sel[0]))
                else:
                    conn.execute("""INSERT INTO learners
                        (admission_no,first_name,last_name,other_name,gender,nemis_no,
                         class_id,parent_name,parent_phone,status)
                        VALUES (?,?,?,?,?,?,?,?,?,?)""",
                        (adm,fn,ln,f_on.get(),f_gn.get(),f_nm.get() or None,
                         cl_id,f_pp.get(),f_ph.get(),f_st.get() or "Active"))
                conn.commit()
                messagebox.showinfo("Saved","Learner saved!",parent=win)
                win.destroy(); reload()
            except sqlite3.IntegrityError as ex:
                messagebox.showerror("Duplicate",str(ex),parent=win)
            finally: conn.close()

        bot = tk.Frame(win, bg=T("PANEL"), pady=8); bot.pack(side="bottom", fill="x", padx=20)
        mk_btn(bot,"💾 Save",save,m["accent"],T("BG")).pack(side="left",padx=4)
        tk.Button(bot,text="✖ Cancel",command=win.destroy,bg=T("BORDER"),fg=T("TEXT"),
                  font=FONT_H,relief="flat",padx=10,pady=5).pack(side="left",padx=4)

    # ══════════════════════════════════════════════════════════
    # TAB 3 — SUBJECTS (section-filtered)
    # ══════════════════════════════════════════════════════════
    def _tab_subjects(self, nb):
        frm = tk.Frame(nb, bg=T("BG")); nb.add(frm, text="📚 Subjects")
        m = self.meta

        lo, hi = _grade_sort_range(
            "Grade 7" if self.sec_key=="junior" else
            "Grade 4" if self.sec_key=="upper"  else
            "Grade 1" if self.sec_key=="lower"  else "PP1")

        top = tk.Frame(frm, bg=T("BG"), pady=6); top.pack(fill="x", padx=12)
        mk_lbl(top, f"Subjects — {m['label']} ({m['sub']})", 12, True).pack(side="left")
        mk_btn(top, "＋ Add Subject", lambda: self._add_subject(tbl, reload, lo, hi),
               m["accent"], T("BG")).pack(side="right", padx=3)
        mk_btn(top, "➕ Add Sub-Subject", lambda: self._add_sub_subject(tbl, reload, lo, hi),
               T("ORANGE"), T("BG")).pack(side="right", padx=3)

        tbl_f = tk.Frame(frm, bg=T("BG")); tbl_f.pack(fill="both", expand=True, padx=12, pady=4)
        tbl = StyledTable(tbl_f,["Code","Subject Name","Max Marks","Type","Active"],
                          col_widths=[80,230,90,100,60],
                          context_menu=[
                              ("✏ Edit Subject",        lambda: self._edit_subject(tbl, reload, lo, hi)),
                              (None, None),
                              ("🗑 Delete Subject",      lambda: self._del_subject(tbl, reload)),
                              ("🗑 Delete ALL Subjects", lambda: self._del_all_subjects(reload, lo, hi)),
                          ])
        tbl.pack(fill="both", expand=True)

        def reload():
            tbl.clear()
            conn = get_conn()
            # Include standard subjects in this section's sort_order range PLUS
            # any sub-subjects whose composite parent falls in the same range
            # (sub-subjects are stored with sort_order=99 so the plain BETWEEN
            # filter would silently exclude them, making them un-editable).
            for r in conn.execute(
                "SELECT code,name,max_marks,is_active,"
                "COALESCE(is_composite,0) AS is_composite,"
                "COALESCE(composite_parent_id,NULL) AS composite_parent_id "
                "FROM subjects "
                "WHERE sort_order BETWEEN ? AND ? "
                "   OR composite_parent_id IN ("
                "       SELECT id FROM subjects WHERE sort_order BETWEEN ? AND ?) "
                "ORDER BY COALESCE(composite_parent_id,0), sort_order, name",
                (lo, hi, lo, hi)).fetchall():
                if r["composite_parent_id"]:
                    prow = conn.execute("SELECT name FROM subjects WHERE id=?",
                                        (r["composite_parent_id"],)).fetchone()
                    pname = prow["name"] if prow else "?"
                    stype = f"↳ Sub of: {pname[:16]}"
                elif r["is_composite"]:
                    stype = "Composite (parent)"
                else:
                    stype = "Standard"
                tbl.insert([r["code"],r["name"],int(r["max_marks"]),stype,
                            "Yes" if r["is_active"] else "No"])
            conn.close()

        ab = tk.Frame(frm, bg=T("BG")); ab.pack(fill="x", padx=12, pady=(0,4))
        mk_btn(ab,"✏ Edit Subject", lambda: self._edit_subject(tbl, reload, lo, hi),
               T("ORANGE"), T("BG")).pack(side="left", padx=3)
        mk_btn(ab,"🗑 Delete Subject", lambda: self._del_subject(tbl, reload),
               T("RED"), T("WHITE")).pack(side="left", padx=3)
        mk_btn(ab,"🗑 Delete ALL Subjects", lambda: self._del_all_subjects(reload, lo, hi),
               "#7f1d1d", T("WHITE")).pack(side="left", padx=3)
        tk.Label(frm, text="  ℹ  Subjects are shared across all classes in this section. "
                           "Sub-subjects appear in the Marksheet only and their scores SUM into the parent in Broadsheet/Report forms.",
                 bg=T("BG"), fg=T("SUBTEXT"), font=("Segoe UI",8)).pack(anchor="w",padx=12)
        reload()

    def _add_subject(self, tbl, reload, lo, hi):
        """Open a form to add a new subject scoped to this section's sort_order range."""
        m = self.meta
        win = tk.Toplevel(); win.title("Add Subject"); win.configure(bg=T("PANEL"))
        win.geometry("420x320"); win.grab_set()
        mk_lbl(win, f"Add Subject — {m['label']}", 13, True, m["accent"]).pack(pady=(12,6))
        frm = tk.Frame(win, bg=T("PANEL"), padx=24); frm.pack(fill="both", expand=True)

        f_cd = LF(frm, "Short Code *  e.g. ENG, MTH", bg=T("PANEL")); f_cd.pack(fill="x", pady=4)
        f_nm = LF(frm, "Full Subject Name *", caps=True, bg=T("PANEL")); f_nm.pack(fill="x", pady=4)
        f_mx = LF(frm, "Max Marks", bg=T("PANEL")); f_mx.set("100"); f_mx.pack(fill="x", pady=4)
        f_st = LF(frm, "Strand", "combo",
                  ["Core","Humanities","Sciences","Technical","Applied","Creative","Values"],
                  bg=T("PANEL")); f_st.set("Core"); f_st.pack(fill="x", pady=4)
        f_ac = LF(frm, "Active", "combo", ["Yes","No"], bg=T("PANEL")); f_ac.set("Yes"); f_ac.pack(fill="x", pady=4)

        def save():
            cd = f_cd.get().strip(); nm = f_nm.get().strip()
            if not cd or not nm:
                messagebox.showerror("Required","Code and Name are required.",parent=win); return
            try: mx = float(f_mx.get() or 100)
            except: mx = 100.0
            # Assign next available sort_order in this section's range
            conn2 = get_conn()
            existing_orders = [r[0] for r in conn2.execute(
                "SELECT sort_order FROM subjects WHERE sort_order BETWEEN ? AND ? ORDER BY sort_order",
                (lo, hi)).fetchall()]
            # Find first gap in the range, or use hi if all taken
            new_order = lo
            for o in range(lo, hi + 1):
                if o not in existing_orders:
                    new_order = o; break
            else:
                # Range full — use hi+1 as overflow (still functionally works)
                new_order = hi
            try:
                conn2.execute(
                    "INSERT INTO subjects (code,name,strand,max_marks,is_active,sort_order,section_key) "
                    "VALUES (?,?,?,?,?,?,?)",
                    (cd, nm, f_st.get(), mx, 1 if f_ac.get()=="Yes" else 0, new_order, self.sec_key))
                conn2.commit()
                messagebox.showinfo("Saved","Subject added!",parent=win)
                win.destroy(); reload()
            except sqlite3.IntegrityError:
                messagebox.showerror("Duplicate",f"Code '{cd}' already exists.",parent=win)
            finally: conn2.close()

        bot = tk.Frame(win, bg=T("PANEL"), pady=8); bot.pack(side="bottom", fill="x", padx=24)
        mk_btn(bot, "💾 Save", save, m["accent"], T("BG")).pack(side="left", padx=4)
        tk.Button(bot, text="✖ Cancel", command=win.destroy, bg=T("BORDER"), fg=T("TEXT"),
                  font=FONT_H, relief="flat", padx=10, pady=5).pack(side="left", padx=4)

    def _add_sub_subject(self, tbl, reload, lo, hi):
        """Add a sub-subject that is hidden in broadsheet/report form but visible in marksheet.
        Its marks are weighted into a composite parent subject's total.
        """
        m = self.meta
        conn_p = get_conn()
        # Get parent-eligible subjects in this section (standard or composite parents)
        parent_opts = conn_p.execute(
            "SELECT id, code, name FROM subjects "
            "WHERE is_active=1 AND sort_order BETWEEN ? AND ? "
            "AND COALESCE(composite_parent_id,0)=0 "
            "ORDER BY sort_order, name",
            (lo, hi)).fetchall()
        conn_p.close()

        if not parent_opts:
            messagebox.showwarning("No Subjects",
                "No parent subjects found in this section.\n"
                "Add at least one regular subject first, then add sub-subjects under it.")
            return

        win = tk.Toplevel(); win.title("Add Sub-Subject"); win.configure(bg=T("PANEL"))
        win.geometry("460x320"); win.grab_set()
        mk_lbl(win, f"Add Sub-Subject — {m['label']}", 13, True, T("ORANGE")).pack(pady=(12,6))
        tk.Label(win,
                 text="Sub-subjects appear ONLY in the Marksheet.\n"
                      "Their scores are SUMMED into the parent subject\n"
                      "for the Broadsheet and Report Form.",
                 bg=T("PANEL"), fg=T("SUBTEXT"), font=("Segoe UI",8),
                 justify="left").pack(anchor="w", padx=24, pady=(0,6))

        frm = tk.Frame(win, bg=T("PANEL"), padx=24); frm.pack(fill="both", expand=True)

        # Parent subject picker
        f_pr = LF(frm, "Parent Subject *", "combo",
                  [f"{r['id']}|{r['code']} — {r['name']}" for r in parent_opts],
                  bg=T("PANEL")); f_pr.pack(fill="x", pady=4)
        f_cd = LF(frm, "Sub-Subject Short Code *  e.g. ORAL, WRIT", bg=T("PANEL")); f_cd.pack(fill="x", pady=4)
        f_nm = LF(frm, "Sub-Subject Full Name *", caps=True, bg=T("PANEL")); f_nm.pack(fill="x", pady=4)
        f_mx = LF(frm, "Max Marks", bg=T("PANEL")); f_mx.set("100"); f_mx.pack(fill="x", pady=4)

        def save():
            pr_sel = f_pr.get()
            if not pr_sel:
                messagebox.showerror("Required","Select a parent subject.",parent=win); return
            try:
                parent_id = int(pr_sel.split("|")[0])
            except:
                messagebox.showerror("Error","Invalid parent subject.",parent=win); return
            cd = f_cd.get().strip(); nm = f_nm.get().strip()
            if not cd or not nm:
                messagebox.showerror("Required","Code and Name are required.",parent=win); return
            try: mx = float(f_mx.get() or 100)
            except: mx = 100.0

            conn2 = get_conn()
            # Mark parent as composite
            conn2.execute("UPDATE subjects SET is_composite=1 WHERE id=?", (parent_id,))
            # Sub-subjects always get sort_order=99 — they are found via
            # composite_parent_id, not by sort_order range, so 99 is safe.
            new_order = 99

            try:
                conn2.execute(
                    "INSERT INTO subjects (code,name,strand,max_marks,is_active,sort_order,"
                    "section_key,is_composite,composite_parent_id,composite_weight) "
                    "VALUES (?,?,?,?,1,?,?,0,?,1.0)",
                    (cd, nm, "Sub", mx, new_order, self.sec_key, parent_id))
                conn2.commit()
                messagebox.showinfo("Saved",
                    f"Sub-subject '{nm}' added under parent subject.\n"
                    "It will appear in Marksheet only.\n"
                    "The parent subject will show the combined SUM in Broadsheet & Report Form.",
                    parent=win)
                win.destroy(); reload()
            except sqlite3.IntegrityError:
                messagebox.showerror("Duplicate",f"Code '{cd}' already exists.",parent=win)
            finally: conn2.close()

        bot = tk.Frame(win, bg=T("PANEL"), pady=8); bot.pack(side="bottom", fill="x", padx=24)
        mk_btn(bot, "💾 Save Sub-Subject", save, T("ORANGE"), T("BG")).pack(side="left", padx=4)
        tk.Button(bot, text="✖ Cancel", command=win.destroy, bg=T("BORDER"), fg=T("TEXT"),
                  font=FONT_H, relief="flat", padx=10, pady=5).pack(side="left", padx=4)

    def _del_subject(self, tbl, reload):
        sel = tbl.get_selected()
        if not sel: messagebox.showwarning("Select","Select a subject to delete."); return
        code = sel[0]; name = sel[1]
        if not messagebox.askyesno("Confirm Delete",
                                   f"Delete subject '{name}' ({code})?\n\n"
                                   "⚠ This will also remove all assessments and results linked to it.",
                                   icon="warning"): return
        conn = get_conn()
        row = conn.execute("SELECT id FROM subjects WHERE code=?", (code,)).fetchone()
        if row:
            # cascade: results → assessments → subject
            asms = [r[0] for r in conn.execute(
                "SELECT id FROM assessments WHERE subject_id=?", (row["id"],)).fetchall()]
            for aid in asms:
                conn.execute("DELETE FROM results WHERE assessment_id=?", (aid,))
            conn.execute("DELETE FROM assessments WHERE subject_id=?", (row["id"],))
            conn.execute("DELETE FROM subjects WHERE id=?", (row["id"],))
            conn.commit()
            messagebox.showinfo("Deleted", f"Subject '{name}' deleted.")
        conn.close(); reload()

    def _del_all_subjects(self, reload, lo, hi):
        """Delete ALL subjects in this section's sort_order range after double confirmation."""
        m = self.meta
        conn = get_conn()
        subj_rows = conn.execute(
            "SELECT id, name FROM subjects WHERE sort_order BETWEEN ? AND ?", (lo, hi)).fetchall()
        conn.close()
        if not subj_rows:
            messagebox.showinfo("Empty", "No subjects found in this section."); return
        if not messagebox.askyesno("⚠ Delete ALL Subjects",
                f"Permanently delete ALL {len(subj_rows)} subject(s) in\n"
                f"{m['label']} ({m['sub']})?\n\n"
                "All assessments and results linked to these subjects will also be deleted. "
                "This CANNOT be undone.", icon="warning"):
            return
        cwin = tk.Toplevel(); cwin.title("⚠ Confirm Delete All Subjects")
        cwin.configure(bg=T("PANEL")); cwin.geometry("420x200"); cwin.grab_set(); cwin.resizable(False, False)
        tk.Label(cwin, text="⚠ FINAL WARNING", bg=T("PANEL"), fg=T("RED"),
                 font=("Segoe UI", 13, "bold")).pack(pady=(14, 4))
        tk.Label(cwin, text=f"Type DELETE to confirm removing all {len(subj_rows)} subject(s):",
                 bg=T("PANEL"), fg=T("TEXT"), font=FONT_B).pack()
        cv = tk.StringVar()
        tk.Entry(cwin, textvariable=cv, font=FONT_H, bg=T("CARD"), fg=T("RED"),
                 justify="center", insertbackground=T("RED"), relief="flat",
                 highlightthickness=1, highlightbackground=T("RED"), width=20).pack(pady=8)
        def _confirm():
            if cv.get().strip().upper() != "DELETE":
                messagebox.showerror("Wrong", "Type DELETE (capitals) to confirm.", parent=cwin); return
            cwin.destroy()
            conn2 = get_conn()
            try:
                for row in subj_rows:
                    asms = [r[0] for r in conn2.execute(
                        "SELECT id FROM assessments WHERE subject_id=?", (row["id"],)).fetchall()]
                    for aid in asms:
                        conn2.execute("DELETE FROM results WHERE assessment_id=?", (aid,))
                    conn2.execute("DELETE FROM assessments WHERE subject_id=?", (row["id"],))
                    conn2.execute("DELETE FROM subjects WHERE id=?", (row["id"],))
                conn2.commit()
                messagebox.showinfo("Deleted", f"✅ All {len(subj_rows)} subject(s) in {m['label']} deleted.")
            except Exception as ex:
                conn2.rollback()
                messagebox.showerror("Error", str(ex))
            finally:
                conn2.close()
            reload()
        bot = tk.Frame(cwin, bg=T("PANEL"), pady=6); bot.pack()
        mk_btn(bot, "🗑 Confirm DELETE ALL", _confirm, "#7f1d1d", T("WHITE")).pack(side="left", padx=4)
        tk.Button(bot, text="✖ Cancel", command=cwin.destroy, bg=T("BORDER"), fg=T("TEXT"),
                  font=FONT_H, relief="flat", padx=10, pady=5).pack(side="left", padx=4)

    def _edit_subject(self, tbl, reload, lo, hi):
        sel = tbl.get_selected()
        if not sel: messagebox.showwarning("Select","Select a subject."); return
        code = sel[0]
        conn = get_conn()
        row = conn.execute("SELECT * FROM subjects WHERE code=?", (code,)).fetchone()
        conn.close()
        if not row: return

        win = tk.Toplevel(); win.title("Edit Subject"); win.configure(bg=T("PANEL"))
        win.geometry("400x280"); win.grab_set()
        mk_lbl(win,"Edit Subject",13,True,T("ACCENT")).pack(pady=(12,6))
        frm = tk.Frame(win,bg=T("PANEL"),padx=24); frm.pack(fill="both",expand=True)

        f_cd = LF(frm,"Code *",   bg=T("PANEL")); f_cd.set(row["code"]); f_cd.pack(fill="x",pady=4)
        f_nm = LF(frm,"Name *",   bg=T("PANEL")); f_nm.set(row["name"]); f_nm.pack(fill="x",pady=4)
        f_mx = LF(frm,"Max Marks",bg=T("PANEL")); f_mx.set(str(row["max_marks"])); f_mx.pack(fill="x",pady=4)
        f_ac = LF(frm,"Active","combo",["Yes","No"],bg=T("PANEL"))
        f_ac.set("Yes" if row["is_active"] else "No"); f_ac.pack(fill="x",pady=4)

        def save():
            cd=f_cd.get(); nm=f_nm.get()
            if not cd or not nm:
                messagebox.showerror("Required","Code and Name required.",parent=win); return
            try: mx=float(f_mx.get() or 100)
            except: mx=100.0
            conn2=get_conn()
            try:
                conn2.execute("UPDATE subjects SET code=?,name=?,max_marks=?,is_active=? WHERE id=?",
                              (cd,nm,mx,1 if f_ac.get()=="Yes" else 0,row["id"]))
                conn2.commit()
                messagebox.showinfo("Saved","Subject updated!",parent=win)
                win.destroy(); reload()
            except Exception as ex:
                conn2.rollback()
                messagebox.showerror("Error",str(ex),parent=win)
            finally: conn2.close()

        bot=tk.Frame(win,bg=T("PANEL"),pady=8); bot.pack(side="bottom",fill="x",padx=24)
        mk_btn(bot,"💾 Save",save).pack(side="left",padx=4)
        tk.Button(bot,text="✖ Cancel",command=win.destroy,bg=T("BORDER"),fg=T("TEXT"),
                  font=FONT_H,relief="flat",padx=10,pady=5).pack(side="left",padx=4)

    # ══════════════════════════════════════════════════════════
    # TAB 4 — ENTER MARKS (bulk grid)
    # ══════════════════════════════════════════════════════════
    def _tab_marks(self, nb):
        frm = tk.Frame(nb, bg=T("BG")); nb.add(frm, text="✏️ Enter Marks")
        m = self.meta

        fb = tk.Frame(frm, bg=T("CARD"), padx=12, pady=8); fb.pack(fill="x", padx=12, pady=6)
        classes = section_classes(self.sec_key)
        cls_var  = tk.StringVar()
        term_var = tk.StringVar(value="Term 1")
        year_var = tk.StringVar(value=str(datetime.now().year))
        type_var = tk.StringVar(value="End of Term")
        sort_var = tk.StringVar(value="Name (A–Z)")

        mk_lbl(fb,"Class:",color=T("SUBTEXT")).pack(side="left",padx=(0,4))
        ttk.Combobox(fb,textvariable=cls_var,values=classes,font=FONT_B,
                     state="readonly",width=26).pack(side="left",padx=4)
        mk_lbl(fb,"Term:",color=T("SUBTEXT")).pack(side="left",padx=(8,4))
        ttk.Combobox(fb,textvariable=term_var,values=["Term 1","Term 2","Term 3"],
                     font=FONT_B,state="readonly",width=10).pack(side="left",padx=4)
        mk_lbl(fb,"Year:",color=T("SUBTEXT")).pack(side="left",padx=(8,4))
        tk.Entry(fb,textvariable=year_var,width=6,bg=T("BG"),fg=T("TEXT"),font=FONT_B,
                 insertbackground=T("ACCENT"),relief="flat",highlightthickness=1,
                 highlightbackground=T("BORDER")).pack(side="left",padx=4)
        mk_lbl(fb,"Type:",color=T("SUBTEXT")).pack(side="left",padx=(8,4))
        ttk.Combobox(fb,textvariable=type_var,
                     values=["CATS","End of Term","Mid-Term","Mock","KJSEA"],
                     font=FONT_B,state="readonly",width=13).pack(side="left",padx=4)
        mk_lbl(fb,"Sort By:",color=T("SUBTEXT")).pack(side="left",padx=(8,4))
        ttk.Combobox(fb,textvariable=sort_var,
                     values=["Name (A–Z)","Adm Number"],
                     font=FONT_B,state="readonly",width=14).pack(side="left",padx=4)

        # Legend
        leg = tk.Frame(frm,bg=T("PANEL"),pady=3); leg.pack(fill="x",padx=12,pady=2)
        for lv in get_cbc_levels():
            f=tk.Frame(leg,bg=cbc_color(lv["level"]),padx=5,pady=2); f.pack(side="left",padx=2)
            tk.Label(f,text=f"{lv['level']}: {lv['min']}-{lv['max']}%",
                     bg=cbc_color(lv["level"]),fg="white",font=FONT_S).pack()
        tk.Label(leg,text="  Blank=Absent  Tab/Enter=next  ↑↓←→ Arrow keys navigate cells",
                 bg=T("PANEL"),fg=T("SUBTEXT"),font=FONT_S).pack(side="left",padx=6)

        # Grid canvas
        gc = tk.Frame(frm,bg=T("BG")); gc.pack(fill="both",expand=True,padx=12,pady=4)
        canvas = tk.Canvas(gc,bg=T("CARD"),highlightthickness=0)
        vsb=ttk.Scrollbar(gc,orient="vertical",  command=canvas.yview)
        hsb=ttk.Scrollbar(gc,orient="horizontal",command=canvas.xview)
        canvas.configure(yscrollcommand=vsb.set,xscrollcommand=hsb.set)
        vsb.pack(side="right",fill="y"); hsb.pack(side="bottom",fill="x")
        canvas.pack(side="left",fill="both",expand=True)
        grid_frame=tk.Frame(canvas,bg=T("CARD"))
        gid=canvas.create_window((0,0),window=grid_frame,anchor="nw")
        grid_frame.bind("<Configure>",lambda e:canvas.configure(scrollregion=canvas.bbox("all")))
        canvas.bind("<Configure>",lambda e:canvas.itemconfig(gid,width=e.width))
        _attach_touch_scroll(canvas)
        # propagate touch drag from grid_frame cells to the canvas
        grid_frame.bind("<ButtonPress-1>",
            lambda e: canvas.event_generate("<ButtonPress-1>", x=e.x, y=e.y))
        grid_frame.bind("<B1-Motion>",
            lambda e: canvas.event_generate("<B1-Motion>", x=e.x, y=e.y))

        def _scroll_to_entry(ent):
            """Ensure entry widget is visible by scrolling canvas to it."""
            canvas.update_idletasks()
            sr = canvas.cget("scrollregion")
            if not sr: return
            try:
                parts = [float(x) for x in str(sr).split()]
                total_h = parts[3] - parts[1] if len(parts) >= 4 else 1
            except Exception: return
            ey = ent.winfo_y()
            eh = ent.winfo_height()
            ch = canvas.winfo_height()
            # current view top pixel
            top_frac = canvas.yview()[0]
            top_px   = top_frac * total_h
            bot_px   = top_px + ch
            margin   = eh + 4
            if ey < top_px + margin:
                canvas.yview_moveto(max(0, (ey - margin) / total_h))
            elif ey + eh > bot_px - margin:
                canvas.yview_moveto(min(1, (ey + eh + margin - ch) / total_h))

        marks_vars={}; assessment_cache={}

        bot=tk.Frame(frm,bg=T("PANEL"),pady=6); bot.pack(fill="x",padx=12)
        status_lbl=tk.Label(bot,text="",bg=T("PANEL"),fg=T("GREEN"),font=FONT_B)
        status_lbl.pack(side="left",padx=8)

        def load_grid():
            for w in grid_frame.winfo_children(): w.destroy()
            marks_vars.clear(); assessment_cache.clear()
            cv=cls_var.get()
            if not cv: messagebox.showwarning("Select","Select a class."); return
            cls_id=int(cv.split("|")[0])
            term=term_var.get(); year=year_var.get().strip(); atype=type_var.get()
            _sort_by = sort_var.get()
            _order_sql = "admission_no" if _sort_by == "Adm Number" else "first_name,last_name"
            conn=get_conn()
            learners=conn.execute(f"""SELECT id,admission_no,UPPER(first_name)||' '||UPPER(last_name) AS name
                FROM learners WHERE class_id=? AND status='Active' ORDER BY {_order_sql}""",
                (cls_id,)).fetchall()
            # Grade from class
            cls_row=conn.execute("SELECT grade FROM classes WHERE id=?",(cls_id,)).fetchone()
            grade_str=cls_row["grade"] if cls_row else ""
            subjects=get_section_subjects(grade_str,conn)
            if not learners:
                tk.Label(grid_frame,text="⚠ No active learners.",bg=T("CARD"),
                         fg=T("ORANGE"),font=FONT_H,pady=20).pack(); conn.close(); return
            if not subjects:
                tk.Label(grid_frame,text="⚠ No subjects for this grade.",bg=T("CARD"),
                         fg=T("ORANGE"),font=FONT_H,pady=20).pack(); conn.close(); return
            for subj in subjects:
                ex=conn.execute("SELECT id FROM assessments WHERE class_id=? AND subject_id=? AND term=? AND academic_year=? AND type=?",
                                (cls_id,subj["id"],term,year,atype)).fetchone()
                if ex: aid=ex["id"]
                else:
                    conn.execute("INSERT INTO assessments (name,type,class_id,subject_id,term,academic_year,date,max_marks,status) VALUES (?,?,?,?,?,?,date('now'),?,'Ongoing')",
                                 (f"{atype} {term} {year} — {subj['code']}",atype,cls_id,subj["id"],term,year,subj["max_marks"]))
                    conn.commit(); aid=conn.execute("SELECT last_insert_rowid()").fetchone()[0]
                assessment_cache[(cls_id,subj["id"],term,year)]=aid
            existing={}
            for (_,sid,_,_),aid in assessment_cache.items():
                for r in conn.execute("SELECT * FROM results WHERE assessment_id=?",(aid,)).fetchall():
                    existing[(r["learner_id"],aid)]=r
            for col,(txt,w,is_sub) in enumerate(
                    [("Learner",24,False),("Adm",9,False)] +
                    [(s["code"], 9, bool(s["composite_parent_id"])) for s in subjects]):
                bg_hdr = T("ACCENT2") if is_sub else T("BORDER")
                fg_hdr = T("BG")      if is_sub else m["accent"]
                tk.Label(grid_frame, text=txt, bg=bg_hdr, fg=fg_hdr, font=FONT_H,
                         width=w, anchor="w" if col<2 else "center", padx=4, pady=5
                         ).grid(row=0, column=col, sticky="nsew", padx=1, pady=1)
            all_entries=[]
            entry_grid=[]   # entry_grid[row_idx][col_idx] for arrow navigation
            n_subj=len(subjects)
            for ri,lrn in enumerate(learners):
                bg2=T("CARD") if ri%2==0 else T("BORDER")
                r=ri+1
                tk.Label(grid_frame,text=lrn["name"][:28],bg=bg2,fg=T("TEXT"),
                         font=FONT_B,width=24,anchor="w",padx=4,pady=4
                         ).grid(row=r,column=0,sticky="nsew",padx=1,pady=1)
                tk.Label(grid_frame,text=lrn["admission_no"],bg=bg2,fg=T("SUBTEXT"),
                         font=FONT_S,width=9,anchor="center"
                         ).grid(row=r,column=1,sticky="nsew",padx=1,pady=1)
                row_entries=[]
                for ci,subj in enumerate(subjects):
                    aid=assessment_cache.get((cls_id,subj["id"],term,year))
                    v=tk.StringVar()
                    if aid and (lrn["id"],aid) in existing:
                        ex_r=existing[(lrn["id"],aid)]
                        v.set("" if ex_r["is_absent"] else (str(int(ex_r["marks"])) if ex_r["marks"] is not None and ex_r["marks"]==int(ex_r["marks"]) else str(ex_r["marks"] or "")))
                    ent=tk.Entry(grid_frame,textvariable=v,width=9,bg=T("BG"),fg=T("TEXT"),
                                 font=FONT_B,relief="flat",highlightthickness=1,
                                 highlightbackground=T("BORDER"),justify="center")
                    ent.grid(row=r,column=ci+2,sticky="nsew",padx=1,pady=1)
                    ent.bind("<FocusIn>", lambda ev,e=ent: e.after(10, lambda: _scroll_to_entry(e)))
                    # Real-time validation: highlight red if out of range
                    def _cell_validate(event=None, _v=v, _e=ent, _mx=subj["max_marks"]):
                        s=_v.get().strip()
                        if not s: _e.configure(highlightbackground=T("BORDER")); return
                        try:
                            m=float(s)
                            if m < 0 or m > _mx: _e.configure(highlightbackground=T("RED")); return
                            lv,_,__=get_cbc_level(m,_mx)
                            _e.configure(highlightbackground=cbc_color(lv))
                        except: _e.configure(highlightbackground=T("RED"))
                    v.trace_add("write", lambda *a, fn=_cell_validate: fn())
                    marks_vars[(lrn["id"],subj["id"])]=v
                    all_entries.append(ent)
                    row_entries.append(ent)
                entry_grid.append(row_entries)
            n_rows=len(entry_grid)
            def _focus(ent):
                ent.focus_set(); ent.select_range(0,"end")
                ent.after(10, lambda: _scroll_to_entry(ent))
            for i,e in enumerate(all_entries):
                nxt=all_entries[i+1] if i+1<len(all_entries) else all_entries[0]
                e.bind("<Tab>",   lambda ev,n=nxt: (_focus(n),"break"))
                e.bind("<Return>",lambda ev,n=nxt: (_focus(n),"break"))
            # Arrow key bindings using grid coordinates
            for ri in range(n_rows):
                for ci in range(n_subj):
                    ent=entry_grid[ri][ci]
                    def _up(ev,r=ri,c=ci):
                        nr=(r-1)%n_rows; _focus(entry_grid[nr][c]); return "break"
                    def _down(ev,r=ri,c=ci):
                        nr=(r+1)%n_rows; _focus(entry_grid[nr][c]); return "break"
                    def _left(ev,r=ri,c=ci):
                        if c>0: _focus(entry_grid[r][c-1]); return "break"
                    def _right(ev,r=ri,c=ci):
                        if c<n_subj-1: _focus(entry_grid[r][c+1]); return "break"
                    ent.bind("<Up>",    _up)
                    ent.bind("<Down>",  _down)
                    ent.bind("<Left>",  _left)
                    ent.bind("<Right>", _right)
            conn.close()
            status_lbl.configure(text=f"  Loaded {len(learners)} learners × {len(subjects)} subjects")

        def save_all():
            if not marks_vars: messagebox.showwarning("Load","Load the grid first."); return
            cv=cls_var.get()
            if not cv: return
            cls_id=int(cv.split("|")[0])
            term=term_var.get(); year=year_var.get().strip()
            conn=get_conn(); saved=0; absent=0; skipped=0
            for (lid,sid),v in marks_vars.items():
                aid=assessment_cache.get((cls_id,sid,term,year))
                if not aid: continue
                raw=v.get().strip()
                try:
                    marks=float(raw)
                    max_m=conn.execute("SELECT max_marks FROM subjects WHERE id=?",(sid,)).fetchone()["max_marks"]
                    if marks < 0 or marks > max_m:
                        skipped+=1; continue
                    lv,_,pts=get_cbc_level(marks,max_m)
                    conn.execute("""INSERT INTO results (learner_id,assessment_id,marks,performance_level,points,is_absent)
                        VALUES (?,?,?,?,?,0) ON CONFLICT(learner_id,assessment_id)
                        DO UPDATE SET marks=excluded.marks,performance_level=excluded.performance_level,
                        points=excluded.points,is_absent=0,entry_date=date('now')""",(lid,aid,marks,lv,pts))
                    saved+=1
                except (ValueError,TypeError):
                    conn.execute("""INSERT INTO results (learner_id,assessment_id,marks,performance_level,points,is_absent)
                        VALUES (?,?,NULL,'AB',0,1) ON CONFLICT(learner_id,assessment_id)
                        DO UPDATE SET marks=NULL,performance_level='AB',points=0,is_absent=1,entry_date=date('now')""",(lid,aid))
                    absent+=1
            conn.commit(); conn.close()
            msg=f"  ✅ Saved {saved} marks, {absent} absent"
            if skipped: msg+=f", ⚠ {skipped} skipped (out of 0-100 range)"
            status_lbl.configure(text=msg)

        # ── Download Excel template ────────────────────────────────────
        def download_template():
            if not OPENPYXL_OK:
                messagebox.showerror("Missing Library",
                    "openpyxl is required.\nRun:  pip install openpyxl"); return
            cv = cls_var.get()
            if not cv:
                messagebox.showwarning("Select", "Select a class first."); return
            cls_id  = int(cv.split("|")[0])
            term    = term_var.get()
            year    = year_var.get().strip()
            atype   = type_var.get()
            conn    = get_conn()
            cls_row = conn.execute("SELECT name,grade FROM classes WHERE id=?", (cls_id,)).fetchone()
            grade_str = cls_row["grade"] if cls_row else ""
            cls_name  = cls_row["name"]  if cls_row else ""
            subjects  = get_section_subjects(grade_str, conn)
            _tmpl_sort = sort_var.get()
            _tmpl_order = "admission_no" if _tmpl_sort == "Adm Number" else "first_name,last_name"
            learners  = conn.execute(
                f"SELECT id,admission_no,UPPER(first_name)||' '||UPPER(last_name) AS name "
                f"FROM learners WHERE class_id=? AND status='Active' ORDER BY {_tmpl_order}",
                (cls_id,)).fetchall()
            conn.close()
            if not subjects:
                messagebox.showwarning("No Subjects", "No subjects found for this grade."); return
            if not learners:
                messagebox.showwarning("No Learners", "No active learners in this class."); return

            path = filedialog.asksaveasfilename(
                defaultextension=".xlsx",
                filetypes=[("Excel Workbook","*.xlsx")],
                initialfile=f"marks_template_{cls_name}_{term}_{year}.xlsx".replace(" ","_"))
            if not path: return

            import openpyxl
            from openpyxl.styles import (Font, PatternFill, Alignment,
                                         Border, Side, Protection)
            from openpyxl.utils import get_column_letter

            wb = openpyxl.Workbook()
            ws = wb.active
            ws.title = "Marks Entry"

            # ── Colour palette ────────────────────────────────────────────
            _NAVY  = "0d2844"
            _CYAN  = "06b6d4"
            _AMBER = "f59e0b"
            _SUB   = "0284c7"   # sub-subject column header
            _LGREY = "f0f4f8"
            _DGREY = "e2e8f0"

            thin = Side(style="thin", color="aaaaaa")
            bdr  = Border(left=thin, right=thin, top=thin, bottom=thin)

            def hdr_fill(hex_color):
                return PatternFill("solid", fgColor=hex_color)

            # ── Row 1: document title ─────────────────────────────────────
            ws.merge_cells(start_row=1, start_column=1,
                           end_row=1,   end_column=2 + len(subjects))
            title_cell = ws.cell(row=1, column=1,
                value=f"iQ School Systems — MARKS ENTRY TEMPLATE  |  {cls_name}  |  {term} {year}  |  {atype}  |  Sorted: {_tmpl_sort}")
            title_cell.font      = Font(name="Segoe UI", bold=True, size=13, color="FFFFFF")
            title_cell.fill      = hdr_fill(_NAVY)
            title_cell.alignment = Alignment(horizontal="center", vertical="center")
            ws.row_dimensions[1].height = 28

            # ── Row 2: instructions ───────────────────────────────────────
            ws.merge_cells(start_row=2, start_column=1,
                           end_row=2,   end_column=2 + len(subjects))
            instr = ws.cell(row=2, column=1,
                value=(f"⚠  DO NOT change the ADM NO column or add/remove columns.  "
                       f"Leave mark blank for ABSENT.  Save as .xlsx before importing.  "
                       f"Sorted by: {_tmpl_sort}"))
            instr.font      = Font(name="Segoe UI", italic=True, size=9, color="7c3aed")
            instr.fill      = hdr_fill("ede9fe")
            instr.alignment = Alignment(horizontal="center", vertical="center")
            ws.row_dimensions[2].height = 18

            # ── Row 3: column headers ─────────────────────────────────────
            ws.cell(row=3, column=1, value="ADM NO").font = Font(bold=True, color="FFFFFF")
            ws.cell(row=3, column=1).fill      = hdr_fill(_NAVY)
            ws.cell(row=3, column=1).alignment = Alignment(horizontal="center")
            ws.cell(row=3, column=1).border    = bdr

            ws.cell(row=3, column=2, value="LEARNER NAME").font = Font(bold=True, color="FFFFFF")
            ws.cell(row=3, column=2).fill      = hdr_fill(_NAVY)
            ws.cell(row=3, column=2).alignment = Alignment(horizontal="left")
            ws.cell(row=3, column=2).border    = bdr

            for ci, subj in enumerate(subjects, start=3):
                is_sub = bool(subj["composite_parent_id"])
                label  = f"{subj['code']}\n(max {int(subj['max_marks'])})"
                c      = ws.cell(row=3, column=ci, value=label)
                c.font      = Font(bold=True, color="FFFFFF", size=8)
                c.fill      = hdr_fill(_SUB if is_sub else _CYAN)
                c.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
                c.border    = bdr
                ws.column_dimensions[get_column_letter(ci)].width = 10

            ws.row_dimensions[3].height = 32
            ws.column_dimensions["A"].width = 14
            ws.column_dimensions["B"].width = 30

            # ── Rows 4+: learner rows ─────────────────────────────────────
            for ri, lrn in enumerate(learners):
                row_num = ri + 4
                bg = _LGREY if ri % 2 == 0 else _DGREY

                adm_c = ws.cell(row=row_num, column=1, value=lrn["admission_no"])
                adm_c.font      = Font(bold=True, size=9)
                adm_c.fill      = hdr_fill(bg)
                adm_c.alignment = Alignment(horizontal="center")
                adm_c.border    = bdr
                adm_c.protection = Protection(locked=True)

                nm_c = ws.cell(row=row_num, column=2, value=lrn["name"])
                nm_c.font      = Font(size=9)
                nm_c.fill      = hdr_fill(bg)
                nm_c.alignment = Alignment(horizontal="left")
                nm_c.border    = bdr
                nm_c.protection = Protection(locked=True)

                for ci, subj in enumerate(subjects, start=3):
                    mc = ws.cell(row=row_num, column=ci, value=None)
                    mc.fill      = PatternFill("solid", fgColor="FFFFFF")
                    mc.alignment = Alignment(horizontal="center")
                    mc.border    = bdr
                    # Data validation: 0 – max_marks
                    from openpyxl.worksheet.datavalidation import DataValidation
                    dv = DataValidation(
                        type="decimal", operator="between",
                        formula1="0", formula2=str(subj["max_marks"]),
                        allow_blank=True,
                        showErrorMessage=True,
                        errorTitle="Invalid Mark",
                        error=f"Enter 0–{int(subj['max_marks'])} or leave blank for absent.")
                    ws.add_data_validation(dv)
                    dv.add(mc)
                ws.row_dimensions[row_num].height = 16

            # ── freeze panes, sheet protection ────────────────────────────
            ws.freeze_panes = "C4"   # freeze name + adm columns and header rows

            try:
                wb.save(path)
                messagebox.showinfo("Template Saved",
                    f"Template saved to:\n{path}\n\n"
                    "Fill in the marks columns and use\n'📤 Import from Excel' to load them.")
            except Exception as ex:
                messagebox.showerror("Save Error", str(ex))

        # ── Import marks from Excel ────────────────────────────────────
        def import_from_excel():
            if not OPENPYXL_OK:
                messagebox.showerror("Missing Library",
                    "openpyxl is required.\nRun:  pip install openpyxl"); return
            cv = cls_var.get()
            if not cv:
                messagebox.showwarning("Select", "Select a class first."); return
            cls_id  = int(cv.split("|")[0])
            term    = term_var.get()
            year    = year_var.get().strip()
            atype   = type_var.get()

            path = filedialog.askopenfilename(
                filetypes=[("Excel Workbook","*.xlsx"),("All files","*.*")],
                title="Select filled marks template")
            if not path: return

            try:
                import openpyxl as _opx
                wb  = _opx.load_workbook(path, data_only=True)
                ws  = wb.active
            except Exception as ex:
                messagebox.showerror("Open Error", f"Cannot open file:\n{ex}"); return

            # ── Read header row (row 3) to get subject codes ──────────────
            hdr_row = [ws.cell(row=3, column=c).value for c in range(1, ws.max_column + 1)]
            # hdr_row[0]="ADM NO", hdr_row[1]="LEARNER NAME", hdr_row[2+]="CODE\n(max N)"
            subj_codes = []   # list of (col_index_0based, code_str)
            for ci, h in enumerate(hdr_row):
                if ci < 2 or h is None: continue
                code = str(h).split("\n")[0].strip()
                subj_codes.append((ci, code))

            if not subj_codes:
                messagebox.showerror("Format Error",
                    "Could not read subject columns.\n"
                    "Make sure you are using the template downloaded from iQ School Systems."); return

            conn = get_conn()
            cls_row   = conn.execute("SELECT grade FROM classes WHERE id=?", (cls_id,)).fetchone()
            grade_str = cls_row["grade"] if cls_row else ""
            subjects  = get_section_subjects(grade_str, conn)

            # Map code → subject row
            subj_map = {s["code"].upper(): s for s in subjects}

            # Map admission_no → learner id
            learner_map = {
                r["admission_no"]: r["id"]
                for r in conn.execute(
                    "SELECT id,admission_no FROM learners "
                    "WHERE class_id=? AND status='Active'", (cls_id,)).fetchall()
            }

            # Ensure assessment records exist for all subjects
            local_cache = {}
            for subj in subjects:
                ex = conn.execute(
                    "SELECT id FROM assessments WHERE class_id=? AND subject_id=? "
                    "AND term=? AND academic_year=? AND type=?",
                    (cls_id, subj["id"], term, year, atype)).fetchone()
                if ex:
                    aid = ex["id"]
                else:
                    conn.execute(
                        "INSERT INTO assessments "
                        "(name,type,class_id,subject_id,term,academic_year,date,max_marks,status) "
                        "VALUES (?,?,?,?,?,?,date('now'),?,'Ongoing')",
                        (f"{atype} {term} {year} — {subj['code']}",
                         atype, cls_id, subj["id"], term, year, subj["max_marks"]))
                    conn.commit()
                    aid = conn.execute("SELECT last_insert_rowid()").fetchone()[0]
                local_cache[subj["id"]] = aid
            # Also update the shared assessment_cache so grid stays in sync
            for subj in subjects:
                assessment_cache[(cls_id, subj["id"], term, year)] = local_cache[subj["id"]]

            # ── Process data rows (row 4 onwards) ─────────────────────────
            saved = 0; absent = 0; skipped = 0; unknown_lrn = 0; unknown_subj = 0
            errors = []

            for row_num in range(4, ws.max_row + 1):
                adm_no = ws.cell(row=row_num, column=1).value
                if adm_no is None: continue
                adm_no = str(adm_no).strip()
                if not adm_no: continue

                lid = learner_map.get(adm_no)
                if lid is None:
                    unknown_lrn += 1
                    errors.append(f"Row {row_num}: ADM '{adm_no}' not found in this class")
                    continue

                for ci, code in subj_codes:
                    subj = subj_map.get(code.upper())
                    if subj is None:
                        unknown_subj += 1; continue

                    aid  = local_cache.get(subj["id"])
                    if not aid: continue

                    cell_val = ws.cell(row=row_num, column=ci + 1).value

                    if cell_val is None or str(cell_val).strip() == "":
                        # Blank → absent
                        conn.execute(
                            "INSERT INTO results "
                            "(learner_id,assessment_id,marks,performance_level,points,is_absent) "
                            "VALUES (?,?,NULL,'AB',0,1) "
                            "ON CONFLICT(learner_id,assessment_id) DO UPDATE SET "
                            "marks=NULL,performance_level='AB',points=0,"
                            "is_absent=1,entry_date=date('now')",
                            (lid, aid))
                        absent += 1
                    else:
                        try:
                            marks = float(str(cell_val).strip())
                            if marks < 0 or marks > subj["max_marks"]:
                                skipped += 1
                                errors.append(
                                    f"Row {row_num} / {code}: {marks} out of range "
                                    f"(0–{subj['max_marks']})")
                                continue
                            lv, _, pts = get_cbc_level(marks, subj["max_marks"])
                            conn.execute(
                                "INSERT INTO results "
                                "(learner_id,assessment_id,marks,performance_level,points,is_absent) "
                                "VALUES (?,?,?,?,?,0) "
                                "ON CONFLICT(learner_id,assessment_id) DO UPDATE SET "
                                "marks=excluded.marks,"
                                "performance_level=excluded.performance_level,"
                                "points=excluded.points,is_absent=0,entry_date=date('now')",
                                (lid, aid, marks, lv, pts))
                            saved += 1
                        except (ValueError, TypeError):
                            skipped += 1
                            errors.append(
                                f"Row {row_num} / {code}: invalid value '{cell_val}'")

            conn.commit(); conn.close()

            # ── Summary dialog ────────────────────────────────────────────
            summary = (f"✅  Import complete!\n\n"
                       f"  Marks saved : {saved}\n"
                       f"  Absent      : {absent}\n"
                       f"  Skipped     : {skipped}\n"
                       f"  Unknown ADM : {unknown_lrn}")
            if errors:
                summary += f"\n\nFirst {min(5,len(errors))} issue(s):\n" + \
                           "\n".join(errors[:5])
            messagebox.showinfo("Import Result", summary)
            status_lbl.configure(
                text=f"  ✅ Imported — {saved} marks, {absent} absent, {skipped} skipped")
            # Reload the on-screen grid so it reflects imported values
            load_grid()

        def print_marksheet_quick():
            """Generate a blank printable marksheet PDF directly from the Enter Marks toolbar."""
            if not REPORTLAB_OK:
                messagebox.showerror("Missing Library","reportlab is required for PDF export."); return
            cv = cls_var.get()
            if not cv: messagebox.showwarning("Select","Select a class first."); return
            cls_id = int(cv.split("|")[0]); term = term_var.get(); year = year_var.get().strip()
            conn = get_conn()
            cls  = conn.execute("SELECT * FROM classes WHERE id=?", (cls_id,)).fetchone()
            learners = conn.execute(
                "SELECT id,admission_no,UPPER(first_name)||' '||UPPER(last_name) AS name "
                "FROM learners WHERE class_id=? AND status='Active' ORDER BY first_name,last_name",
                (cls_id,)).fetchall()
            grade_str = cls["grade"] if cls and cls["grade"] else ""
            subjects  = get_section_subjects(grade_str, conn)
            conn.close()
            if not learners: messagebox.showwarning("Empty","No active learners in this class."); return
            if not subjects: messagebox.showwarning("No Subjects","No subjects found for this grade."); return
            path = filedialog.asksaveasfilename(
                defaultextension=".pdf", filetypes=[("PDF","*.pdf")],
                initialfile=f"Marksheet_{cls['name']}_{term}.pdf")
            if not path: return
            # Portrait A4: usable width = 190 mm; autofit columns to content.
            _MS_USABLE  = 190*mm
            from reportlab.pdfbase.pdfmetrics import stringWidth as _sw_ms0
            _ms0_FN = "Helvetica"; _ms0_FB = "Helvetica-Bold"; _ms0_FS = 7; _ms0_PAD = 3
            doc = SimpleDocTemplate(path, pagesize=A4,
                                    topMargin=8*mm, bottomMargin=18*mm,
                                    leftMargin=10*mm, rightMargin=10*mm)
            gen_date = datetime.now().strftime("%d %b %Y  %H:%M")
            def _ms_footer(canvas_obj, doc_obj):
                canvas_obj.saveState()
                canvas_obj.setFont("Helvetica", 7)
                canvas_obj.setFillColor(rl_colors.HexColor("#555555"))
                footer_txt = f"iQ School Systems   |   Generated: {gen_date}   |   Page {doc_obj.page}"
                canvas_obj.drawCentredString(A4[0]/2, 8*mm, footer_txt)
                canvas_obj.restoreState()
            elems = []
            logo = get_logo_image(18, 18)
            hdr  = [[logo or "",
                     Paragraph(f"<b>{school_name().upper()}</b><br/>"
                               f"<b><font size=9 color='white'>EXAMINATION MARKSHEET — {cls['name'].upper()} | {term.upper()} | {year}</font></b>",
                               ParagraphStyle("mh2", fontSize=12, alignment=TA_CENTER, textColor=rl_colors.white, fontName="Helvetica-Bold")), ""]]
            ht = Table(hdr, colWidths=[20*mm, None, 20*mm])
            ht.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),rl_colors.HexColor("#0d1b2a")),
                                    ("TEXTCOLOR",(0,0),(-1,-1),rl_colors.white),
                                    ("VALIGN",(0,0),(-1,-1),"MIDDLE"),
                                    ("TOPPADDING",(0,0),(-1,-1),6),("BOTTOMPADDING",(0,0),(-1,-1),6)]))
            elems.append(ht); elems.append(Spacer(1,3*mm))
            elems.append(Paragraph(
                f"<font size=8>Class Teacher: {cls['teacher'] or '___________'}   "
                f"School: {school_name()}   Prepared by: ___________   Date: ___________</font>",
                ParagraphStyle("si2", fontSize=8, spaceAfter=3)))
            col_hdr = ["#","ADM NO","LEARNER NAME"] + [s["code"]+f"\n(/{int(s['max_marks'])})" for s in subjects]
            data    = [col_hdr]
            for i, lrn in enumerate(learners):
                data.append([str(i+1), lrn["admission_no"], lrn["name"]] + [""]*len(subjects))
            data.append(["","","CLASS AVERAGE"] + [""]*len(subjects))
            def _ms0_col_w(ci, rows):
                mx = 0
                for ri, row in enumerate(rows):
                    cell = str(row[ci]) if ci < len(row) and row[ci] is not None else ""
                    f = _ms0_FB if ri == 0 else _ms0_FN
                    for line in cell.split("\n"):
                        mx = max(mx, _sw_ms0(line, f, _ms0_FS))
                return mx + _ms0_PAD * 2
            _raw_ms0 = [_ms0_col_w(ci, data) for ci in range(len(data[0]))]
            _raw_ms0_total = sum(_raw_ms0)
            if _raw_ms0_total > 0:
                _ms0_scale = _MS_USABLE / max(_raw_ms0_total, _MS_USABLE)
                cw = [max(5*mm, w * _ms0_scale) for w in _raw_ms0]
                cw = [w * (_MS_USABLE / sum(cw)) for w in cw]
            else:
                _ms0_sw = (_MS_USABLE - (10+18+52)*mm) / max(len(subjects), 1)
                cw = [10*mm, 18*mm, 52*mm] + [_ms0_sw]*len(subjects)
            _ms0_min = min(cw[3:]) if len(cw) > 3 else (cw[-1] if cw else 8*mm)
            _ms_fs = 7 if _ms0_min >= 8*mm else (6 if _ms0_min >= 5*mm else 5)
            t  = Table(data, colWidths=cw, repeatRows=1)
            ts = [("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),("FONTSIZE",(0,0),(-1,-1),_ms_fs),
                  ("BACKGROUND",(0,0),(-1,0),rl_colors.HexColor("#0d1b2a")),
                  ("TEXTCOLOR",(0,0),(-1,0),rl_colors.white),
                  ("ALIGN",(0,1),(-1,-1),"CENTER"),("ALIGN",(2,1),(2,-1),"LEFT"),
                  ("GRID",(0,0),(-1,-1),0.3,rl_colors.grey),
                  ("TOPPADDING",(0,0),(-1,-1),2),("BOTTOMPADDING",(0,0),(-1,-1),2),
                  ("FONTNAME",(0,0),(-1,-1),"Helvetica"),
                  ("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),
                  ("BACKGROUND",(0,-1),(-1,-1),rl_colors.HexColor("#e8f4f8")),
                  ("FONTNAME",(0,-1),(-1,-1),"Helvetica-Bold")]
            t.setStyle(TableStyle(ts)); elems.append(t)
            elems.append(Spacer(1,6*mm))
            elems.append(Paragraph(
                f"<font size=8>Signed: __________________ (Class Teacher) &nbsp;&nbsp;&nbsp; "
                f"Signed: __________________ (Head Teacher) &nbsp;&nbsp;&nbsp; Stamp: ________________</font>",
                ParagraphStyle("sig2", fontSize=8, spaceAfter=4)))
            doc.build(elems, onFirstPage=_ms_footer, onLaterPages=_ms_footer)
            messagebox.showinfo("PDF Saved", f"Marksheet saved to:\n{path}")

        mk_btn(fb,"▶ Load Grid",load_grid,m["accent"],T("BG")).pack(side="left",padx=10)
        mk_btn(fb,"📥 Download Template",download_template,T("YELLOW"),T("BG")).pack(side="left",padx=4)
        mk_btn(fb,"📤 Import from Excel",import_from_excel,T("ORANGE"),T("BG")).pack(side="left",padx=4)
        mk_btn(fb,"📄 Print Marksheet",print_marksheet_quick,T("RED"),T("WHITE")).pack(side="left",padx=4)

        # ── Remote Marks Entry Link ──────────────────────────────────────
        def _open_remote_link_dialog():
            import webbrowser as _wb, time as _time

            global _RMT_CLOUD_URL, _RMT_CLOUD_TOKEN

            # ── Load cloud config ────────────────────────────────────────
            _cl_url, _cl_tok = _rmt_load_cloud_cfg()
            if _cl_url: _RMT_CLOUD_URL = _cl_url
            if _cl_tok: _RMT_CLOUD_TOKEN = _cl_tok

            # ── Check standalone server ──────────────────────────────────
            _standalone_data = _rmt_load_standalone_url()
            _standalone_url  = _standalone_data.get("url", "")

            # ── Start in-process server if no cloud/standalone ───────────
            if not _RMT_CLOUD_URL and not _standalone_url:
                try:
                    import flask  # noqa
                except ImportError:
                    messagebox.showerror(
                        "Flask Required",
                        "Remote marks requires Flask.\n\nRun:  pip install flask\nThen restart the app.",
                        parent=frm); return
                _rmt_start_server(_RMT_PORT)
                _time.sleep(0.5)

            sec = self.sec_key
            section_labels = {
                "junior":     "🎓  Junior (Gr 7–9)",
                "upper":      "📘  Upper Primary (Gr 4–6)",
                "lower":      "📗  Lower Primary (Gr 1–3)",
                "preprimary": "🌱  Pre-Primary (PP1–PP2)",
            }

            _state = {"mode": "lan", "ngrok_url": "", "links": {}, "standalone": bool(_standalone_url)}

            def _build_lan_links():
                if _standalone_url:
                    sa_links = _standalone_data.get("links", {})
                    if sa_links:
                        _state["links"] = sa_links; _state["mode"] = "standalone-lan"; return
                _state["links"] = _rmt_generate_links(_RMT_PORT); _state["mode"] = "lan"

            def _build_ngrok_links(pub_url):
                _state["links"] = _rmt_generate_links(_RMT_PORT, base_url=pub_url)
                _state["ngrok_url"] = pub_url; _state["mode"] = "internet"

            def _build_cloud_links(curl, ctok):
                links = {}
                for s in ("junior","upper","lower","preprimary"):
                    links[s] = f"{curl.rstrip('/')}/enter/{s}?token={ctok}&section={s}"
                _state["links"] = links; _state["mode"] = "cloud"

            # Determine initial mode
            if _RMT_CLOUD_URL and _RMT_CLOUD_TOKEN:
                _build_cloud_links(_RMT_CLOUD_URL, _RMT_CLOUD_TOKEN)
