        # ── sub-tab: Marksheet ───────────────────────────────
        mfrm=tk.Frame(rnb,bg=T("BG")); rnb.add(mfrm,text="📝 Marksheet")
        mf=tk.Frame(mfrm,bg=T("CARD"),padx=12,pady=8); mf.pack(fill="x",padx=8,pady=6)
        ms_cls=tk.StringVar(); ms_term=tk.StringVar(value="Term 1")
        ms_year=tk.StringVar(value=str(datetime.now().year))
