class ClassesPage(tk.Frame):
    def __init__(self, parent, app):
        super().__init__(parent, bg=T("BG"))
        self.app = app
        self._build(); self.load()

    def refresh(self): self.load()

    def _build(self):
        top = tk.Frame(self, bg=T("BG"), pady=10); top.pack(fill="x", padx=24)
        sec  = self.app.current_section
        meta = SECTIONS[sec]
        mk_lbl(top, f"{meta['icon']}  Classes — {meta['label']}  ({meta['sub']})",
               20, True).pack(side="left")
        mk_btn(top,"＋ Add Class",self.open_form).pack(side="right",padx=4)

        cols=["ID","Class Name","Grade","School","Teacher","Year","Learners"]
        tbl_f=tk.Frame(self,bg=T("BG")); tbl_f.pack(fill="both",expand=True,padx=24,pady=8)
        self.tbl=StyledTable(tbl_f,cols,col_widths=[40,120,80,180,140,70,80],
                             on_double_click=lambda e: self.show_class_info(),
                             context_menu=[
                                 ("➕ Add Class",   self.open_form),
                                 ("✏ Edit Class",   lambda: self.open_form(edit=True)),
                                 ("ℹ Class Info",   self.show_class_info),
                                 (None, None),
                                 ("🗑 Delete Class", self.delete),
                             ])
        self.tbl.pack(fill="both",expand=True)

        ab=tk.Frame(self,bg=T("BG")); ab.pack(fill="x",padx=24,pady=(0,12))
        mk_btn(ab,"ℹ Info / Edit",self.show_class_info,T("ACCENT")).pack(side="left",padx=4)
        mk_btn(ab,"✏ Edit",lambda: self.open_form(edit=True),T("ORANGE"),T("BG")).pack(side="left",padx=4)
        mk_btn(ab,"🗑 Delete",self.delete,T("RED"),T("WHITE")).pack(side="left",padx=4)
        mk_btn(ab,"🗑 Delete ALL",self.delete_all,"#7f1d1d",T("WHITE")).pack(side="left",padx=4)
        mk_lbl(ab,"  Double-click a class for details",9,color=T("SUBTEXT")).pack(side="left",padx=8)

    def load(self):
        self.tbl.clear()
        sec   = self.app.current_section
        cls_r = section_classes(sec, formatted=False)
        cids  = {c["id"] for c in cls_r}
        conn  = get_conn()
        for r in conn.execute("""
            SELECT c.id,c.name,c.grade,COALESCE(s.name,'—'),
                   COALESCE(c.teacher,'—'),COALESCE(c.academic_year,'—'),
                   COUNT(l.id)
            FROM classes c
            LEFT JOIN schools s ON c.school_id=s.id
            LEFT JOIN learners l ON l.class_id=c.id
            GROUP BY c.id ORDER BY c.grade,c.name""").fetchall():
            if r[0] in cids:
                self.tbl.insert(list(r))
        conn.close()

    def show_class_info(self):
        sel=self.tbl.get_selected()
        if not sel: messagebox.showwarning("Select","Select a class first."); return
        cid=sel[0]
        conn=get_conn()
        cls=conn.execute("SELECT * FROM classes WHERE id=?", (cid,)).fetchone()
        learners=conn.execute("""
            SELECT l.admission_no, UPPER(l.first_name)||' '||UPPER(l.last_name) AS name,
                   l.gender, l.status
            FROM learners l WHERE l.class_id=? ORDER BY l.last_name
        """, (cid,)).fetchall()
        results=conn.execute("""
            SELECT COUNT(r.id) AS cnt, AVG(r.points) AS avg_pts
            FROM results r
            JOIN assessments a ON r.assessment_id=a.id
            WHERE a.class_id=? AND r.is_absent=0
        """, (cid,)).fetchone()
        conn.close()

        win=tk.Toplevel(); win.title(f"Class Info — {cls['name']}")
        win.configure(bg=T("PANEL")); win.geometry("700x520"); win.grab_set()

        hdr=tk.Frame(win,bg=T("ACCENT"),pady=12); hdr.pack(fill="x")
        tk.Label(hdr,text=f"🏫  {cls['name']}  |  {cls['grade']}",
                 bg=T("ACCENT"),fg=T("BG"),font=("Segoe UI",15,"bold")).pack(side="left",padx=16)
        tk.Label(hdr,text=f"Teacher: {cls['teacher'] or '—'}  |  Year: {cls['academic_year'] or '—'}",
                 bg=T("ACCENT"),fg=T("BG"),font=FONT_B).pack(side="right",padx=16)

        # Stats row
        stats=tk.Frame(win,bg=T("CARD"),pady=10); stats.pack(fill="x",padx=16,pady=8)
        for label,val,color in [
            ("Total Learners",len(learners),T("ACCENT")),
            ("Results Entered",results["cnt"] if results else 0,T("GREEN")),
            ("Avg Points",f"{results['avg_pts']:.1f}" if results and results['avg_pts'] else "—",T("ORANGE")),
        ]:
            f=tk.Frame(stats,bg=T("CARD"),padx=20,pady=8,
                       highlightthickness=1,highlightbackground=color)
            f.pack(side="left",expand=True,fill="x",padx=6)
            tk.Label(f,text=str(val),bg=T("CARD"),fg=color,font=("Segoe UI",20,"bold")).pack()
            tk.Label(f,text=label,bg=T("CARD"),fg=T("SUBTEXT"),font=FONT_S).pack()

        # Learners table
        mk_lbl(win,"Learners in this Class",11,True,T("ACCENT")).pack(anchor="w",padx=16,pady=(4,2))
        tf=tk.Frame(win,bg=T("PANEL")); tf.pack(fill="both",expand=True,padx=16,pady=(0,8))
        tbl=StyledTable(tf,["Adm No","Name","Gender","Status"],
                        col_widths=[90,220,80,80],bg=T("PANEL"))
        tbl.pack(fill="both",expand=True)
        for l in learners: tbl.insert(list(l))

        mk_btn(win,"Close",win.destroy,T("BORDER"),T("TEXT")).pack(pady=8)

    def open_form(self, edit=False):
        sel=None
        if edit:
            sel=self.tbl.get_selected()
            if not sel: messagebox.showwarning("Select","Select a class."); return
        win=tk.Toplevel(); win.title("Class"); win.configure(bg=T("PANEL"))
        win.geometry("460x380"); win.resizable(True,True); win.grab_set()
        mk_lbl(win,"Edit Class" if edit else "Add Class",14,True,T("ACCENT")).pack(pady=(16,8))

        frm=tk.Frame(win,bg=T("PANEL"),padx=28); frm.pack(fill="both",expand=True)
        conn=get_conn()
        schools=[f"{r['id']}|{r['name']}" for r in conn.execute("SELECT id,name FROM schools").fetchall()]
        conn.close()

        _sec = self.app.current_section
        if _sec == "junior":
            _grade_opts, _def_grade = ["Grade 7","Grade 8","Grade 9"], "Grade 7"
        elif _sec == "upper":
            _grade_opts, _def_grade = ["Grade 4","Grade 5","Grade 6"], "Grade 4"
        elif _sec == "lower":
            _grade_opts, _def_grade = ["Grade 1","Grade 2","Grade 3"], "Grade 1"
        elif _sec == "preprimary":
            _grade_opts, _def_grade = ["PP1","PP2","Nursery"], "PP1"
        else:
            _grade_opts, _def_grade = ["Grade 1","Grade 2","Grade 3","Grade 4","Grade 5",
                                       "Grade 6","Grade 7","Grade 8","Grade 9"], "Grade 7"

        f_nm=LF(frm,"Class Name *   e.g. Grade 7A",bg=T("PANEL")); f_nm.pack(fill="x",pady=5)
        f_gr=LF(frm,"Grade *","combo",_grade_opts,bg=T("PANEL")); f_gr.pack(fill="x",pady=5)
        if not edit:
            f_gr.set(_def_grade)
        f_sc=LF(frm,"School","combo",schools,bg=T("PANEL")); f_sc.pack(fill="x",pady=5)
        f_tc=LF(frm,"Class Teacher",bg=T("PANEL")); f_tc.pack(fill="x",pady=5)
        f_yr=LF(frm,"Academic Year",bg=T("PANEL")); f_yr.set(str(datetime.now().year))
        f_yr.pack(fill="x",pady=5)

        if edit and sel:
            conn=get_conn()
            row=conn.execute("SELECT * FROM classes WHERE id=?",(sel[0],)).fetchone()
            conn.close()
            if row:
                f_nm.set(row["name"]); f_gr.set(row["grade"] or "")
                f_tc.set(row["teacher"] or ""); f_yr.set(row["academic_year"] or "")
                for s in schools:
                    if s.startswith(str(row["school_id"])+"|"): f_sc.set(s); break

        def save():
            nm=f_nm.get(); gr=f_gr.get()
            if not nm: messagebox.showerror("Required","Class Name required.",parent=win); return
            if not gr: messagebox.showerror("Required","Grade required.",parent=win); return
            sc_v=f_sc.get(); sc_id=int(sc_v.split("|")[0]) if sc_v and "|" in sc_v else None
            conn=get_conn()
            try:
                if edit and sel:
                    conn.execute("UPDATE classes SET name=?,grade=?,school_id=?,teacher=?,academic_year=? WHERE id=?",
                                 (nm,gr,sc_id,f_tc.get(),f_yr.get(),sel[0]))
                else:
                    conn.execute("INSERT INTO classes (name,grade,school_id,teacher,academic_year) VALUES (?,?,?,?,?)",
                                 (nm,gr,sc_id,f_tc.get(),f_yr.get()))
                conn.commit()
                messagebox.showinfo("Saved","Class saved!",parent=win)
                win.destroy(); self.load()
            except Exception as ex:
                conn.rollback()
                messagebox.showerror("Error",str(ex),parent=win)
            finally: conn.close()

        bot=tk.Frame(win,bg=T("PANEL"),pady=10); bot.pack(side="bottom",fill="x",padx=28)
        mk_btn(bot,"💾 Save",save).pack(side="left",padx=4)
        tk.Button(bot,text="✖ Cancel",command=win.destroy,bg=T("BORDER"),fg=T("TEXT"),
                  font=FONT_H,relief="flat",padx=12,pady=6).pack(side="left",padx=4)

    def delete(self):
        sel=self.tbl.get_selected()
        if not sel: messagebox.showwarning("Select","Select a class."); return
        if not messagebox.askyesno("Confirm",
                f"Delete class '{sel[1]}'?\n\nThis will also delete all assessments and results for this class."): return
        conn=get_conn()
        try:
            asms = [r[0] for r in conn.execute(
                "SELECT id FROM assessments WHERE class_id=?", (sel[0],)).fetchall()]
            for aid in asms:
                conn.execute("DELETE FROM results WHERE assessment_id=?", (aid,))
            conn.execute("DELETE FROM assessments WHERE class_id=?", (sel[0],))
            conn.execute("UPDATE learners SET class_id=NULL WHERE class_id=?", (sel[0],))
            conn.execute("DELETE FROM classes WHERE id=?", (sel[0],))
            conn.commit()
            messagebox.showinfo("Deleted", f"Class '{sel[1]}' deleted.")
        except Exception as ex:
            conn.rollback()
            messagebox.showerror("Error", str(ex))
        finally:
            conn.close()
        self.load()

    def delete_all(self):
        """Delete ALL classes in the current section after double confirmation."""
        sec   = self.app.current_section
        meta  = SECTIONS[sec]
        cls_r = section_classes(sec, formatted=False)
        if not cls_r:
            messagebox.showinfo("Empty", "No classes found in this section."); return
        cids = [c["id"] for c in cls_r]
        if not messagebox.askyesno("⚠ Delete ALL Classes",
                f"Permanently delete ALL {len(cids)} class(es) in\n"
                f"{meta['label']} ({meta['sub']})?\n\n"
                "All learners, assessments and results for these classes will also be deleted. "
                "This CANNOT be undone.", icon="warning"):
            return
        # Second confirmation
        cwin = tk.Toplevel(); cwin.title("⚠ Confirm Delete All Classes")
        cwin.configure(bg=T("PANEL")); cwin.geometry("420x200"); cwin.grab_set(); cwin.resizable(False, False)
        tk.Label(cwin, text="⚠ FINAL WARNING", bg=T("PANEL"), fg=T("RED"),
                 font=("Segoe UI", 13, "bold")).pack(pady=(14, 4))
        tk.Label(cwin, text=f"Type DELETE to confirm removing all {len(cids)} class(es):",
                 bg=T("PANEL"), fg=T("TEXT"), font=FONT_B).pack()
        cv = tk.StringVar()
        tk.Entry(cwin, textvariable=cv, font=FONT_H, bg=T("CARD"), fg=T("RED"),
                 justify="center", insertbackground=T("RED"), relief="flat",
                 highlightthickness=1, highlightbackground=T("RED"), width=20).pack(pady=8)
        def _confirm():
            if cv.get().strip().upper() != "DELETE":
                messagebox.showerror("Wrong", "Type DELETE (capitals) to confirm.", parent=cwin); return
            cwin.destroy()
            conn = get_conn()
            try:
                for cid in cids:
                    asms = [r[0] for r in conn.execute(
                        "SELECT id FROM assessments WHERE class_id=?", (cid,)).fetchall()]
                    for aid in asms:
                        conn.execute("DELETE FROM results WHERE assessment_id=?", (aid,))
                    conn.execute("DELETE FROM assessments WHERE class_id=?", (cid,))
                    conn.execute("UPDATE learners SET class_id=NULL WHERE class_id=?", (cid,))
                    conn.execute("DELETE FROM classes WHERE id=?", (cid,))
                conn.commit()
                messagebox.showinfo("Deleted", f"✅ All {len(cids)} class(es) in {meta['label']} deleted.")
            except Exception as ex:
                conn.rollback()
                messagebox.showerror("Error", str(ex))
            finally:
                conn.close()
            self.load()
        bot = tk.Frame(cwin, bg=T("PANEL"), pady=6); bot.pack()
        mk_btn(bot, "🗑 Confirm DELETE ALL", _confirm, "#7f1d1d", T("WHITE")).pack(side="left", padx=4)
        tk.Button(bot, text="✖ Cancel", command=cwin.destroy, bg=T("BORDER"), fg=T("TEXT"),
                  font=FONT_H, relief="flat", padx=10, pady=5).pack(side="left", padx=4)


# ─────────────────────────────────────────────────────────────
# LEARNERS PAGE
# ─────────────────────────────────────────────────────────────
class LearnersPage(tk.Frame):
    def __init__(self, parent, app):
        super().__init__(parent, bg=T("BG"))
        self.app = app
        self._build(); self.load()

    def refresh(self): self.load()

    def _build(self):
        top=tk.Frame(self,bg=T("BG"),pady=10); top.pack(fill="x",padx=24)
        sec  = self.app.current_section
        meta = SECTIONS[sec]
        mk_lbl(top, f"🎒  Learners — {meta['label']}  ({meta['sub']})", 20, True).pack(side="left")
        mk_btn(top,"＋ Add Learner",self.open_form).pack(side="right",padx=4)
        mk_btn(top,"⬇ Export CSV",self.export_csv,T("BORDER"),T("TEXT")).pack(side="right",padx=4)
        mk_btn(top,"📥 Import Excel",self.import_excel,"#16a34a",T("WHITE")).pack(side="right",padx=4)
        mk_btn(top,"📋 Template",self.download_template,T("BORDER"),T("TEXT")).pack(side="right",padx=4)

        sf=tk.Frame(self,bg=T("BG")); sf.pack(fill="x",padx=24,pady=4)
        self.search_var=tk.StringVar()
        tk.Entry(sf,textvariable=self.search_var,font=FONT_B,bg=T("CARD"),fg=T("TEXT"),
                 insertbackground=T("ACCENT"),relief="flat",
                 highlightthickness=1,highlightbackground=T("BORDER"),width=36).pack(side="left")
        mk_btn(sf,"🔍",self.load,width=3).pack(side="left",padx=4)
        mk_btn(sf,"↺",lambda:[self.search_var.set(""),self.load()],T("BORDER"),T("TEXT"),width=3).pack(side="left")

        # Warning bar for learners with no class (hidden until needed)
        self._unassigned_bar = tk.Label(
            self, text="", bg="#2d1b00", fg="#f97316",
            font=("Segoe UI", 9, "bold"), anchor="w", padx=10, pady=5)

        cols=["ID","Adm No","First Name","Last Name","Assessment No","Gender","Class","Status"]
        tbl_f=tk.Frame(self,bg=T("BG")); tbl_f.pack(fill="both",expand=True,padx=24,pady=6)
        self.tbl=StyledTable(tbl_f,cols,col_widths=[40,80,120,120,100,70,110,80],
                             on_double_click=lambda e: self.open_form(edit=True),
                             context_menu=[
                                 ("➕ Add Learner",     self.open_form),
                                 ("✏ Edit Learner",    lambda: self.open_form(edit=True)),
                                 ("📋 Report Card",    self.view_report),
                                 (None, None),
                                 ("🗑 Delete",          self.delete),
                                 ("🗑 Delete Selected", self.delete_selected),
                             ])
        self.tbl.pack(fill="both",expand=True)

        ab=tk.Frame(self,bg=T("BG")); ab.pack(fill="x",padx=24,pady=(0,10))
        mk_btn(ab,"✏ Edit",lambda: self.open_form(edit=True),T("ORANGE"),T("BG")).pack(side="left",padx=4)
        mk_btn(ab,"🗑 Delete",self.delete,T("RED"),T("WHITE")).pack(side="left",padx=4)
        mk_btn(ab,"🗑 Delete Selected",self.delete_selected,"#dc2626",T("WHITE")).pack(side="left",padx=4)
        mk_btn(ab,"🗑 Delete ALL",self.delete_all,"#7f1d1d",T("WHITE")).pack(side="left",padx=4)
        mk_btn(ab,"📋 Report Card",self.view_report,"#a855f7",T("WHITE")).pack(side="left",padx=4)
        tk.Label(ab,text="  Ctrl+click or Shift+click to multi-select",
                 bg=T("BG"),fg=T("SUBTEXT"),font=("Segoe UI",8)).pack(side="left",padx=6)

    def load(self):
        self.tbl.clear()
        q    = self.search_var.get().strip(); like = f"%{q}%"
        sec  = self.app.current_section
        cids = [c["id"] for c in section_classes(sec, formatted=False)]
        conn = get_conn()

        search_filter = ("(l.admission_no LIKE ? OR l.first_name LIKE ?"
                         " OR l.last_name LIKE ? OR l.nemis_no LIKE ?)")
        base_select = (
            "SELECT l.id, l.admission_no, UPPER(l.first_name), UPPER(l.last_name),"
            " COALESCE(l.nemis_no,'--'), COALESCE(l.gender,'--'),"
            " COALESCE(c.name,'(No Class)'), l.status,"
            " CASE WHEN l.class_id IS NULL THEN 1 ELSE 0 END AS unassigned"
            " FROM learners l LEFT JOIN classes c ON l.class_id=c.id "
        )

        if cids:
            ph   = ",".join("?" * len(cids))
            rows = conn.execute(
                base_select +
                f"WHERE (l.class_id IN ({ph}) OR l.class_id IS NULL)"
                f" AND {search_filter}"
                f" ORDER BY unassigned DESC, l.last_name, l.first_name",
                cids + [like, like, like, like]
            ).fetchall()
        else:
            rows = conn.execute(
                base_select +
                f"WHERE {search_filter}"
                f" ORDER BY l.last_name, l.first_name",
                (like, like, like, like)
            ).fetchall()

        n_unassigned = 0
        for r in rows:
            vals = list(r[:8])
            tag  = "warn" if r["unassigned"] else ""
            self.tbl.insert(vals, tag=tag)
            if r["unassigned"]: n_unassigned += 1

        conn.close()

        if n_unassigned:
            self._unassigned_bar.configure(
                text=f"  ⚠  {n_unassigned} learner(s) have no class — select one and use  ✏ Edit  to assign a class.",
                bg="#2d1b00", fg="#f97316")
            self._unassigned_bar.pack(fill="x", padx=24, pady=(0,4))
        else:
            self._unassigned_bar.pack_forget()

    def _get_classes(self):
        return section_classes(self.app.current_section)

    def open_form(self, edit=False):
        sel = None
        if edit:
            sel = self.tbl.get_selected()
            if not sel: messagebox.showwarning("Select","Select a learner."); return

        win = tk.Toplevel()
        win.title("Edit Learner" if edit else "Add Learner")
        win.configure(bg=T("PANEL"))
        win.geometry("580x640"); win.resizable(True, True); win.grab_set()

        # ── Title ──
        mk_lbl(win, "Edit Learner" if edit else "Add Learner", 14, True, T("ACCENT")).pack(pady=(12,4))

        # ── Scrollable body ──
        canvas = tk.Canvas(win, bg=T("PANEL"), highlightthickness=0)
        vsb = ttk.Scrollbar(win, orient="vertical", command=canvas.yview)
        canvas.configure(yscrollcommand=vsb.set)
        vsb.pack(side="right", fill="y")
        canvas.pack(side="top", fill="both", expand=True)
        frm = tk.Frame(canvas, bg=T("PANEL"), padx=24)
        fid = canvas.create_window((0,0), window=frm, anchor="nw")
        frm.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
        canvas.bind("<Configure>", lambda e: canvas.itemconfig(fid, width=e.width))
        _attach_touch_scroll(canvas)
        frm.bind("<ButtonPress-1>",
            lambda e: canvas.event_generate("<ButtonPress-1>", x=e.x, y=e.y))
        frm.bind("<B1-Motion>",
            lambda e: canvas.event_generate("<B1-Motion>", x=e.x, y=e.y))

        classes = self._get_classes()
        fields = {}

        # ── PHOTO SECTION ──────────────────────────────────────────
        photo_outer = tk.Frame(frm, bg=T("CARD"), pady=10, padx=12)
        photo_outer.pack(fill="x", pady=(4,8))
        mk_lbl(photo_outer, "📷  Learner Photo  (PNG / JPG only)", 9, True, T("ACCENT")).pack(anchor="w")

        photo_row = tk.Frame(photo_outer, bg=T("CARD")); photo_row.pack(fill="x", pady=6)

        # Photo preview box
        photo_box = tk.Frame(photo_row, bg=T("BORDER"), width=90, height=110,
                             highlightthickness=2, highlightbackground=T("ACCENT"))
        photo_box.pack(side="left", padx=(0,16)); photo_box.pack_propagate(False)
        self._photo_lbl = tk.Label(photo_box, text="No Photo", bg=T("BORDER"),
                                   fg=T("SUBTEXT"), font=FONT_S)
        self._photo_lbl.pack(expand=True)
        self._photo_path_var = None   # will hold the path string

        # Buttons beside photo
        btn_col = tk.Frame(photo_row, bg=T("CARD")); btn_col.pack(side="left", fill="y", pady=4)
        mk_lbl(btn_col, "Upload a passport-size photo.", 9, color=T("SUBTEXT")).pack(anchor="w")
        mk_lbl(btn_col, "Accepted: PNG, JPG, JPEG only.", 9, color=T("SUBTEXT")).pack(anchor="w")

        def _pick_photo():
            path = filedialog.askopenfilename(
                title="Select Learner Photo",
                filetypes=[("Image files","*.png *.jpg *.jpeg"),
                           ("PNG","*.png"),("JPG","*.jpg *.jpeg")])
            if not path: return
            ext = os.path.splitext(path)[1].lower()
            if ext not in (".png",".jpg",".jpeg"):
                messagebox.showerror("Wrong Format","Only PNG and JPG files are accepted.",parent=win)
                return
            self._photo_path_var = path
            # Show preview
            if PIL_OK:
                try:
                    img = PILImage.open(path).resize((90,110), PILImage.LANCZOS)
                    self._tk_photo_prev = ImageTk.PhotoImage(img)
                    self._photo_lbl.configure(image=self._tk_photo_prev, text="")
                except Exception as ex:
                    self._photo_lbl.configure(text="📷 Set", image="")
                    messagebox.showwarning("Preview","Could not preview image, but it will be saved.",parent=win)
            else:
                self._photo_lbl.configure(text="📷 Set (no preview)", image="")

        def _clear_photo():
            self._photo_path_var = "__CLEAR__"
            self._photo_lbl.configure(image="", text="No Photo")

        mk_btn(btn_col, "📂 Upload Photo", _pick_photo, T("ACCENT"), T("BG")).pack(anchor="w", pady=(8,4))
        mk_btn(btn_col, "✖ Remove Photo", _clear_photo, T("BORDER"), T("TEXT")).pack(anchor="w")

        # ── FIELDS ────────────────────────────────────────────────
        defs = [
            ("adm",   "Admission Number *",        "entry",  None, False),
            ("fn",    "First Name *",              "entry",  None, True),
            ("ln",    "Last Name *",               "entry",  None, True),
            ("nemis", "Assessment Number",              "entry",  None, False),
            ("gen",   "Gender",                    "combo",  ["MALE","FEMALE"], False),
            ("cls",   "Class",                     "combo",  classes, False),
            ("st",    "Status",                    "combo",
             ["Active","Inactive","Transferred","Graduated"], False),
        ]
        for key, label, wtype, vals, caps in defs:
            f = LF(frm, label, wtype=wtype, values=vals, caps=caps, bg=T("PANEL"))
            f.pack(fill="x", pady=3)
            fields[key] = f

        # ── Populate for edit ──────────────────────────────────────
        existing_photo = None
        if edit and sel:
            conn = get_conn()
            row = conn.execute("SELECT * FROM learners WHERE id=?", (sel[0],)).fetchone()
            conn.close()
            if row:
                fields["adm"].set(row["admission_no"])
                fields["fn"].set(row["first_name"]); fields["ln"].set(row["last_name"])
                fields["nemis"].set(row["nemis_no"] or "")
                fields["gen"].set(row["gender"] or ""); fields["st"].set(row["status"] or "Active")
                if row["class_id"]:
                    for c in classes:
                        if c.startswith(str(row["class_id"])+"|"): fields["cls"].set(c); break
                # Show existing photo
                existing_photo = row["photo_path"] if "photo_path" in row.keys() else None
                if existing_photo and os.path.exists(str(existing_photo)):
                    self._photo_path_var = existing_photo
                    if PIL_OK:
                        try:
                            img = PILImage.open(existing_photo).resize((90,110), PILImage.LANCZOS)
                            self._tk_photo_prev = ImageTk.PhotoImage(img)
                            self._photo_lbl.configure(image=self._tk_photo_prev, text="")
                        except Exception: pass
        def save():
            adm = fields["adm"].get(); fn = fields["fn"].get().upper(); ln = fields["ln"].get().upper()
            if not adm or not fn or not ln:
                messagebox.showerror("Required","Adm No, First Name and Last Name are required.",parent=win)
                return
            cls_v = fields["cls"].get()
            cls_id = int(cls_v.split("|")[0]) if cls_v and "|" in cls_v else None
            nemis = fields["nemis"].get() or None

            # Handle photo
            final_photo = existing_photo  # default: keep old
            if self._photo_path_var == "__CLEAR__":
                final_photo = None
            elif self._photo_path_var and self._photo_path_var != existing_photo:
                ext = os.path.splitext(self._photo_path_var)[1].lower()
                dest = os.path.join(PHOTOS_DIR, f"{adm}{ext}")
                try:
                    import shutil
                    shutil.copy2(self._photo_path_var, dest)
                    final_photo = dest
                except Exception as ex:
                    messagebox.showwarning("Photo Warning",
                        f"Could not copy photo: {ex}\nLearner will be saved without photo.",parent=win)
                    final_photo = None

            conn = get_conn()
            try:
                if edit and sel:
                    conn.execute("""UPDATE learners SET admission_no=?,first_name=?,last_name=?,
                        nemis_no=?,gender=?,class_id=?,
                        status=?,photo_path=? WHERE id=?""",
                        (adm,fn,ln,nemis,fields["gen"].get(),
                         cls_id,fields["st"].get(),final_photo,sel[0]))
                else:
                    conn.execute("""INSERT INTO learners
                        (admission_no,first_name,last_name,nemis_no,gender,
                         class_id,status,photo_path)
                        VALUES (?,?,?,?,?,?,?,?)""",
                        (adm,fn,ln,nemis,fields["gen"].get(),
                         cls_id,fields["st"].get() or "Active",final_photo))
                conn.commit()
                messagebox.showinfo("Saved","Learner saved successfully!",parent=win)
                win.destroy(); self.load()
            except sqlite3.IntegrityError as ex:
                conn.rollback()
                messagebox.showerror("Duplicate",str(ex),parent=win)
            finally:
                conn.close()

        # ── Bottom buttons ─────────────────────────────────────────
        bot = tk.Frame(win, bg=T("PANEL"), pady=8)
        bot.pack(side="bottom", fill="x", padx=24)
        mk_btn(bot,"💾 Save Learner", save).pack(side="left", padx=4)
        tk.Button(bot,text="✖ Cancel",command=win.destroy,bg=T("BORDER"),fg=T("TEXT"),
                  font=FONT_H,relief="flat",padx=10,pady=5).pack(side="left",padx=4)

    def delete(self):
        sel=self.tbl.get_selected()
        if not sel: messagebox.showwarning("Select","Select a learner."); return
        try:
            learner_id = int(sel[0])
        except (ValueError, TypeError, IndexError):
            messagebox.showerror("Error", "Could not determine learner ID. Please re-select and try again.")
            return
        name = f"{sel[2]} {sel[3]}" if len(sel) > 3 else str(sel[1])
        if messagebox.askyesno("Confirm", f"Delete learner '{name}'?\n\nThis will also remove all their results."):
            conn=get_conn()
            try:
                conn.execute("DELETE FROM results WHERE learner_id=?", (learner_id,))
                conn.execute("DELETE FROM learners WHERE id=?", (learner_id,))
                conn.commit()
                messagebox.showinfo("Deleted", f"Learner '{name}' deleted.")
            except Exception as ex:
                conn.rollback()
                messagebox.showerror("Error", str(ex))
            finally:
                conn.close()
            self.load()

    def delete_selected(self):
        """Delete all currently selected learners (multi-select)."""
        rows = self.tbl.get_all_selected()
        if not rows:
            messagebox.showwarning("Select", "Select one or more learners first.\n\n"
                                             "Tip: Use Ctrl+click or Shift+click to select multiple.")
            return
        names = "\n".join(f"  • {r[2]} {r[3]}" if len(r) > 3 else f"  • {r[1]}" for r in rows[:10])
        if len(rows) > 10:
            names += f"\n  … and {len(rows)-10} more"
        if not messagebox.askyesno("Confirm Delete",
                f"Delete {len(rows)} learner(s)?\n\n{names}\n\n"
                "This will also remove ALL their results. This cannot be undone.",
                icon="warning"):
            return
        conn = get_conn()
        deleted = 0
        try:
            for r in rows:
                try:
                    lid = int(r[0])
                except (ValueError, TypeError):
                    continue
                conn.execute("DELETE FROM results WHERE learner_id=?", (lid,))
                conn.execute("DELETE FROM learners WHERE id=?", (lid,))
                deleted += 1
            conn.commit()
            messagebox.showinfo("Deleted", f"✅ {deleted} learner(s) deleted successfully.")
        except Exception as ex:
            conn.rollback()
            messagebox.showerror("Error", str(ex))
        finally:
            conn.close()
        self.load()

    def delete_all(self):
        """Delete ALL learners in the current section after double confirmation."""
        sec  = self.app.current_section
        meta = SECTIONS[sec]
        cids = [c["id"] for c in section_classes(sec, formatted=False)]
        if not cids:
            messagebox.showinfo("Empty", "No classes found for this section.")
            return
        conn = get_conn()
        ph = ",".join("?"*len(cids))
        count = conn.execute(
            f"SELECT COUNT(*) FROM learners WHERE class_id IN ({ph})", cids).fetchone()[0]
        conn.close()
        if count == 0:
            messagebox.showinfo("Empty", "No learners found in this section.")
            return
        # First confirmation
        if not messagebox.askyesno("⚠ Delete ALL Learners",
                f"You are about to permanently delete ALL {count} learner(s) "
                f"in {meta['label']} ({meta['sub']}).\n\n"
                "This will also delete ALL their results.\n\n"
                "Are you sure you want to continue?",
                icon="warning"):
            return
        # Second confirmation — type section name
        confirm_win = tk.Toplevel()
        confirm_win.title("⚠ Confirm Delete All")
        confirm_win.configure(bg=T("PANEL"))
        confirm_win.geometry("420x200")
        confirm_win.grab_set()
        confirm_win.resizable(False, False)
        tk.Label(confirm_win,
                 text="⚠ FINAL WARNING",
                 bg=T("PANEL"), fg=T("RED"),
                 font=("Segoe UI", 13, "bold")).pack(pady=(16,4))
        tk.Label(confirm_win,
                 text=f"Type DELETE to confirm removing all {count} learner(s):",
                 bg=T("PANEL"), fg=T("TEXT"),
                 font=FONT_B).pack()
        conf_var = tk.StringVar()
        tk.Entry(confirm_win, textvariable=conf_var, font=FONT_H,
                 bg=T("CARD"), fg=T("RED"), justify="center",
                 insertbackground=T("RED"), relief="flat",
                 highlightthickness=1, highlightbackground=T("RED"),
                 width=20).pack(pady=8)

        def _do_delete_all():
            if conf_var.get().strip().upper() != "DELETE":
                messagebox.showerror("Wrong", "You must type DELETE (in capitals) to confirm.",
                                     parent=confirm_win)
                return
            confirm_win.destroy()
            conn2 = get_conn()
            try:
                lids = [r[0] for r in conn2.execute(
                    f"SELECT id FROM learners WHERE class_id IN ({ph})", cids).fetchall()]
                for lid in lids:
                    conn2.execute("DELETE FROM results WHERE learner_id=?", (lid,))
                conn2.execute(f"DELETE FROM learners WHERE class_id IN ({ph})", cids)
                conn2.commit()
                messagebox.showinfo("Deleted",
                    f"✅ All {len(lids)} learner(s) deleted from {meta['label']}.")
            except Exception as ex:
                conn2.rollback()
                messagebox.showerror("Error", str(ex))
            finally:
                conn2.close()
            self.load()

        bot = tk.Frame(confirm_win, bg=T("PANEL"), pady=6); bot.pack()
        mk_btn(bot, "🗑 Confirm DELETE ALL", _do_delete_all, "#7f1d1d", T("WHITE")).pack(side="left", padx=4)
        tk.Button(bot, text="✖ Cancel", command=confirm_win.destroy,
                  bg=T("BORDER"), fg=T("TEXT"), font=FONT_H,
                  relief="flat", padx=10, pady=5).pack(side="left", padx=4)

    def view_report(self):
        sel=self.tbl.get_selected()
        if not sel: messagebox.showwarning("Select","Select a learner."); return
        ReportCardWindow(self.app,sel[0],f"{sel[2]} {sel[3]}")

    def export_csv(self):
        path=filedialog.asksaveasfilename(defaultextension=".csv",filetypes=[("CSV","*.csv")])
        if not path: return
        conn=get_conn()
        rows=conn.execute("""SELECT l.*,c.name AS cls FROM learners l
            LEFT JOIN classes c ON l.class_id=c.id""").fetchall()
        conn.close()
        with open(path,"w",newline="") as f:
            w=csv.writer(f)
            w.writerow(["ID","AdmNo","FirstName","LastName","OtherName","Gender",
                        "Assessment No","Class","ParentName","ParentPhone","Status","EnrollDate"])
            for r in rows:
                w.writerow([r["id"],r["admission_no"],r["first_name"].upper(),r["last_name"].upper(),
                            r["other_name"],r["gender"],r["nemis_no"],r["cls"],
                            r["parent_name"],r["parent_phone"],r["status"],r["enroll_date"]])
        messagebox.showinfo("Exported",f"Exported to:\n{path}")

    def download_template(self):
        """Save a ready-to-fill Excel template with correct headers and an example row."""
        if not OPENPYXL_OK:
            messagebox.showerror("Missing Library",
                "openpyxl is required.\n\nInstall it:\n    pip install openpyxl\n\nThen restart.")
            return

        # Fetch real class names to show in the template
        conn = get_conn()
        cls_names = [r["name"] for r in conn.execute("SELECT name FROM classes ORDER BY grade, name").fetchall()]
        conn.close()
        cls_example = cls_names[0] if cls_names else "Grade 7A"

        path = filedialog.asksaveasfilename(
            title="Save Learner Import Template",
            defaultextension=".xlsx",
            initialfile="learners_import_template.xlsx",
            filetypes=[("Excel Files","*.xlsx"),("All Files","*.*")])
        if not path: return

        try:
            wb = openpyxl.Workbook()
            ws = wb.active
            ws.title = "Learners"

            # ── Header row with styling ────────────────────────
            from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
            hdr_fill   = PatternFill("solid", fgColor="0D2844")
            hdr_font   = Font(bold=True, color="FFFFFF", size=11)
            thin_side  = Side(style="thin", color="AAAAAA")
            thin_bdr   = Border(left=thin_side, right=thin_side, top=thin_side, bottom=thin_side)
            center_aln = Alignment(horizontal="center", vertical="center")

            headers = ["AdmNo", "FirstName", "LastName", "Assessment No", "Gender", "Class", "Status"]
            col_widths = [14, 18, 18, 18, 10, 16, 12]

            for ci, (h, w) in enumerate(zip(headers, col_widths), start=1):
                cell = ws.cell(row=1, column=ci, value=h)
                cell.font   = hdr_font
                cell.fill   = hdr_fill
                cell.border = thin_bdr
                cell.alignment = center_aln
                ws.column_dimensions[cell.column_letter].width = w

            # ── Example data row ───────────────────────────────
            example = ["ADM001", "John", "Kamau", "NEM123456", "MALE", cls_example, "Active"]
            for ci, val in enumerate(example, start=1):
                cell = ws.cell(row=2, column=ci, value=val)
                cell.font   = Font(size=10, italic=True, color="555555")
                cell.border = thin_bdr
                cell.alignment = center_aln

            # ── Instructions sheet ─────────────────────────────
            ws2 = wb.create_sheet("Instructions")
            instructions = [
                ("Column",       "Required?", "Notes"),
                ("AdmNo",        "Yes",       "Unique admission number"),
                ("FirstName",    "Yes",       "Learner's first name"),
                ("LastName",     "Yes",       "Learner's surname"),
                ("Assessment No",        "No",        "Assessment registration number"),
                ("Gender",       "No",        "MALE or FEMALE"),
                ("Class",        "No",        "Must exactly match a class name in the system"),
                ("Status",       "No",        "Active / Inactive / Transferred / Graduated  (default: Active)"),
            ]
            for ri, row_data in enumerate(instructions, start=1):
                for ci, val in enumerate(row_data, start=1):
                    cell = ws2.cell(row=ri, column=ci, value=val)
                    if ri == 1:
                        cell.font = Font(bold=True, color="FFFFFF", size=11)
                        cell.fill = PatternFill("solid", fgColor="0D2844")
                    cell.border = thin_bdr
                    cell.alignment = Alignment(vertical="center", wrap_text=True)
            ws2.column_dimensions["A"].width = 14
            ws2.column_dimensions["B"].width = 12
            ws2.column_dimensions["C"].width = 50

            # ── Class names reference sheet ────────────────────
            ws3 = wb.create_sheet("Class Names (Reference)")
            ws3.cell(row=1, column=1, value="Available Class Names").font = Font(bold=True)
            ws3.cell(row=1, column=2, value="(copy these exactly into the Class column)").font = Font(italic=True, color="777777")
            for ri, nm in enumerate(cls_names, start=2):
                ws3.cell(row=ri, column=1, value=nm)
            ws3.column_dimensions["A"].width = 20
            ws3.column_dimensions["B"].width = 45

            wb.save(path)
            messagebox.showinfo("Template Saved",
                f"Template saved to:\n{path}\n\n"
                "Fill in the 'Learners' sheet and use  📥 Import Excel  to load it.\n"
                "See the 'Instructions' tab for help.")
        except Exception as ex:
            messagebox.showerror("Error", f"Could not save template:\n{ex}")

    def import_excel(self):
        """Bulk-import learners from an Excel file (.xlsx) with preview before committing."""
        if not OPENPYXL_OK:
            messagebox.showerror("Missing Library",
                "openpyxl is required for Excel import.\n\n"
                "Install it by running:\n    pip install openpyxl\n\n"
                "Then restart the application.")
            return

        path = filedialog.askopenfilename(
            title="Select Excel File",
            filetypes=[("Excel Files","*.xlsx *.xlsm"),("All Files","*.*")])
        if not path: return

        try:
            wb = openpyxl.load_workbook(path, read_only=True, data_only=True)
            ws = wb.active
        except Exception as ex:
            messagebox.showerror("Read Error", f"Could not open file:\n{ex}"); return

        # ── Read header row ────────────────────────────────────
        rows = list(ws.iter_rows(values_only=True))
        if not rows:
            messagebox.showwarning("Empty", "The Excel file appears to be empty."); return

        headers = [str(h).strip().lower() if h else "" for h in rows[0]]

        def _col(names):
            for n in names:
                if n in headers: return headers.index(n)
            return None

        ci_adm    = _col(["admno","adm no","admission_no","admission no","adm"])
        ci_fn     = _col(["firstname","first_name","first name","fname"])
        ci_ln     = _col(["lastname","last_name","last name","lname","surname"])
        ci_nemis  = _col(["nemis","nemis_no","nemis no"])
        ci_gender = _col(["gender","sex"])
        ci_class  = _col(["class","class name","classname"])
        ci_status = _col(["status"])

        if ci_adm is None or ci_fn is None or ci_ln is None:
            missing = []
            if ci_adm is None: missing.append("AdmNo")
            if ci_fn  is None: missing.append("FirstName")
            if ci_ln  is None: missing.append("LastName")
            messagebox.showerror("Missing Columns",
                f"Required column(s) not found: {', '.join(missing)}\n\n"
                "Row 1 of your sheet must include:\n"
                "  AdmNo  |  FirstName  |  LastName\n\n"
                f"Your headers detected:\n  {', '.join(h for h in headers if h)}\n\n"
                "Tip: click  📋 Template  to download a ready-to-fill file.")
            return

        # ── Build class name → id lookup ───────────────────────
        conn = get_conn()
        cls_rows = conn.execute("SELECT id, name FROM classes ORDER BY grade, name").fetchall()
        conn.close()
        cls_lookup  = {r["name"].strip().lower(): r["id"] for r in cls_rows}
        cls_display = {r["name"].strip().lower(): r["name"] for r in cls_rows}

        # ── Parse rows into preview list ───────────────────────
        preview = []   # list of dicts per valid row
        skipped_blank = 0

        for rn, row in enumerate(rows[1:], start=2):
            def _v(idx):
                if idx is None or idx >= len(row): return ""
                return str(row[idx]).strip() if row[idx] is not None else ""

            adm    = _v(ci_adm)
            fn     = _v(ci_fn)
            ln     = _v(ci_ln)
            nemis  = _v(ci_nemis) or None
            gender = _v(ci_gender).upper() if ci_gender is not None else ""
            cls_nm = _v(ci_class).lower() if ci_class is not None else ""
            status = _v(ci_status) or "Active"

            if not adm or not fn or not ln:
                skipped_blank += 1; continue

            cls_id      = cls_lookup.get(cls_nm)
            cls_matched = cls_display.get(cls_nm, "")
            cls_warn    = bool(cls_nm and cls_id is None)   # name given but not found

            if gender not in ("MALE","FEMALE"): gender = ""

            preview.append({
                "row": rn, "adm": adm,
                "fn": fn.upper(), "ln": ln.upper(),
                "nemis": nemis or "", "gender": gender,
                "cls_raw": _v(ci_class) if ci_class is not None else "",
                "cls_id": cls_id, "cls_matched": cls_matched,
                "cls_warn": cls_warn, "status": status,
            })

        if not preview:
            messagebox.showinfo("Nothing to Import",
                f"No valid rows found ({skipped_blank} blank/incomplete row(s) skipped).\n\n"
                "Make sure AdmNo, FirstName and LastName are filled in for each row.")
            return

        # ── Show preview dialog ────────────────────────────────
        self._show_import_preview(preview, skipped_blank, cls_lookup, cls_display)

    def _show_import_preview(self, preview, skipped_blank, cls_lookup, cls_display):
        """Show a preview dialog; user confirms before data is written."""
        warn_rows  = [p for p in preview if p["cls_warn"]]
        n_warn     = len(warn_rows)
        n_ok       = len(preview)

        win = tk.Toplevel()
        win.title("Import Preview — Review Before Importing")
        win.configure(bg=T("PANEL"))
        win.geometry("900x580"); win.resizable(True, True); win.grab_set()

        # ── Header banner ──────────────────────────────────────
        banner = tk.Frame(win, bg="#0d2844", pady=10); banner.pack(fill="x")
        tk.Label(banner, text="📥  Excel Import Preview", bg="#0d2844", fg="#06b6d4",
                 font=("Segoe UI", 14, "bold")).pack(side="left", padx=18)
        stat_txt = (f"  {n_ok} learner(s) ready"
                    + (f"   ·   ⚠ {n_warn} unmatched class(es)" if n_warn else "")
                    + (f"   ·   {skipped_blank} blank row(s) skipped" if skipped_blank else ""))
        tk.Label(banner, text=stat_txt, bg="#0d2844",
                 fg="#f97316" if n_warn else "#22c55e",
                 font=("Segoe UI", 10)).pack(side="left", padx=4)

        # ── Warning panel for unmatched classes ────────────────
        if n_warn:
            wf = tk.Frame(win, bg="#2d1b00", pady=6); wf.pack(fill="x")
            bad_cls = sorted({p["cls_raw"] for p in warn_rows})
            avail   = sorted(cls_display.values())
            tk.Label(wf,
                text=f"⚠  Unmatched class name(s): {', '.join(bad_cls)}\n"
                     f"   These learners will be imported WITHOUT a class assignment.\n"
                     f"   Available classes: {', '.join(avail) if avail else '(none)'}",
                bg="#2d1b00", fg="#f97316",
                font=("Segoe UI", 9), justify="left", anchor="w", padx=14).pack(anchor="w")

        # ── Preview table ──────────────────────────────────────
        cols = ("Row","AdmNo","First Name","Last Name","Assessment No","Gender","Class","Status")
        widths = [45, 80, 115, 115, 100, 70, 130, 90]

        tbl_f = tk.Frame(win, bg=T("PANEL")); tbl_f.pack(fill="both", expand=True, padx=14, pady=8)
        style = ttk.Style(); style.theme_use("clam")
        style.configure("Prev.Treeview",
            background=T("CARD"), foreground=T("TEXT"), rowheight=26,
            fieldbackground=T("CARD"), font=FONT_B)
        style.configure("Prev.Treeview.Heading",
            background=T("BORDER"), foreground=T("ACCENT"), font=FONT_H, relief="flat")
        style.map("Prev.Treeview",
            background=[("selected", T("ACCENT"))],
            foreground=[("selected", T("BG"))])

        tree = ttk.Treeview(tbl_f, columns=cols, show="headings", style="Prev.Treeview")
        vsb  = ttk.Scrollbar(tbl_f, orient="vertical",   command=tree.yview)
        hsb  = ttk.Scrollbar(tbl_f, orient="horizontal", command=tree.xview)
        tree.configure(yscrollcommand=vsb.set, xscrollcommand=hsb.set)
        tree.grid(row=0, column=0, sticky="nsew")
        vsb.grid(row=0, column=1, sticky="ns")
        hsb.grid(row=1, column=0, sticky="ew")
        tbl_f.columnconfigure(0, weight=1); tbl_f.rowconfigure(0, weight=1)

        for col, w in zip(cols, widths):
            tree.heading(col, text=col)
            tree.column(col, width=w, minwidth=40, anchor="w")

        tree.tag_configure("warn",  foreground="#f97316")
        tree.tag_configure("ok",    foreground=T("TEXT"))

        for p in preview:
            cls_cell = p["cls_matched"] if p["cls_matched"] else (
                f"⚠ {p['cls_raw']}" if p["cls_raw"] else "(none)")
            tag = "warn" if p["cls_warn"] else "ok"
            tree.insert("", "end", tags=(tag,), values=(
                p["row"], p["adm"], p["fn"], p["ln"],
                p["nemis"], p["gender"], cls_cell, p["status"]))

        # ── Footer buttons ─────────────────────────────────────
        bot = tk.Frame(win, bg=T("PANEL"), pady=10); bot.pack(side="bottom", fill="x", padx=18)

        def _do_import():
            conn = get_conn()
            inserted = skipped_dup = errors = 0
            error_msgs = []
            try:
                for p in preview:
                    try:
                        conn.execute(
                            "INSERT OR IGNORE INTO learners "
                            "(admission_no,first_name,last_name,nemis_no,gender,class_id,status) "
                            "VALUES (?,?,?,?,?,?,?)",
                            (p["adm"], p["fn"], p["ln"],
                             p["nemis"] or None,
                             p["gender"] or None,
                             p["cls_id"], p["status"]))
                        changed = conn.execute("SELECT changes()").fetchone()[0]
                        if changed:
                            inserted += 1
                        else:
                            skipped_dup += 1
                    except Exception as ex:
                        errors += 1
                        error_msgs.append(f"Row {p['row']}: {ex}")
                conn.commit()
            except Exception as ex:
                conn.rollback()
                messagebox.showerror("Import Error", str(ex))
                return
            finally:
                conn.close()
            win.destroy()
            summary = (f"✅  Imported:  {inserted} learner(s)\n"
                       f"⏭  Skipped (already exists):  {skipped_dup}\n"
                       f"❌  Errors:  {errors}")
            if error_msgs:
                summary += "\n\nErrors:\n" + "\n".join(error_msgs[:8])
            messagebox.showinfo("Import Complete", summary)
            self.load()

        mk_btn(bot, f"✅ Import {n_ok} Learner(s)", _do_import, "#16a34a", T("WHITE")).pack(side="left", padx=4)
        tk.Button(bot, text="✖ Cancel", command=win.destroy,
                  bg=T("BORDER"), fg=T("TEXT"), font=FONT_H,
                  relief="flat", padx=12, pady=6).pack(side="left", padx=4)
        if n_warn:
            tk.Label(bot,
                text=f"⚠  {n_warn} learner(s) will be imported without a class  —  you can assign them later.",
                bg=T("PANEL"), fg="#f97316", font=("Segoe UI", 9)).pack(side="left", padx=12)


# ─────────────────────────────────────────────────────────────
# SUBJECTS PAGE  —  redirects users to manage subjects
#                   inside each section panel on the Dashboard
# ─────────────────────────────────────────────────────────────
class SubjectsPage(tk.Frame):
    """
    The standalone Subjects page now directs users to manage subjects
    per section (Junior / Upper Primary / Lower Primary) from the
    Dashboard section panels, where Add / Edit / Delete are available
    scoped to each category's sort-order range.
    """
    def __init__(self, parent, app):
        super().__init__(parent, bg=T("BG"))
        self.app = app
        self._build()

    def _build(self):
        top = tk.Frame(self, bg=T("BG"), pady=16); top.pack(fill="x", padx=24)
        mk_lbl(top, "📚  CBC Subjects", 20, True).pack(side="left")

        card = tk.Frame(self, bg=T("CARD"), padx=28, pady=28,
                        highlightthickness=1, highlightbackground=T("BORDER"))
        card.pack(padx=40, pady=20, fill="x")

        mk_lbl(card, "Subjects are now managed per section.", 14, True, T("ACCENT")).pack(anchor="w", pady=(0,10))
        mk_lbl(card,
               "Each school section (Junior / Upper Primary / Lower Primary) has its own\n"
               "subject list. Open a section panel on the Dashboard and click the\n"
               "📚 Subjects tab to Add, Edit or Delete subjects for that section.",
               10, color=T("TEXT")).pack(anchor="w", pady=(0,18))

        btn_row = tk.Frame(card, bg=T("CARD")); btn_row.pack(anchor="w")
        for sec_key, meta in SECTIONS.items():
            mk_btn(
                btn_row,
                f"{meta['icon']}  {meta['label']}",
                lambda k=sec_key: self.app.set_section(k, "Dashboard"),
                meta["accent"], T("BG")
            ).pack(side="left", padx=6, pady=4)

    def refresh(self):
        pass


# ─────────────────────────────────────────────────────────────
# ASSESSMENTS PAGE
# ─────────────────────────────────────────────────────────────
class AssessmentsPage(tk.Frame):
    def __init__(self, parent, app):
        super().__init__(parent, bg=T("BG"))
        self.app=app; self._build(); self.load()

    def refresh(self): self.load()

    def _build(self):
        top=tk.Frame(self,bg=T("BG"),pady=10); top.pack(fill="x",padx=24)
        sec  = self.app.current_section
        meta = SECTIONS[sec]
        mk_lbl(top, f"📝  Assessments — {meta['label']}  ({meta['sub']})", 20, True).pack(side="left")
        mk_btn(top,"＋ New",self.open_form).pack(side="right",padx=4)

        cols=["ID","Name","Type","Class","Subject/Learning Area","Term","Year","Max Marks","Status"]
        tbl_f=tk.Frame(self,bg=T("BG")); tbl_f.pack(fill="both",expand=True,padx=24,pady=10)
        self.tbl=StyledTable(tbl_f,cols,col_widths=[40,180,80,110,140,60,60,80,90],
                             context_menu=[
                                 ("➕ New Assessment", self.open_form),
                                 ("✏ Edit",            lambda: self.open_form(edit=True)),
                                 ("✏ Enter Results",   self.enter_results),
                                 (None, None),
                                 ("🗑 Delete",          self.delete),
                             ])
        self.tbl.pack(fill="both",expand=True)

        ab=tk.Frame(self,bg=T("BG")); ab.pack(fill="x",padx=24,pady=(0,12))
        mk_btn(ab,"✏ Edit",lambda: self.open_form(edit=True),T("ORANGE"),T("BG")).pack(side="left",padx=4)
        mk_btn(ab,"✏ Enter Results",self.enter_results,T("GREEN"),T("BG")).pack(side="left",padx=4)
        mk_btn(ab,"🗑 Delete",self.delete,T("RED"),T("WHITE")).pack(side="left",padx=4)

    def load(self):
        self.tbl.clear()
        sec   = self.app.current_section
        cids  = [c["id"] for c in section_classes(sec, formatted=False)]
        conn  = get_conn()
        if cids:
            ph = ",".join("?" * len(cids))
            rows = conn.execute(f"""
                SELECT a.id,a.name,a.type,COALESCE(c.name,'—'),COALESCE(s.name,'—'),
                       COALESCE(a.term,'—'),COALESCE(a.academic_year,'—'),a.max_marks,a.status
                FROM assessments a
                LEFT JOIN classes c ON a.class_id=c.id
                LEFT JOIN subjects s ON a.subject_id=s.id
                WHERE a.class_id IN ({ph})
                ORDER BY a.id DESC""", cids).fetchall()
        else:
            rows = []
        for r in rows:
            self.tbl.insert(list(r))
        conn.close()

    def _get_classes(self):
        return section_classes(self.app.current_section)

    def _get_subjects(self):
        conn=get_conn()
        res=[f"{r['id']}|{r['code']} - {r['name']}" for r in conn.execute("SELECT id,code,name FROM subjects WHERE is_active=1").fetchall()]
        conn.close(); return res

    def open_form(self, edit=False):
        sel=None
        if edit:
            sel=self.tbl.get_selected()
            if not sel: messagebox.showwarning("Select","Select an assessment."); return
        win=tk.Toplevel(); win.title("Assessment"); win.configure(bg=T("PANEL"))
        win.geometry("500x580"); win.grab_set()
        mk_lbl(win,"Assessment",14,True,T("ACCENT")).pack(pady=(16,8))

        # ── Scrollable form body ────────────────────────────────
        sf = ScrollFrame(win, bg=T("PANEL")); sf.pack(fill="both", expand=True, padx=4)
        frm = sf.inner; frm.configure(padx=24)

        classes  = self._get_classes()
        subjects = self._get_subjects()

        f_nm = LF(frm,"Name *",bg=T("PANEL"));                                               f_nm.pack(fill="x",pady=4)
        f_tp = LF(frm,"Type","combo",["CATS","End of Term","Mid-Term","KJSEA","KCPE","Mock","Assignment"],bg=T("PANEL")); f_tp.pack(fill="x",pady=4)
        f_cl = LF(frm,"Class","combo",classes,bg=T("PANEL"));                                f_cl.pack(fill="x",pady=4)
        f_tr = LF(frm,"Term","combo",["Term 1","Term 2","Term 3"],bg=T("PANEL"));            f_tr.pack(fill="x",pady=4)
        f_yr = LF(frm,"Academic Year",bg=T("PANEL")); f_yr.set(str(datetime.now().year));    f_yr.pack(fill="x",pady=4)
        f_dt = LF(frm,"Date (YYYY-MM-DD)",bg=T("PANEL"));                                    f_dt.pack(fill="x",pady=4)
        f_mx = LF(frm,"Max Marks",bg=T("PANEL")); f_mx.set("100");                           f_mx.pack(fill="x",pady=4)
        f_st = LF(frm,"Status","combo",["Scheduled","Ongoing","Completed","Cancelled"],bg=T("PANEL")); f_st.pack(fill="x",pady=4)

        # ── Subject multi-select with Select All ────────────────
        sb_frame = tk.LabelFrame(frm, text=" Subjects * ", bg=T("PANEL"),
                                 fg=T("ACCENT"), font=("Segoe UI", 9, "bold"),
                                 relief="groove", bd=1)
        sb_frame.pack(fill="x", pady=6)

        # Header row: Select All checkbox
        hdr_row = tk.Frame(sb_frame, bg=T("PANEL")); hdr_row.pack(fill="x", padx=8, pady=(4,2))
        all_var = tk.BooleanVar(value=False)
        sb_vars = {}   # subject_id -> BooleanVar

        def _toggle_all():
            v = all_var.get()
            for bv in sb_vars.values(): bv.set(v)

        tk.Checkbutton(hdr_row, text="Select All", variable=all_var,
                       command=_toggle_all,
                       bg=T("PANEL"), fg=T("ACCENT"),
                       selectcolor=T("BG"),
                       font=("Segoe UI", 9, "bold"),
                       activebackground=T("PANEL"),
                       relief="flat", cursor="hand2").pack(side="left")

        def _sync_all_var(*_):
            """Keep 'Select All' ticked only when every subject is ticked."""
            all_var.set(all(bv.get() for bv in sb_vars.values()) if sb_vars else False)

        # Scrollable checklist
        cb_outer = tk.Frame(sb_frame, bg=T("PANEL")); cb_outer.pack(fill="x", padx=8, pady=(0,6))
        cb_canvas = tk.Canvas(cb_outer, bg=T("PANEL"), highlightthickness=0, height=140)
        cb_vsb    = ttk.Scrollbar(cb_outer, orient="vertical", command=cb_canvas.yview)
        cb_inner  = tk.Frame(cb_canvas, bg=T("PANEL"))
        cb_inner.bind("<Configure>", lambda e: cb_canvas.configure(scrollregion=cb_canvas.bbox("all")))
        _cbwin = cb_canvas.create_window((0,0), window=cb_inner, anchor="nw")
        cb_canvas.configure(yscrollcommand=cb_vsb.set)
        cb_canvas.bind("<Configure>", lambda e: cb_canvas.itemconfig(_cbwin, width=e.width))
        _attach_touch_scroll(cb_canvas)
        cb_inner.bind("<ButtonPress-1>",
            lambda e: cb_canvas.event_generate("<ButtonPress-1>", x=e.x, y=e.y))
        cb_inner.bind("<B1-Motion>",
            lambda e: cb_canvas.event_generate("<B1-Motion>", x=e.x, y=e.y))
        cb_vsb.pack(side="right", fill="y"); cb_canvas.pack(side="left", fill="both", expand=True)

        for s in subjects:
            sid = int(s.split("|")[0])
            bv  = tk.BooleanVar(value=False)
            sb_vars[sid] = bv
            bv.trace_add("write", _sync_all_var)
            tk.Checkbutton(cb_inner, text=s.split("|")[1] if "|" in s else s,
                           variable=bv,
                           bg=T("PANEL"), fg=T("TEXT"),
                           selectcolor=T("BG"),
                           font=("Segoe UI", 9),
                           activebackground=T("PANEL"),
                           relief="flat", anchor="w"
                           ).pack(fill="x", padx=4, pady=1)

        # ── Pre-fill when editing ───────────────────────────────
        if edit and sel:
            conn=get_conn()
            row=conn.execute("SELECT * FROM assessments WHERE id=?",(sel[0],)).fetchone()
            conn.close()
            if row:
                f_nm.set(row["name"]); f_tp.set(row["type"] or "CATS")
                f_tr.set(row["term"] or ""); f_yr.set(row["academic_year"] or "")
                f_dt.set(row["date"] or ""); f_mx.set(str(row["max_marks"] or 100))
                f_st.set(row["status"] or "Scheduled")
                for c in classes:
                    if c.startswith(str(row["class_id"])+"|"): f_cl.set(c); break
                # Tick the saved subject
                if row["subject_id"] and row["subject_id"] in sb_vars:
                    sb_vars[row["subject_id"]].set(True)

        # ── Save ────────────────────────────────────────────────
        def save():
            nm = f_nm.get()
            selected_sids = [sid for sid, bv in sb_vars.items() if bv.get()]
            if not nm:
                messagebox.showerror("Required","Assessment name is required.",parent=win); return
            if not selected_sids:
                messagebox.showerror("Required","Select at least one subject.",parent=win); return
            cl_v  = f_cl.get()
            cl_id = int(cl_v.split("|")[0]) if cl_v and "|" in cl_v else None
            try: mx = float(f_mx.get() or 100)
            except: mx = 100
            conn = get_conn()
            if edit and sel:
                # Edit mode — update only the first selected subject (keep original behaviour)
                sb_id = selected_sids[0]
                conn.execute("""UPDATE assessments SET name=?,type=?,class_id=?,subject_id=?,
                    term=?,academic_year=?,date=?,max_marks=?,status=? WHERE id=?""",
                    (nm,f_tp.get(),cl_id,sb_id,f_tr.get(),f_yr.get(),f_dt.get(),mx,f_st.get(),sel[0]))
            else:
                # Insert one assessment per selected subject
                for sb_id in selected_sids:
                    conn.execute("""INSERT INTO assessments
                        (name,type,class_id,subject_id,term,academic_year,date,max_marks,status)
                        VALUES (?,?,?,?,?,?,?,?,?)""",
                        (nm,f_tp.get() or "CATS",cl_id,sb_id,
                         f_tr.get(),f_yr.get(),f_dt.get(),mx,f_st.get() or "Scheduled"))
            conn.commit(); conn.close()
            n = len(selected_sids)
            messagebox.showinfo("Saved",
                f"{'Assessment' if n==1 else str(n)+' assessments'} saved!",parent=win)
            win.destroy(); self.load()

        bot=tk.Frame(win,bg=T("PANEL"),pady=10); bot.pack(side="bottom",fill="x",padx=28)
        mk_btn(bot,"💾 Save",save).pack(side="left",padx=4)
        # Ctrl+S shortcut inside the form window
        win.bind("<Control-s>", lambda e: save())
        win.bind("<Control-S>", lambda e: save())
        tk.Button(bot,text="✖ Cancel",command=win.destroy,bg=T("BORDER"),fg=T("TEXT"),
                  font=FONT_H,relief="flat",padx=12,pady=6).pack(side="left",padx=4)

    def enter_results(self):
        sel=self.tbl.get_selected()
        if not sel: messagebox.showwarning("Select","Select an assessment."); return
        ResultEntryWindow(self,sel[0],sel[1])

    def delete(self):
        sel=self.tbl.get_selected()
        if not sel: messagebox.showwarning("Select","Select an assessment."); return
        if messagebox.askyesno("Confirm",f"Delete '{sel[1]}'?\n\nThis will also delete all results recorded for this assessment."):
            conn=get_conn()
            try:
                conn.execute("DELETE FROM results WHERE assessment_id=?",(sel[0],))
                conn.execute("DELETE FROM assessments WHERE id=?",(sel[0],))
                conn.commit()
                messagebox.showinfo("Deleted","Assessment and its results have been deleted.")
            except Exception as ex:
                conn.rollback()
                messagebox.showerror("Error", str(ex))
            finally:
                conn.close()
            self.load()


# ─────────────────────────────────────────────────────────────
# RESULT ENTRY WINDOW (per assessment) — full-screen, scrollable
# ─────────────────────────────────────────────────────────────
class ResultEntryWindow(tk.Toplevel):
    def __init__(self, parent, assessment_id, assessment_name):
        super().__init__(parent)
        self.assessment_id   = assessment_id
        self.assessment_name = assessment_name
        self.title(f"✏️  Enter Marks — {assessment_name}")
        self.configure(bg=T("BG"))
        self.resizable(True, True)
        self.grab_set()

        # Maximise on every platform
        try:
            self.state("zoomed")
        except Exception:
            try:
                self.attributes("-zoomed", True)
            except Exception:
                self.geometry("1400x860")

        conn = get_conn()
        asm = conn.execute(
            "SELECT * FROM assessments WHERE id=?", (assessment_id,)).fetchone()
        self.max_marks = float(asm["max_marks"]) if asm else 100
        self.class_id  = asm["class_id"]  if asm else None
        conn.close()

        self._canvas  = None
        self.row_data = []
        self._build()
        self._load()

        # ── Keyboard shortcuts ────────────────────────────────────
        # Use self.bind() NOT bind_all — bind_all operates on the Tk root
        # and gets wiped by canvas.unbind_all() calls inside scroll helpers.
        # Per-Entry bindings in _load() cover the case when an Entry has focus.
        def _cs(e):
            self._save_all(silent=True)
            return "break"
        self.bind("<Control-s>", _cs)
        self.bind("<Control-S>", _cs)
        self.bind("<Escape>",    lambda e: self._on_close())

    # ── Layout ──────────────────────────────────────────────────
    def _build(self):
        # Top accent bar
        top = tk.Frame(self, bg=T("ACCENT"))
        top.pack(fill="x")
        tk.Label(top,
                 text=f"📝  {self.assessment_name}   |   Max marks: {int(self.max_marks)}",
                 bg=T("ACCENT"), fg=T("BG"),
                 font=("Segoe UI", 14, "bold")
                 ).pack(side="left", padx=16, pady=10)
        tk.Button(top, text="✖  Close", command=self._on_close,
                  bg=T("BG"), fg=T("ACCENT"),
                  font=("Segoe UI", 10, "bold"),
                  relief="flat", cursor="hand2", padx=12, pady=6
                  ).pack(side="right", padx=12, pady=8)

        # CBC legend + hint strip
        leg_bar = tk.Frame(self, bg=T("PANEL"))
        leg_bar.pack(fill="x")
        tk.Label(leg_bar,
                 text="  Leave blank = Absent  |  Tab / Enter / ↓ = next  |  ↑ = previous  |  Ctrl+S = save  |  Red border = out of range",
                 bg=T("PANEL"), fg=T("SUBTEXT"), font=("Segoe UI", 9)
                 ).pack(side="left", padx=12, pady=4)
        for lv in get_cbc_levels():
            clr = cbc_color(lv["level"])
            b = tk.Frame(leg_bar, bg=clr, padx=6, pady=2)
            b.pack(side="left", padx=2, pady=3)
            tk.Label(b, text=f"{lv['level']} {lv['min']}–{lv['max']}%",
                     bg=clr, fg="white", font=("Segoe UI", 8, "bold")).pack()

        # Sticky column-header row
        hdr = tk.Frame(self, bg="#0d2844")
        hdr.pack(fill="x")
        _COL_CFGS = [
            ("#",                           0, 50,  "center"),
            ("Adm No",                      0, 100, "w"),
            ("Learner Name",                2, 220, "w"),
            ("Marks",                       0, 100, "center"),
            ("CBC Level  &  Performance",   3, 300, "w"),
            ("Pts",                         0, 60,  "center"),
            ("Teacher Comment (optional)",  4, 260, "w"),
        ]
        self._col_cfgs = _COL_CFGS
        for ci, (lbl, wt, mn, anc) in enumerate(_COL_CFGS):
            hdr.columnconfigure(ci, weight=wt, minsize=mn)
        for ci, (lbl, wt, mn, anc) in enumerate(_COL_CFGS):
            tk.Label(hdr, text=lbl,
                     bg="#0d2844", fg="#22d3ee",
                     font=("Segoe UI", 10, "bold"),
                     anchor=anc, padx=8, pady=8
                     ).grid(row=0, column=ci, sticky="nsew", padx=1)

        # Scrollable body
        outer = tk.Frame(self, bg=T("BG"))
        outer.pack(fill="both", expand=True)

        self._canvas = tk.Canvas(outer, bg=T("CARD"), highlightthickness=0)
        vsb = ttk.Scrollbar(outer, orient="vertical", command=self._canvas.yview)
        self._canvas.configure(yscrollcommand=vsb.set)
        vsb.pack(side="right", fill="y")
        self._canvas.pack(side="left", fill="both", expand=True)

        self.body = tk.Frame(self._canvas, bg=T("CARD"))
        self._win_id = self._canvas.create_window((0, 0), window=self.body, anchor="nw")
        self.body.bind("<Configure>",
            lambda e: self._canvas.configure(scrollregion=self._canvas.bbox("all")))
        self._canvas.bind("<Configure>",
            lambda e: self._canvas.itemconfig(self._win_id, width=e.width))
        # Mouse-wheel + touch drag — single helper handles everything
        _attach_touch_scroll(self._canvas)
        self.body.bind("<ButtonPress-1>",
            lambda e: self._canvas.event_generate("<ButtonPress-1>", x=e.x, y=e.y))
        self.body.bind("<B1-Motion>",
            lambda e: self._canvas.event_generate("<B1-Motion>", x=e.x, y=e.y))

        # Bottom action bar (always visible, docked to bottom)
        bot = tk.Frame(self, bg=T("PANEL"), pady=8)
        bot.pack(fill="x", side="bottom")
        self.status = tk.Label(bot, text="", bg=T("PANEL"),
                                fg=T("GREEN"), font=("Segoe UI", 11, "bold"))
        self.status.pack(side="left", padx=16)
        mk_btn(bot, "💾  Save All Marks", self._save_all,
               T("GREEN"), T("BG")).pack(side="right", padx=12)
        mk_btn(bot, "↺  Reload", self._load,
               T("BORDER"), T("TEXT")).pack(side="right", padx=4)

    # ── Clean close ─────────────────────────────────────────────
    def _on_close(self):
        self.destroy()

    # ── Scroll canvas to keep a widget visible ─────────────────
    def _scroll_to(self, widget):
        self._canvas.update_idletasks()
        sr = self._canvas.cget("scrollregion")
        if not sr:
            return
        try:
            parts     = [float(x) for x in str(sr).split()]
            total_h   = parts[3] - parts[1] if len(parts) >= 4 else 1
        except Exception:
            return
        if total_h <= 0:
            return
        wy   = widget.winfo_y()
        wh   = widget.winfo_height()
        ch   = self._canvas.winfo_height()
        # Centre entry in viewport
        frac = max(0.0, min(1.0, (wy - ch // 2 + wh // 2) / total_h))
        self._canvas.yview_moveto(frac)

    # ── Build / rebuild learner rows ───────────────────────────
    def _load(self):
        for w in self.body.winfo_children():
            w.destroy()
        self.row_data = []
        all_entries   = []

        conn = get_conn()
        if self.class_id:
            learners = conn.execute(
                "SELECT id, admission_no, UPPER(first_name)||' '||UPPER(last_name) AS name "
                "FROM learners WHERE class_id=? AND status='Active' "
                "ORDER BY first_name, last_name",
                (self.class_id,)).fetchall()
        else:
            learners = conn.execute(
                "SELECT id, admission_no, UPPER(first_name)||' '||UPPER(last_name) AS name "
                "FROM learners WHERE status='Active' "
                "ORDER BY first_name, last_name").fetchall()

        if not learners:
            tk.Label(self.body,
                     text="⚠  No active learners in this class.\nAdd learners and assign them to this class first.",
                     bg=T("CARD"), fg=T("ORANGE"),
                     font=("Segoe UI", 12), pady=60, justify="center").pack()
            conn.close()
            self.status.configure(text="No learners found.")
            return

        # Propagate column weights into the body grid
        for ci, (_, wt, mn, _) in enumerate(self._col_cfgs):
            self.body.columnconfigure(ci, weight=wt, minsize=mn)

        for i, lrn in enumerate(learners):
            res = conn.execute(
                "SELECT * FROM results WHERE learner_id=? AND assessment_id=?",
                (lrn["id"], self.assessment_id)).fetchone()

            row_bg_color = T("CARD") if i % 2 == 0 else T("BORDER")

            # Row number
            tk.Label(self.body, text=str(i + 1),
                     bg=row_bg_color, fg=T("SUBTEXT"),
                     font=("Segoe UI", 10), anchor="center", padx=4, pady=7
                     ).grid(row=i, column=0, sticky="nsew", padx=1, pady=1)

            # Adm No
            tk.Label(self.body, text=lrn["admission_no"],
                     bg=row_bg_color, fg=T("SUBTEXT"),
                     font=("Segoe UI", 10), anchor="w", padx=8
                     ).grid(row=i, column=1, sticky="nsew", padx=1, pady=1)

            # Name
            tk.Label(self.body, text=lrn["name"],
                     bg=row_bg_color, fg=T("TEXT"),
                     font=("Segoe UI", 10, "bold"), anchor="w", padx=10
                     ).grid(row=i, column=2, sticky="nsew", padx=1, pady=1)

            # Marks entry (large, easy to type into)
            mv = tk.StringVar()
            if res and not res["is_absent"] and res["marks"] is not None:
                mv.set(str(int(res["marks"]))
                       if res["marks"] == int(res["marks"])
                       else str(res["marks"]))

            entry = tk.Entry(self.body, textvariable=mv,
                             font=("Segoe UI", 13, "bold"),
                             bg=T("BG"), fg=T("TEXT"),
                             insertbackground=T("ACCENT"),
                             relief="flat",
                             highlightthickness=2,
                             highlightbackground=T("BORDER"),
                             highlightcolor=T("ACCENT"),
                             justify="center", width=8)
            entry.grid(row=i, column=3, sticky="nsew", padx=6, pady=3)
            all_entries.append(entry)

            # Level / performance label
            lv_lbl = tk.Label(self.body, text="",
                               bg=row_bg_color, fg=T("SUBTEXT"),
                               font=("Segoe UI", 10), anchor="w", padx=10)
            lv_lbl.grid(row=i, column=4, sticky="nsew", padx=1, pady=1)

            # Points
            pt_lbl = tk.Label(self.body, text="",
                               bg=row_bg_color, fg=T("TEXT"),
                               font=("Segoe UI", 10, "bold"), anchor="center")
            pt_lbl.grid(row=i, column=5, sticky="nsew", padx=4, pady=1)

            # Comment
            cv = tk.StringVar(
                value=res["teacher_comment"] if res and res["teacher_comment"] else "")
            comment = tk.Entry(self.body, textvariable=cv,
                                font=("Segoe UI", 10),
                                bg=T("BG"), fg=T("TEXT"),
                                insertbackground=T("ACCENT"),
                                relief="flat",
                                highlightthickness=1,
                                highlightbackground=T("BORDER"))
            comment.grid(row=i, column=6, sticky="nsew", padx=6, pady=3)

            # Real-time validation
            def _upd(event=None, _mv=mv, _ll=lv_lbl, _pl=pt_lbl, _e=entry):
                s = _mv.get().strip()
                if not s:
                    _ll.configure(text="— Absent —", fg=T("SUBTEXT"))
                    _pl.configure(text="")
                    _e.configure(highlightbackground=T("BORDER"))
                    return
                try:
                    m = float(s)
                    if m < 0 or m > self.max_marks:
                        _ll.configure(
                            text=f"⚠  Out of range  (0 – {int(self.max_marks)})",
                            fg=T("RED"))
                        _pl.configure(text="")
                        _e.configure(highlightbackground=T("RED"))
                        return
                    lv, label, pts = get_cbc_level(m, self.max_marks)
                    _ll.configure(text=f"{lv}  —  {label}", fg=cbc_color(lv))
                    _pl.configure(text=str(pts))
                    _e.configure(highlightbackground=cbc_color(lv))
                except (ValueError, TypeError):
                    _ll.configure(text="invalid entry", fg=T("RED"))
                    _pl.configure(text="")

            mv.trace_add("write", lambda *a, fn=_upd: fn())
            _upd()
            self.row_data.append({"lid": lrn["id"], "mv": mv, "cv": cv})

            # ── Ctrl+S bound directly on each Entry (Entry swallows keystrokes
            #    before Toplevel bindings fire). "break" prevents the default
            #    Entry behaviour (inserting ctrl-char) from also running.
            def _ctrl_save(e, fn=self._save_all):
                fn(silent=True)
                return "break"
            entry.bind("<Control-s>",   _ctrl_save)
            entry.bind("<Control-S>",   _ctrl_save)
            comment.bind("<Control-s>", _ctrl_save)
            comment.bind("<Control-S>", _ctrl_save)

        conn.close()

        # Keyboard nav: Tab / Enter / ↑ / ↓ — each move also auto-scrolls
        def _go(widget):
            widget.focus_set()
            widget.select_range(0, "end")
            widget.after(20, lambda: self._scroll_to(widget))
            return "break"

        n = len(all_entries)
        for idx, e in enumerate(all_entries):
            nxt = all_entries[(idx + 1) % n]
            prv = all_entries[(idx - 1) % n]
            e.bind("<Tab>",     lambda ev, w=nxt: _go(w))
            e.bind("<Return>",  lambda ev, w=nxt: _go(w))
            e.bind("<Down>",    lambda ev, w=nxt: _go(w))
            e.bind("<Up>",      lambda ev, w=prv: _go(w))
            e.bind("<FocusIn>", lambda ev, w=e: w.after(20, lambda: self._scroll_to(w)))

        if all_entries:
            all_entries[0].focus_set()
            self.after(150, lambda: self._scroll_to(all_entries[0]))

        self.status.configure(
            text=f"✏️  {len(learners)} learner(s) loaded  —  enter marks, then click 💾 Save All Marks")

    # ── Save all results ────────────────────────────────────────
    def _save_all(self, silent=False):
        """Save all marks. silent=True (Ctrl+S) shows status bar only, no dialog."""
        if not self.row_data:
            if not silent:
                messagebox.showwarning("Empty", "No learners loaded.")
            return
        saved = 0; errors = []
        conn  = get_conn()
        for row in self.row_data:
            s = row["mv"].get().strip()
            is_absent = (s == "")
            marks = 0.0
            if not is_absent:
                try:
                    marks = float(s)
                    if marks < 0 or marks > self.max_marks:
                        errors.append(
                            f"Mark {marks} out of range for learner id {row['lid']} — skipped")
                        continue
                except (ValueError, TypeError):
                    errors.append(
                        f"'{s}' is not a valid number for learner id {row['lid']} — skipped")
                    continue
            lv, _lbl, pts = get_cbc_level(marks, self.max_marks)
            perf  = "AB" if is_absent else lv
            pts_v = 0    if is_absent else pts
            ex = conn.execute(
                "SELECT id FROM results WHERE learner_id=? AND assessment_id=?",
                (row["lid"], self.assessment_id)).fetchone()
            if ex:
                conn.execute(
                    "UPDATE results SET marks=?,performance_level=?,points=?,"
                    "is_absent=?,teacher_comment=?,entry_date=date('now') "
                    "WHERE learner_id=? AND assessment_id=?",
                    (marks, perf, pts_v, int(is_absent),
                     row["cv"].get(), row["lid"], self.assessment_id))
            else:
                conn.execute(
                    "INSERT INTO results "
                    "(learner_id,assessment_id,marks,performance_level,"
                    " points,is_absent,teacher_comment) "
                    "VALUES (?,?,?,?,?,?,?)",
                    (row["lid"], self.assessment_id, marks, perf,
                     pts_v, int(is_absent), row["cv"].get()))
            saved += 1
        conn.commit(); conn.close()
        msg = f"✅  {saved} result(s) saved."
        if errors:
            detail = f"\n\n{len(errors)} skipped:\n" + "\n".join(errors[:8])
            messagebox.showwarning("Saved with issues", msg + detail)
        elif silent:
            # Ctrl+S: flash status bar only — don't interrupt keyboard flow
            self.status.configure(text=f"✅  Auto-saved {saved} result(s)  [Ctrl+S]",
                                  fg=T("GREEN"))
            self.after(3000, lambda: self.status.configure(
                text=f"✏️  {saved} learner(s) loaded  —  Ctrl+S to save",
                fg=T("GREEN")))
        else:
            self.status.configure(text=msg)
            messagebox.showinfo("Saved", msg)
            self._load()

# ─────────────────────────────────────────────────────────────
# REPORT CARD WINDOW (on-screen viewer)
# ─────────────────────────────────────────────────────────────
class ReportCardWindow(tk.Toplevel):
    def __init__(self, parent, learner_id, learner_name):
        super().__init__(parent)
        self.learner_id=learner_id
        self.title(f"Report Card — {learner_name}")
        self.configure(bg=T("PANEL")); self.geometry("860x680"); self.grab_set()
        self._build(learner_name)

    def _build(self, name):
        hdr=tk.Frame(self,bg=T("ACCENT"),pady=12); hdr.pack(fill="x")
        tk.Label(hdr,text=f"📋  CBC REPORT CARD  —  {school_name()}",
                 bg=T("ACCENT"),fg=T("BG"),font=("Segoe UI",15,"bold")).pack()
        conn=get_conn()
        lrn=conn.execute("""SELECT l.*,c.name AS cls,c.grade FROM learners l
            LEFT JOIN classes c ON l.class_id=c.id WHERE l.id=?""",(self.learner_id,)).fetchone()

        info=tk.Frame(self,bg=T("CARD"),padx=18,pady=10); info.pack(fill="x",padx=14,pady=8)
        for col,(label,val) in enumerate([
            ("Name",f"{lrn['first_name'].upper()} {lrn['last_name'].upper()}"),
            ("Adm No",lrn["admission_no"]),("Assessment No",lrn["nemis_no"] or "—"),
            ("Class",lrn["cls"] or "—"),("Gender",lrn["gender"] or "—"),
        ]):
            f=tk.Frame(info,bg=T("CARD")); f.pack(side="left",expand=True)
            tk.Label(f,text=label,bg=T("CARD"),fg=T("SUBTEXT"),font=FONT_S).pack(anchor="w")
            tk.Label(f,text=str(val),bg=T("CARD"),fg=T("TEXT"),font=FONT_H).pack(anchor="w")

        cols=["SUBJECT","ASSESSMENT","TERM","MARKS","MAX","% SCORE","LEVEL","POINTS","PERFORMANCE"]
        tbl_f=tk.Frame(self,bg=T("PANEL")); tbl_f.pack(fill="both",expand=True,padx=14,pady=4)
        tbl=StyledTable(tbl_f,cols,col_widths=[160,180,60,60,60,70,60,60,200])
        tbl.pack(fill="both",expand=True)

        rows=conn.execute("""
            SELECT s.name,a.name,COALESCE(a.term,'—'),
                   r.marks,a.max_marks,
                   ROUND(100.0*r.marks/a.max_marks,1),
                   r.performance_level,r.points,
                   CASE r.performance_level
                     WHEN 'EE1' THEN 'Exceeding Expectation 1'
                     WHEN 'EE2' THEN 'Exceeding Expectation 2'
                     WHEN 'ME1' THEN 'Meeting Expectation 1'
                     WHEN 'ME2' THEN 'Meeting Expectation 2'
                     WHEN 'AE1' THEN 'Approaching Expectation 1'
                     WHEN 'AE2' THEN 'Approaching Expectation 2'
                     WHEN 'BE1' THEN 'Below Expectation 1'
                     WHEN 'BE2' THEN 'Below Expectation 2'
                     WHEN 'AB'  THEN 'Absent'
                     ELSE '—' END
            FROM results r
            JOIN assessments a ON r.assessment_id=a.id
            JOIN subjects s ON a.subject_id=s.id
            WHERE r.learner_id=? ORDER BY s.name,a.term
        """,(self.learner_id,)).fetchall()
        conn.close()

        total_pts=0; n=0
        for r in rows:
            tag=r[6] if r[6] in [lv["level"] for lv in get_cbc_levels()] else ""
            tbl.insert(list(r),tag=tag)
            if r[6] not in (None,"AB",""): total_pts+=(r[7] or 0); n+=1

        # Autofit columns to content after data is loaded
        tbl.update_idletasks()
        tbl.autofit_columns()
        # Re-autofit when window is resized so columns always fill the available space
        def _on_resize(event, _tbl=tbl):
            _tbl.autofit_columns()
        tbl_f.bind("<Configure>", _on_resize)

        summ=tk.Frame(self,bg=T("CARD"),padx=18,pady=10); summ.pack(fill="x",padx=14,pady=6)
        avg=round(total_pts/n,2) if n else 0
        for label,val,color in [("Total Points",total_pts,T("ACCENT")),
                                  ("Subjects",n,T("GREEN")),("Avg Points",avg,T("YELLOW"))]:
            f=tk.Frame(summ,bg=T("CARD"),padx=14,pady=6,highlightthickness=1,highlightbackground=color)
            f.pack(side="left",padx=6)
            tk.Label(f,text=str(val),bg=T("CARD"),fg=color,font=("Segoe UI",16,"bold")).pack()
            tk.Label(f,text=label,bg=T("CARD"),fg=T("SUBTEXT"),font=FONT_S).pack()
        tk.Label(summ,text=overall_comment(avg),bg=T("CARD"),fg=T("TEXT"),
                 font=FONT_B,wraplength=320,justify="left").pack(side="left",padx=14)

        bot=tk.Frame(self,bg=T("PANEL"),pady=8); bot.pack(fill="x",padx=14)
        mk_btn(bot,"📄 Export PDF",lambda: generate_report_pdf_single(self.learner_id),T("RED"),T("WHITE")).pack(side="left",padx=4)
        mk_btn(bot,"⬇ Export CSV",lambda: self._export_csv(lrn,rows,total_pts,avg),T("BORDER"),T("TEXT")).pack(side="left",padx=4)
        mk_btn(bot,"Close",self.destroy,T("BORDER"),T("TEXT")).pack(side="right",padx=6)

    def _export_csv(self,lrn,rows,total_pts,avg):
        path=filedialog.asksaveasfilename(defaultextension=".csv",filetypes=[("CSV","*.csv")])
        if not path: return
        with open(path,"w",newline="") as f:
            w=csv.writer(f); w.writerow(["CBC REPORT CARD",school_name()])
            w.writerow(["Name",f"{lrn['first_name'].upper()} {lrn['last_name'].upper()}","Adm No",lrn["admission_no"]])
            w.writerow(["SUBJECT","ASSESSMENT","TERM","MARKS","MAX","% SCORE","LEVEL","POINTS","PERFORMANCE"])
            for r in rows: w.writerow(list(r))
            w.writerow([]); w.writerow(["Total Points",total_pts,"Avg Points",avg,overall_comment(avg)])
        messagebox.showinfo("Exported",f"Exported to:\n{path}")


# ─────────────────────────────────────────────────────────────
# PDF GENERATION — SINGLE REPORT CARD
# ─────────────────────────────────────────────────────────────
def _get_class_position(learner_id, lrn):
    """Return (position, class_total) using standard competition ranking (ties share the same rank).
    Example: scores 90, 85, 85, 70 -> ranks 1, 2, 2, 4."""
    if not lrn or not lrn["class_id"]:
        return None, None
    conn = get_conn()
    grade_str = lrn["grade"] if lrn["grade"] else ""
    use_marks = is_primary_grade(grade_str)
    score_expr = "SUM(CASE WHEN r.is_absent=0 THEN r.marks ELSE 0 END)" if use_marks else "SUM(CASE WHEN r.is_absent=0 THEN r.points ELSE 0 END)"
    results = conn.execute(f"""
        SELECT r.learner_id, {score_expr} AS total_pts
        FROM results r
        JOIN assessments a ON r.assessment_id = a.id
        WHERE a.class_id = ?
        GROUP BY r.learner_id
        ORDER BY total_pts DESC
    """, (lrn["class_id"],)).fetchall()
    conn.close()
    if not results:
        return None, None
    total = len(results)
    # Standard competition ranking: tied learners share the same rank,
    # next rank skips (1, 2, 2, 4 -- not 1, 2, 2, 3)
    rank = 1
    for i, row in enumerate(results):
        if i > 0 and results[i]["total_pts"] < results[i - 1]["total_pts"]:
            rank = i + 1
        if row["learner_id"] == learner_id:
            return rank, total
    return None, total


def generate_report_pdf_single(learner_id, filepath=None):
    conn = get_conn()
    lrn = conn.execute(
        "SELECT l.*,c.name AS cls,c.grade,c.teacher "
        "FROM learners l LEFT JOIN classes c ON l.class_id=c.id WHERE l.id=?",
        (learner_id,)
    ).fetchone()

    # Build rows for active subjects filtered to this learner's section/grade
    _grade_str = lrn["grade"] if lrn and lrn["grade"] else ""
    all_subjects = get_section_subjects(_grade_str, conn)

    rows = []
    for subj in all_subjects:
        res = conn.execute("""
            SELECT r.marks, a.max_marks,
                   ROUND(100.0*r.marks/a.max_marks,1) AS pct,
                   r.performance_level, r.points,
                   r.is_absent, r.teacher_comment, a.term
            FROM results r
            JOIN assessments a ON r.assessment_id=a.id
            WHERE r.learner_id=? AND a.subject_id=?
            ORDER BY r.id DESC LIMIT 1
        """, (learner_id, subj["id"])).fetchone()
        if res:
            rows.append((subj["name"], res["term"] or "—", res["marks"],
                         res["max_marks"], res["pct"], res["performance_level"],
                         res["points"], res["is_absent"], res["teacher_comment"],
                         subj["sort_order"]))
        else:
            rows.append((subj["name"], "—", None, 100, None, None, None, 0, "",
                         subj["sort_order"]))
    conn.close()

    if not filepath:
        adm = lrn["admission_no"] if lrn else "learner"
        filepath = filedialog.asksaveasfilename(
            defaultextension=".pdf", filetypes=[("PDF","*.pdf")],
            initialfile=f"ReportCard_{adm}.pdf")
    if not filepath: return

    pos, total = _get_class_position(learner_id, lrn)
    # Extract term/year from the first row that has data
    _term = next((r[1] for r in rows if r[1] and r[1] != "—"), "")
    _year = str(datetime.now().year)
    _primary = is_primary_grade(lrn["grade"] if lrn and lrn["grade"] else "")
    try:
        _build_report_pdf(lrn, rows, filepath, class_position=pos, class_total=total, term=_term, year=_year, primary=_primary)
        messagebox.showinfo("PDF Saved", f"Report card saved to:\n{filepath}")
    except Exception as e:
        messagebox.showerror("PDF Error", f"Failed to build PDF:\n{e}")



def conn_get_lrn(learner_id):
    conn = get_conn()
    lrn = conn.execute(
        "SELECT l.*,c.name AS cls,c.grade,c.teacher "
        "FROM learners l LEFT JOIN classes c ON l.class_id=c.id WHERE l.id=?",
        (learner_id,)
    ).fetchone()
    conn.close()
    return lrn

def conn_get_rows(learner_id):
    conn = get_conn()
    rows = conn.execute("""
        SELECT s.name, a.term, r.marks, a.max_marks,
               ROUND(100.0*r.marks/a.max_marks,1),
               r.performance_level, r.points, r.is_absent, r.teacher_comment,
               s.sort_order
        FROM results r
        JOIN assessments a ON r.assessment_id=a.id
        JOIN subjects s ON a.subject_id=s.id
        WHERE r.learner_id=? ORDER BY s.sort_order, s.name, a.term
    """, (learner_id,)).fetchall()
    conn.close()
    return rows

def _build_report_elems(lrn, rows, class_position=None, class_total=None, term="", year=""):
    """Thin wrapper used by batch PDF export."""
    _primary = is_primary_grade(lrn["grade"] if lrn and lrn["grade"] else "")
    return _report_card_elements(lrn, rows,
                                 class_position=class_position,
                                 class_total=class_total,
                                 term=term, year=year,
                                 primary=_primary)


def _get_full_page_report_elems(lrn, rows, class_position=None, class_total=None, ct_comment=None):
    """Legacy alias — delegates to the unified builder."""
    return _report_card_elements(lrn, rows,
                                 class_position=class_position,
                                 class_total=class_total,
                                 ct_comment=ct_comment)


def _report_card_elements(lrn, rows, class_position=None, class_total=None, ct_comment=None, term="", year="", primary=False, learner_index=0, grade_position=None, grade_total=None):
    """
    Single source of truth for the full-page A4 report card.
    Returns a list of ReportLab flowable elements.
    Used by both single-PDF and batch-PDF export.
    """
    # ── determine section ────────────────────────────────────────────
    grade_str   = lrn["grade"] if lrn["grade"] else ""
    pre_prim    = is_pre_primary_grade(grade_str)
    primary     = primary or is_primary_grade(grade_str) or pre_prim
    lower_prim  = is_lower_primary_grade(grade_str)
    upper_prim  = is_upper_primary_grade(grade_str)

    # ── Step 1: build sub→parent map FIRST so the filter can use it ─────
    # rows tuple index: (name=0, term=1, marks=2, max_marks=3, pct=4,
    #                    perf_level=5, points=6, is_absent=7, teacher_comment=8, sort_order=9)
    _cmp_conn = get_conn()
    # Map: sub-subject name (lower) → {parent_name, parent_sort_order}
    _sub_to_parent: dict = {}
    for _sr in _cmp_conn.execute(
        "SELECT s.name AS sub_name, p.name AS parent_name, "
        "       p.sort_order AS parent_sort "
        "FROM subjects s "
        "JOIN subjects p ON s.composite_parent_id = p.id "
        "WHERE s.composite_parent_id IS NOT NULL "
        "  AND s.is_active = 1 AND p.is_active = 1"
    ).fetchall():
        _sub_to_parent[_sr["sub_name"].strip().lower()] = {
            "name": _sr["parent_name"],
            "sort_order": _sr["parent_sort"],
        }
    _cmp_conn.close()

    # ── Step 2: filter by section — keep normal subjects AND sub-subjects ─
    # Sub-subjects have sort_order=99 (outside any section range) so
    # subj_allowed_for_grade would drop them before grouping.
    # We must keep them here so Step 3 can sum them into their parent row.
    rows = [r for r in rows
            if subj_allowed_for_grade(r[0], grade_str, r[9] if len(r) > 9 else None)
            or str(r[0]).strip().lower() in _sub_to_parent
            ]

    # ── Step 3: split rows — normal subjects vs sub-subject groups ───────
    _normal_rows  = []   # standalone (non-sub) rows pass straight through
    _sub_groups: dict = {}  # parent_name → list of sub-rows
    for _r in rows:
        _rname = str(_r[0]).strip().lower()
        if _rname in _sub_to_parent:
            _pinfo = _sub_to_parent[_rname]
            _sub_groups.setdefault(_pinfo["name"], []).append((_r, _pinfo))
        else:
            _normal_rows.append(_r)

    # ── Step 4: build one synthetic composite row per parent ─────────────
    _synthetic_rows = []
    for _parent_name, _sub_list in _sub_groups.items():
        _pinfo       = _sub_list[0][1]
        _sub_only    = [x[0] for x in _sub_list]
        _has_data    = any(_sr[2] is not None for _sr in _sub_only)
        _any_absent  = any(_sr[7] for _sr in _sub_only)
        _total_marks = sum((_sr[2] or 0) for _sr in _sub_only if not _sr[7])
        _total_max   = sum((_sr[3] or 100) for _sr in _sub_only)
        _pct_val     = round(100.0 * _total_marks / _total_max, 1) if (_total_max and _has_data) else None
        if _has_data and _total_max:
            _lv_code, _, _pts_val = get_cbc_level(_total_marks, _total_max)
        else:
            _lv_code, _pts_val = None, None
        _term_val    = next((_sr[1] for _sr in _sub_only if _sr[1] and _sr[1] != "—"), "—")
        _absent_flag = 1 if (_any_absent and _total_marks == 0) else 0
        _synthetic_rows.append((
            _parent_name,
            _term_val,
            _total_marks if _has_data else None,
            _total_max,
            _pct_val,
            _lv_code,
            _pts_val,
            _absent_flag,
            "",
            _pinfo["sort_order"],
        ))

    rows = _normal_rows + _synthetic_rows

    # ── sort rows by section-specific subject order ───────────────────
    rows = sorted(rows, key=lambda r: subject_sort_key(r[0], grade_str))

    # ── totals ───────────────────────────────────────────────────────
    total_pts = 0; total_marks = 0; n_subjects = 0
    for r in rows:
        if not r[7] and r[6] is not None:
            total_pts   += (r[6] or 0)
            total_marks += (r[2] or 0)
            n_subjects  += 1
    max_pts  = len(rows) * get_cbc_levels()[0]["points"]  # based on actual subjects in this report
    avg_pts  = round(total_pts / n_subjects, 1) if n_subjects else 0
    avg_marks= round(total_marks / n_subjects, 1) if n_subjects else 0
    if not ct_comment:
        if primary:
            # Comment based on average mark percentage (out of 100)
            ct_comment = auto_comment(avg_marks / 10, learner_index) if avg_marks else overall_comment(0)
        else:
            ct_comment = auto_comment(avg_pts, learner_index)

    W   = A4[0] - 24*mm
    sch = school_name()

    # ── Dynamic height computation — every section fills the page ────
    PAGE_W, PAGE_H = A4
    LM = RM = 12 * mm
    TM = 6 * mm
    BM = 14 * mm   # must match _build_report_pdf — footer needs 14 mm clearance
    avail_h = PAGE_H - TM - BM   # full usable height inside the frame

    n_data    = len(rows)         # number of subject rows (already filtered)
    n_ck_rows = 2 if primary else 3   # CBC key rows (primary hides pts)

    # Fixed-height elements (ReportLab pts ≈ 1/72 inch; 1mm ≈ 2.835pt)
    _H_HDR      = 62   # header banner
    _H_INFO     = 68   # 4-row learner info table at 7pt with 3pt padding
    _H_PERF_HDR = 14   # performance table header row
    _H_PERF_TOT = 14   # performance table totals row
    _H_SUMM     = 28   # summary strip
    _H_CK       = n_ck_rows * 13  # CBC key table rows
    _H_SIG      = 40   # 3-line sig paragraph at 7pt/10pt-leading = 30pt text + 10pt padding
    _H_FTR      = 0    # footer drawn in margin via onPage — no flowable height needed
    # Small paragraph labels (3 labels × ~14pt each)
    _H_LABELS   = 42

    # 7 micro-spacers between sections (reduced to save space)
    _N_SP = 7

    _fixed_h = (_H_HDR + _H_INFO + _H_PERF_HDR + _H_PERF_TOT +
                _H_SUMM + _H_CK + _H_SIG + _H_FTR + _H_LABELS)

    # Allocate remaining height: 3% spacers, 12% comments, 10% bar chart, rest = data rows
    _sp_total   = avail_h * 0.03
    _cmt_total  = avail_h * 0.12
    _bar_total  = avail_h * 0.10
    _data_total = avail_h - _fixed_h - _sp_total - _cmt_total - _bar_total

    sp          = _sp_total / _N_SP
    data_row_h  = max(14, _data_total / max(n_data, 1))
    cmt_1_h     = _cmt_total   # class teacher row only (head teacher removed)

    # ── convenience paragraph style factory ─────────────────────────
    def PS(name, size=9, font="Helvetica-Bold", align=TA_LEFT, color="#000000",
           leading=13, indent=0):
        return ParagraphStyle(name, fontSize=size, fontName=font,
                              alignment=align, textColor=rl_colors.HexColor(color),
                              leading=leading, leftIndent=indent, wordWrap="CJK")

    LBL  = PS("rc_lbl",  size=7, font="Helvetica-Bold",   color="#0a2540", leading=10)
    VAL  = PS("rc_val",  size=7, font="Helvetica-Bold",   color="#1a1a1a", leading=10)
    HDR  = PS("rc_hdr",  size=14, font="Helvetica-Bold",   align=TA_CENTER,
              color="#ffffff", leading=20)
    HSUB = PS("rc_hsub", size=9,  font="Helvetica",        align=TA_CENTER,
              color="#aaddff", leading=13)
    HMOT = PS("rc_hmot", size=8,  font="Helvetica-Oblique",align=TA_CENTER,
              color="#88ccee", leading=11)
    CHDR = PS("rc_chdr", size=7,  font="Helvetica-Bold",   align=TA_CENTER,
              color="#ffffff", leading=9)
    SUBJ = PS("rc_subj", size=8,  font="Helvetica-Bold",   color="#0a2540", leading=10)
    PERF = PS("rc_perf", size=7,  font="Helvetica",        color="#0a2540", leading=9)
    CDAT = PS("rc_cdat", size=8,  font="Helvetica-Bold",   align=TA_CENTER, color="#1a1a1a")
    SMRY = PS("rc_smry", size=6,  font="Helvetica-Bold",   align=TA_CENTER, color="#0a2540")
    SMRV = PS("rc_smrv", size=13, font="Helvetica-Bold",   align=TA_CENTER, color="#0a2540")
    CLBL = PS("rc_clbl", size=9,  font="Helvetica-Bold",   color="#0a2540")
    CVAL = PS("rc_cval", size=9,  font="Helvetica-Oblique", color="#1e3a5f", leading=13)
    CBLK = PS("rc_cblk", size=9,  font="Helvetica",        color="#444444")
    NTDS = PS("rc_ntd",  size=11, font="Helvetica-Bold",   color="#0a2540")
    SIGS = PS("rc_sig",  size=7,  font="Helvetica-Bold",   color="#0a2540", leading=10)
    FTRL = PS("rc_ftrl", size=8,  font="Helvetica-Bold",   color="#0a2540")
    FTRC = PS("rc_ftrc", size=9,  font="Helvetica-BoldOblique", align=TA_CENTER, color="#0a2540")
    FTRR = PS("rc_ftrr", size=7,  font="Helvetica",        align=TA_RIGHT,  color="#888888")
    LVHD = PS("rc_lvhd", size=7,  font="Helvetica-Bold",   align=TA_CENTER, color="#ffffff")
    LVRG = PS("rc_lvrg", size=7,  font="Helvetica-Bold",   align=TA_CENTER, color="#333333")
    LVPT = PS("rc_lvpt", size=7,  font="Helvetica",        align=TA_CENTER, color="#333333")

    elems = []

    # ════════════════════════════════════════════════════════════
    # 1. HEADER BANNER  — logo | school title | learner photo
    # ════════════════════════════════════════════════════════════
    logo = get_logo_image(26, 26)

    photo_cell = ""
    if lrn["photo_path"] and os.path.exists(str(lrn["photo_path"])):
        try:
            photo_cell = RLImage(lrn["photo_path"], width=24*mm, height=28*mm)
        except Exception:
            pass  # corrupt/missing image — skip gracefully

    if lower_prim:
        section_label = "PRIMARY SCHOOL — LOWER (Gr 1–3)"
    elif upper_prim:
        section_label = "PRIMARY SCHOOL — UPPER (Gr 4–6)"
    else:
        section_label = "JUNIOR SCHOOL (Gr 7–9)"
    title_para = Paragraph(
        f"<b>{sch.upper()}</b><br/>"
        f"<font size=8>CBC LEARNER'S ACADEMIC REPORT — {section_label}</font><br/>"
        f"<i><font size=7.5>{school_motto()}</font></i>",
        ParagraphStyle("rc_hdr_c", fontSize=14, fontName="Helvetica-Bold",
                       alignment=TA_CENTER, textColor=rl_colors.white, leading=18,
                       wordWrap="CJK")
    )
    hdr_tbl = Table(
        [[logo or "", title_para, photo_cell]],
        colWidths=[28*mm, W - 56*mm, 28*mm]
    )
    hdr_tbl.setStyle(TableStyle([
        ("BACKGROUND",   (0,0),(-1,-1), rl_colors.HexColor("#0a2540")),
        ("VALIGN",       (0,0),(-1,-1), "MIDDLE"),
        ("ALIGN",        (0,0),(0,-1),  "LEFT"),
        ("ALIGN",        (2,0),(2,-1),  "RIGHT"),
        ("TOPPADDING",   (0,0),(-1,-1), 8),
        ("BOTTOMPADDING",(0,0),(-1,-1), 8),
        ("LEFTPADDING",  (0,0),(0,-1),  8),
        ("RIGHTPADDING", (2,0),(2,-1),  8),
    ]))
    elems.append(hdr_tbl)
    elems.append(Spacer(1, sp))

    # ════════════════════════════════════════════════════════════
    # 2. LEARNER INFORMATION BOX  (includes class position)
    # ════════════════════════════════════════════════════════════
    cls_name = str((lrn["cls"]  or "—"))
    grade    = str((lrn["grade"] or ""))
    teacher  = str((lrn["teacher"] or "—"))
    pos_str  = (f"{class_position} / {class_total}"
                if class_position and class_total else "—")
    grade_pos_str = (f"{grade_position} / {grade_total}"
                     if grade_position and grade_total else "—")

    def lbl(t): return Paragraph(t, LBL)
    def val(t): return Paragraph(str(t) if t else "—", VAL)

    # Build learner name — truncate gracefully if extremely long
    _full_name = f"{lrn['first_name'].upper()} {lrn['last_name'].upper()}"
    _NAME_STYLE = ParagraphStyle("rc_name", fontSize=7, fontName="Helvetica-Bold",
                                 textColor=rl_colors.HexColor("#1a1a1a"),
                                 leading=10, wordWrap="CJK")

    info_data = [
        # Row 0: NAME value spans cols 1-2 (col 2 = dummy placeholder hidden by span).
        # ADM NO label in col 3, ADM NO value in col 4, NEMIS (label+value) in col 5.
        [lbl("NAME:"),          Paragraph(_full_name, _NAME_STYLE),
         Paragraph("", VAL),                       # placeholder — hidden by SPAN (1,0)-(2,0)
         lbl("ADM NO:"),        val(lrn["admission_no"]),
         Paragraph(f"Assessment No: {lrn['nemis_no'] or '—'}",
                   ParagraphStyle("rc_nemis", fontSize=7, fontName="Helvetica-Bold",
                                  textColor=rl_colors.HexColor("#1a1a1a"), leading=10))],
        [lbl("CLASS:"),         val(cls_name),
         lbl("GRADE:"),         val(grade or "—"),
         lbl("GENDER:"),        val((lrn["gender"] or "—"))],
        [lbl("CLASS TEACHER:"), val(teacher),
         lbl("TERM:"),          val(term or "—"),
         lbl("YEAR:"),          val(year or "—")],
        [lbl("CLASS POSITION:"), val(pos_str),
         lbl("GRADE POSITION:"), val(grade_pos_str),
         lbl("AVG " + ("MARKS:" if primary else "POINTS:")),
         val(str(avg_marks) if primary else str(avg_pts))],
    ]
    # 28 mm label cols — minimum for "GRADE POSITION:" (25.4 mm text + 2.6 mm padding)
    _lbl_w = 28*mm
    _val_w = (W - _lbl_w * 3) / 3
    cw_info = [_lbl_w, _val_w, _lbl_w, _val_w, _lbl_w, _val_w]
    info_tbl = Table(info_data, colWidths=cw_info)
    info_tbl.setStyle(TableStyle([
        ("GRID",         (0,0),(-1,-1), 0.5, rl_colors.HexColor("#aaaaaa")),
        ("BACKGROUND",   (0,0),(0,-1),  rl_colors.HexColor("#dbeafe")),
        ("BACKGROUND",   (2,0),(2,-1),  rl_colors.HexColor("#dbeafe")),
        ("BACKGROUND",   (4,0),(4,-1),  rl_colors.HexColor("#dbeafe")),
        ("TOPPADDING",   (0,0),(-1,-1), 3),
        ("BOTTOMPADDING",(0,0),(-1,-1), 3),
        ("LEFTPADDING",  (0,0),(-1,-1), 4),
        ("RIGHTPADDING", (0,0),(-1,-1), 3),
        ("VALIGN",       (0,0),(-1,-1), "MIDDLE"),
        ("FONTSIZE",     (0,0),(-1,-1), 7),
        # Span NAME value (col 1) across cols 1-2 for extra width
        ("SPAN",         (1,0),(2,0)),
        # Col 2 in row 0 is now part of the span — clear its label bg
        ("BACKGROUND",   (2,0),(2,0),  rl_colors.HexColor("#ffffff")),
        # Col 4 in row 0 holds ADM NO value (not a label) — white bg
        ("BACKGROUND",   (4,0),(4,0),  rl_colors.HexColor("#ffffff")),
        # Col 3 in row 0 is the ADM NO label — blue bg
        ("BACKGROUND",   (3,0),(3,0),  rl_colors.HexColor("#dbeafe")),
    ]))
    elems.append(info_tbl)
    elems.append(Spacer(1, sp))

    # ════════════════════════════════════════════════════════════
    # 3. ACADEMIC PERFORMANCE TABLE
    #    Every cell is a Paragraph — text wraps, never spills
    # ════════════════════════════════════════════════════════════
    elems.append(Paragraph(
        "<b>ACADEMIC PERFORMANCE</b>",
        PS("rc_sec", size=9, font="Helvetica-Bold", color="#0a2540")
    ))
    elems.append(Spacer(1, sp * 0.4))

    lv_hex = {
        "EE1":"#15803d","EE2":"#16a34a",
        "ME1":"#1d4ed8","ME2":"#2563eb",
        "AE1":"#c2410c","AE2":"#ea580c",
        "BE1":"#b91c1c","BE2":"#dc2626",
        "AB" :"#6b7280",
    }

    def ch(t): return Paragraph(t, CHDR)
    # Wider numeric cols so header text never wraps: MARKS(17) MAX(13) %SCORE(17) LEVEL(15) PTS(12)
    if primary:
        col_hdr_row = [ch("#"), ch("SUBJECT"), ch("MARKS"), ch("MAX"),
                       ch("% SCORE"), ch("LEVEL"), ch("PERFORMANCE DESCRIPTOR")]
    else:
        col_hdr_row = [ch("#"), ch("SUBJECT"), ch("MARKS"), ch("MAX"),
                       ch("% SCORE"), ch("LEVEL"), ch("PTS"), ch("PERFORMANCE DESCRIPTOR")]
    tbl_data   = [col_hdr_row]
    row_styles = []
    row_idx    = 1

    for r in rows:
        subj  = str(r[0]).upper() if r[0] else "—"
        lv    = r[5] or "—"
        pts   = r[6] if not r[7] else 0
        marks = "ABS" if r[7] else (
            str(int(r[2])) if r[2] is not None and r[2] == int(r[2]) else str(r[2]))
        pct   = f"{r[4]}%" if (not r[7] and r[4] is not None) else "—"

        lv_color = rl_colors.HexColor(lv_hex.get(lv, "#6b7280"))
        LV_S = ParagraphStyle(f"rc_lv{row_idx}", fontSize=8, fontName="Helvetica-Bold",
                              alignment=TA_CENTER, textColor=rl_colors.white, leading=10)

        if primary:
            tbl_data.append([
                Paragraph(str(row_idx), CDAT),
                Paragraph(subj,         SUBJ),
                Paragraph(marks,        CDAT),
                Paragraph(str(int(r[3]) if r[3] else 100), CDAT),
                Paragraph(pct,          CDAT),
                Paragraph(lv,           LV_S),
                Paragraph(_lv_label(lv), PERF),
            ])
            row_styles += [("BACKGROUND", (5,row_idx),(5,row_idx), lv_color)]
            bg = rl_colors.white if row_idx % 2 == 1 else rl_colors.HexColor("#f0f7ff")
            row_styles += [
                ("BACKGROUND", (0,row_idx),(4,row_idx), bg),
                ("BACKGROUND", (6,row_idx),(6,row_idx), bg),
            ]
        else:
            tbl_data.append([
                Paragraph(str(row_idx), CDAT),
                Paragraph(subj,         SUBJ),
                Paragraph(marks,        CDAT),
                Paragraph(str(int(r[3]) if r[3] else 100), CDAT),
                Paragraph(pct,          CDAT),
                Paragraph(lv,           LV_S),
                Paragraph(str(pts) if pts else "0", CDAT),
                Paragraph(_lv_label(lv), PERF),
            ])
            row_styles += [("BACKGROUND", (5,row_idx),(5,row_idx), lv_color)]
            bg = rl_colors.white if row_idx % 2 == 1 else rl_colors.HexColor("#f0f7ff")
            row_styles += [
                ("BACKGROUND", (0,row_idx),(4,row_idx), bg),
                ("BACKGROUND", (6,row_idx),(7,row_idx), bg),
            ]
        row_idx += 1

    # Totals row
    if primary:
        tbl_data.append([
            Paragraph("", CDAT),
            Paragraph("<b>TOTAL</b>",
                      ParagraphStyle("rc_tot", fontSize=9, fontName="Helvetica-Bold",
                                     alignment=TA_LEFT, textColor=rl_colors.white, leading=12)),
            Paragraph(f"<b>{int(total_marks)}</b>",
                      ParagraphStyle("rc_totv", fontSize=9, fontName="Helvetica-Bold",
                                     alignment=TA_CENTER, textColor=rl_colors.white, leading=12)),
            Paragraph("", CDAT), Paragraph("", CDAT), Paragraph("", CDAT),
            Paragraph("", CDAT),
        ])
        row_styles += [
            ("BACKGROUND", (0,row_idx),(-1,row_idx), rl_colors.HexColor("#0a2540")),
            ("TEXTCOLOR",  (0,row_idx),(-1,row_idx), rl_colors.white),
            ("FONTNAME",   (0,row_idx),(-1,row_idx), "Helvetica-Bold"),
            ("FONTSIZE",   (0,row_idx),(-1,row_idx), 9),
        ]
    else:
        tbl_data.append([
            Paragraph("", CDAT),
            Paragraph("<b>TOTAL / AGGREGATE</b>",
                      ParagraphStyle("rc_tot", fontSize=9, fontName="Helvetica-Bold",
                                     alignment=TA_LEFT, textColor=rl_colors.white,
                                     leading=12, colSpan=4)),
            Paragraph("", CDAT), Paragraph("", CDAT), Paragraph("", CDAT),
            Paragraph("", CDAT),
            Paragraph(f"<b>{total_pts} / {max_pts}</b>",
                      ParagraphStyle("rc_totv", fontSize=9, fontName="Helvetica-Bold",
                                     alignment=TA_CENTER, textColor=rl_colors.white,
                                     leading=12, colSpan=2)),
            Paragraph("", CDAT),
        ])
        row_styles += [
            ("BACKGROUND", (0,row_idx),(-1,row_idx), rl_colors.HexColor("#0a2540")),
            ("TEXTCOLOR",  (0,row_idx),(-1,row_idx), rl_colors.white),
            ("FONTNAME",   (0,row_idx),(-1,row_idx), "Helvetica-Bold"),
            ("FONTSIZE",   (0,row_idx),(-1,row_idx), 9),
            ("SPAN",       (1,row_idx),(4,row_idx)),
            ("SPAN",       (6,row_idx),(7,row_idx)),
        ]

    # Use dynamically computed data_row_h (fills page proportionally)
    n_data_rows = len(tbl_data)
    # data_row_h already computed above; total row same height for symmetry
    _perf_row_heights = None  # auto-size: let ReportLab fit content into each row

    if primary:
        # Primary cols: #(6) + Subject(55) + Marks(17) + Max(13) + %(17) + Level(15) + Descriptor = rest
        _desc_w_prim = W - (6 + 55 + 17 + 13 + 17 + 15) * mm
        perf_tbl = Table(tbl_data,
                         colWidths=[6*mm, 55*mm, 17*mm, 13*mm, 17*mm, 15*mm, _desc_w_prim],
                         rowHeights=_perf_row_heights)
        perf_tbl.setStyle(TableStyle([
            ("FONTNAME",      (0,0),(-1,0),  "Helvetica-Bold"),
            ("FONTSIZE",      (0,0),(-1,-1), 8),
            ("FONTSIZE",      (0,0),(-1,0),  7),   # header slightly smaller to fit
            ("BACKGROUND",    (0,0),(-1,0),  rl_colors.HexColor("#0a2540")),
            ("TEXTCOLOR",     (0,0),(-1,0),  rl_colors.white),
            ("GRID",          (0,0),(-1,-1), 0.5, rl_colors.HexColor("#999999")),
            ("ALIGN",         (0,0),(-1,-1), "CENTER"),
            ("ALIGN",         (1,0),(1,-1),  "LEFT"),
            ("ALIGN",         (6,0),(6,-1),  "LEFT"),
            ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
            ("TOPPADDING",    (0,0),(-1,-1), 3),
            ("BOTTOMPADDING", (0,0),(-1,-1), 3),
            ("LEFTPADDING",   (1,0),(1,-1),  5),
            ("LEFTPADDING",   (6,0),(6,-1),  5),
        ] + row_styles))
    else:
        # Junior cols: #(6) + Subject(55) + Marks(17) + Max(13) + %(17) + Level(15) + Pts(12) + Descriptor = rest
        _desc_w_jnr = W - (6 + 55 + 17 + 13 + 17 + 15 + 12) * mm
        perf_tbl = Table(tbl_data,
                         colWidths=[6*mm, 55*mm, 17*mm, 13*mm, 17*mm, 15*mm, 12*mm, _desc_w_jnr],
                         rowHeights=_perf_row_heights)
        perf_tbl.setStyle(TableStyle([
            ("FONTNAME",      (0,0),(-1,0),  "Helvetica-Bold"),
            ("FONTSIZE",      (0,0),(-1,-1), 8),
            ("FONTSIZE",      (0,0),(-1,0),  7),   # header slightly smaller to fit
            ("BACKGROUND",    (0,0),(-1,0),  rl_colors.HexColor("#0a2540")),
            ("TEXTCOLOR",     (0,0),(-1,0),  rl_colors.white),
            ("GRID",          (0,0),(-1,-1), 0.5, rl_colors.HexColor("#999999")),
            ("ALIGN",         (0,0),(-1,-1), "CENTER"),
            ("ALIGN",         (1,0),(1,-1),  "LEFT"),
            ("ALIGN",         (7,0),(7,-1),  "LEFT"),
            ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
            ("TOPPADDING",    (0,0),(-1,-1), 3),
            ("BOTTOMPADDING", (0,0),(-1,-1), 3),
            ("LEFTPADDING",   (1,0),(1,-1),  5),
            ("LEFTPADDING",   (7,0),(7,-1),  5),
        ] + row_styles))
    elems.append(perf_tbl)
    elems.append(Spacer(1, sp))

    # ════════════════════════════════════════════════════════════
    # 4. SUMMARY STRIP  (Total pts | Subjects | Avg pts | Position)
    # ════════════════════════════════════════════════════════════
    def sm_lbl(t): return Paragraph(t, SMRY)
    def sm_val(t): return Paragraph(str(t), SMRV)

    if primary:
        summ_data = [[
            sm_lbl("TOTAL MARKS"),
            sm_val(str(int(total_marks))),
            sm_lbl("SUBJECTS ASSESSED"),
            sm_val(str(n_subjects)),
            sm_lbl("AVERAGE MARKS"),
            sm_val(str(avg_marks)),
        ]]
    else:
        summ_data = [[
            sm_lbl("TOTAL POINTS"),
            sm_val(f"{total_pts} / {max_pts}"),
            sm_lbl("SUBJECTS ASSESSED"),
            sm_val(str(n_subjects)),
            sm_lbl("AVERAGE POINTS"),
            sm_val(str(avg_pts)),
        ]]
    summ_tbl = Table(summ_data,
                     colWidths=[36*mm, 26*mm, 44*mm, 20*mm, 36*mm, None],
                     rowHeights=[_H_SUMM])
    summ_tbl.setStyle(TableStyle([
        ("GRID",          (0,0),(-1,-1), 0.5, rl_colors.HexColor("#aaaaaa")),
        ("BACKGROUND",    (0,0),(0,-1),  rl_colors.HexColor("#dbeafe")),
        ("BACKGROUND",    (2,0),(2,-1),  rl_colors.HexColor("#dbeafe")),
        ("BACKGROUND",    (4,0),(4,-1),  rl_colors.HexColor("#dbeafe")),
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
        ("TOPPADDING",    (0,0),(-1,-1), 4),
        ("BOTTOMPADDING", (0,0),(-1,-1), 4),
    ]))
    elems.append(summ_tbl)
    elems.append(Spacer(1, sp))

    # ════════════════════════════════════════════════════════════
    # 5. CBC PERFORMANCE LEVELS KEY  — full-width, clearly readable
    # ════════════════════════════════════════════════════════════
    levels = get_cbc_levels()
    n_lv   = len(levels)
    cw_lv  = [W / n_lv] * n_lv   # equal columns spanning full page width

    LVHD2 = PS("rc_lvhd2", size=8,  font="Helvetica-Bold",    align=TA_CENTER, color="#ffffff")
    LVRG2 = PS("rc_lvrg2", size=7,  font="Helvetica-Bold",    align=TA_CENTER, color="#1a1a1a")
    LVLB2 = PS("rc_lvlb2", size=6,  font="Helvetica",         align=TA_CENTER, color="#333333")
    LVPT2 = PS("rc_lvpt2", size=7,  font="Helvetica-Bold",    align=TA_CENTER, color="#1a1a1a")

    # Row 1: level code (coloured header)
    lv_r1 = [Paragraph(lv["level"], LVHD2) for lv in levels]
    # Row 2: % range
    lv_r2 = [Paragraph(f"{lv['min']}–{lv['max']}%", LVRG2) for lv in levels]
    # Row 3: short descriptor
    _lv_short = {
        "EE1": "Exceeding 1", "EE2": "Exceeding 2",
        "ME1": "Meeting 1",   "ME2": "Meeting 2",
        "AE1": "Approaching 1","AE2":"Approaching 2",
        "BE1": "Below 1",     "BE2": "Below 2",
    }
    lv_r3 = [Paragraph(_lv_short.get(lv["level"], lv["level"]), LVLB2) for lv in levels]

    if primary:
        lv_rows = [lv_r1, lv_r2, lv_r3]
        lv_row_h = [18, 16, 14]
    else:
        lv_r4 = [Paragraph(f"{lv['points']} pts", LVPT2) for lv in levels]
        lv_rows = [lv_r1, lv_r2, lv_r3, lv_r4]
        lv_row_h = [18, 16, 14, 14]

    lv_tbl = Table(lv_rows, colWidths=cw_lv, rowHeights=lv_row_h)
    lv_style = [
        ("GRID",          (0,0),(-1,-1), 0.4, rl_colors.HexColor("#cccccc")),
        ("TOPPADDING",    (0,0),(-1,-1), 2),
        ("BOTTOMPADDING", (0,0),(-1,-1), 2),
        ("LEFTPADDING",   (0,0),(-1,-1), 2),
        ("RIGHTPADDING",  (0,0),(-1,-1), 2),
        ("ALIGN",         (0,0),(-1,-1), "CENTER"),
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
    ]
    for ci, lv in enumerate(levels):
        lv_style.append(("BACKGROUND", (ci,0),(ci,0),
                          rl_colors.HexColor(cbc_color(lv["level"]))))
        lv_style.append(("TEXTCOLOR",  (ci,0),(ci,0), rl_colors.white))
    lv_tbl.setStyle(TableStyle(lv_style))
    elems.append(Paragraph(
        "<b>CBC PERFORMANCE LEVELS KEY:</b>",
        PS("rc_pk", size=8, font="Helvetica-Bold", color="#0a2540")
    ))
    elems.append(Spacer(1, sp * 0.4))
    elems.append(lv_tbl)
    elems.append(Spacer(1, sp))

    # ════════════════════════════════════════════════════════════
    # 6. TERM PROGRESS BAR CHART  (points or marks per term)
    # ════════════════════════════════════════════════════════════
    # Query ALL historical results for this learner across every term
    # so that e.g. a Term 2 report shows Term 1 + Term 2 bars side-by-side.
    _term_order = {"Term 1": 1, "Term 2": 2, "Term 3": 3}
    _bar_metric  = "AVG MARKS" if primary else "AVG POINTS"
    _bar_max     = 100 if primary else get_cbc_levels()[0]["points"]  # 8 for CBC

    # Determine which terms to include: all terms up to (and including) the
    # current report term.  If `term` is unknown, show all available terms.
    _cur_term_rank = _term_order.get(str(term).strip(), 99)

    # Pull every result for this learner from the DB (all terms, all subjects)
    _hist_conn = get_conn()
    _hist_rows = _hist_conn.execute("""
        SELECT a.term,
               r.marks,
               r.points,
               r.is_absent
        FROM results r
        JOIN assessments a ON r.assessment_id = a.id
        WHERE r.learner_id = ?
          AND a.term IS NOT NULL
    """, (lrn["id"],)).fetchall()
    _hist_conn.close()

    # Aggregate per term
    _term_pts: dict = {}   # term_label → list of metric values
    for _hr in _hist_rows:
        _t = str(_hr["term"]).strip() if _hr["term"] else ""
        if not _t or _t == "—":
            continue
        # Only include terms ≤ current report term
        if _term_order.get(_t, 99) > _cur_term_rank:
            continue
        if _hr["is_absent"]:
            continue
        _v = (_hr["marks"] or 0) if primary else (_hr["points"] or 0)
        _term_pts.setdefault(_t, []).append(_v)

    # Sort terms in chronological order
    _sorted_terms = sorted(_term_pts.keys(),
                           key=lambda t: _term_order.get(t, 99))
    _bar_vals = [round(sum(_term_pts[t]) / len(_term_pts[t]), 1)
                 for t in _sorted_terms] if _sorted_terms else []

    # Draw bar chart using ReportLab Drawing
    from reportlab.graphics.shapes import Drawing, Rect, String, Line
    from reportlab.graphics import renderPDF

    _chart_w  = float(W)
    _chart_h  = float(_bar_total)
    _pad_l    = 36.0
    _pad_r    = 12.0
    _pad_t    = 18.0
    _pad_b    = 24.0
    _plot_w   = _chart_w - _pad_l - _pad_r
    _plot_h   = _chart_h - _pad_t - _pad_b

    # Colour scheme:
    #   Previous terms → muted steel blue  (#5b8db8)
    #   Current term   → vivid accent blue  (#1d4ed8) with a highlight stripe
    _prev_bar_color    = "#5b8db8"   # muted — previous terms
    _cur_bar_color     = "#1d4ed8"   # vivid — current report term
    _cur_stripe_color  = "#60a5fa"   # lighter top stripe on current bar

    drawing = Drawing(_chart_w, _chart_h)

    # Background rect
    drawing.add(Rect(0, 0, _chart_w, _chart_h,
                     fillColor=rl_colors.HexColor("#ffffff"),
                     strokeColor=rl_colors.HexColor("#cccccc"),
                     strokeWidth=0.5))

    # Title
    _title_suffix = f" (up to {term})" if term and term != "—" and len(_sorted_terms) > 1 else ""
    drawing.add(String(_chart_w / 2, _chart_h - 10,
                        f"LEARNER PROGRESS — {_bar_metric} BY TERM{_title_suffix}",
                        fontName="Helvetica-Bold", fontSize=7,
                        fillColor=rl_colors.HexColor("#0a2540"),
                        textAnchor="middle"))

    if _sorted_terms and _bar_vals:
        n_bars   = len(_sorted_terms)
        _grp_w   = _plot_w / n_bars
        _bar_w   = _grp_w * 0.55
        _bar_gap = (_grp_w - _bar_w) / 2

        # Horizontal grid lines (4 lines at 25% intervals)
        for gi in range(5):
            gy = _pad_b + (_plot_h * gi / 4)
            drawing.add(Line(_pad_l, gy, _pad_l + _plot_w, gy,
                             strokeColor=rl_colors.HexColor("#dddddd"), strokeWidth=0.4))
            lbl_v = _bar_max * gi / 4
            drawing.add(String(_pad_l - 2, gy - 3,
                               f"{lbl_v:.0f}",
                               fontName="Helvetica", fontSize=5.5,
                               fillColor=rl_colors.HexColor("#666666"),
                               textAnchor="end"))

        for bi, (t_lbl, t_val) in enumerate(zip(_sorted_terms, _bar_vals)):
            bx      = _pad_l + bi * _grp_w + _bar_gap
            bar_h   = max(2.0, (_plot_h * min(t_val, _bar_max) / _bar_max))
            by      = _pad_b

            # Determine if this bar is the current report term
            _is_current = (t_lbl.strip() == str(term).strip())
            _fill_hex   = _cur_bar_color if _is_current else _prev_bar_color
            b_color     = rl_colors.HexColor(_fill_hex)

            # Main bar
            drawing.add(Rect(bx, by, _bar_w, bar_h,
                             fillColor=b_color,
                             strokeColor=rl_colors.HexColor("#ffffff"),
                             strokeWidth=0.5))

            # Highlight stripe at top of current-term bar (3 px tall)
            if _is_current and bar_h > 5:
                drawing.add(Rect(bx, by + bar_h - 3, _bar_w, 3,
                                 fillColor=rl_colors.HexColor(_cur_stripe_color),
                                 strokeWidth=0))

            # Value label on top of bar
            drawing.add(String(bx + _bar_w / 2, by + bar_h + 1.5,
                               f"{t_val}",
                               fontName="Helvetica-Bold", fontSize=6,
                               fillColor=rl_colors.HexColor("#0a2540"),
                               textAnchor="middle"))

            # Term label below bar — bold + accent colour for current term
            _lbl_color = "#1d4ed8" if _is_current else "#0a2540"
            _lbl_font  = "Helvetica-Bold" if _is_current else "Helvetica"
            drawing.add(String(bx + _bar_w / 2, _pad_b - 11,
                               t_lbl + (" \u2605" if _is_current else ""),
                               fontName=_lbl_font, fontSize=6,
                               fillColor=rl_colors.HexColor(_lbl_color),
                               textAnchor="middle"))

        # Y-axis line
        drawing.add(Line(_pad_l, _pad_b, _pad_l, _pad_b + _plot_h,
                         strokeColor=rl_colors.HexColor("#0a2540"), strokeWidth=0.7))
        # X-axis line
        drawing.add(Line(_pad_l, _pad_b, _pad_l + _plot_w, _pad_b,
                         strokeColor=rl_colors.HexColor("#0a2540"), strokeWidth=0.7))

        # Legend — only shown when there is more than one bar
        if n_bars > 1:
            _leg_y  = _pad_b - 20
            _sq_sz  = 5.0
            # Previous terms swatch
            drawing.add(Rect(_pad_l, _leg_y, _sq_sz, _sq_sz,
                             fillColor=rl_colors.HexColor(_prev_bar_color), strokeWidth=0))
            drawing.add(String(_pad_l + _sq_sz + 2, _leg_y + 1,
                               "Previous term(s)",
                               fontName="Helvetica", fontSize=5,
                               fillColor=rl_colors.HexColor("#555555"),
                               textAnchor="start"))
            # Current term swatch
            _leg_x2 = _pad_l + 80
            drawing.add(Rect(_leg_x2, _leg_y, _sq_sz, _sq_sz,
                             fillColor=rl_colors.HexColor(_cur_bar_color), strokeWidth=0))
            drawing.add(String(_leg_x2 + _sq_sz + 2, _leg_y + 1,
                               f"Current term ({term})",
                               fontName="Helvetica-Bold", fontSize=5,
                               fillColor=rl_colors.HexColor("#1d4ed8"),
                               textAnchor="start"))
    else:
        drawing.add(String(_chart_w / 2, _chart_h / 2,
                           "No previous term data available yet.",
                           fontName="Helvetica-Oblique", fontSize=7,
                           fillColor=rl_colors.HexColor("#888888"),
                           textAnchor="middle"))

    from reportlab.graphics.renderSVG import drawToString as _svgStr
    from reportlab.platypus import Flowable

    class _DrawingFlowable(Flowable):
        """Wrap a ReportLab Drawing as a Flowable."""
        def __init__(self, d, w, h):
            Flowable.__init__(self)
            self.d = d; self.width = w; self.height = h
        def draw(self):
            renderPDF.draw(self.d, self.canv, 0, 0)

    elems.append(Paragraph(
        "<b>TERM PROGRESS TRACKER:</b>",
        PS("rc_prog", size=8, font="Helvetica-Bold", color="#0a2540")
    ))
    elems.append(Spacer(1, sp * 0.3))
    elems.append(_DrawingFlowable(drawing, _chart_w, _chart_h))
    elems.append(Spacer(1, sp))

    # ════════════════════════════════════════════════════════════
    # 7. COMMENTS  (Class Teacher auto-generated only)
    # ════════════════════════════════════════════════════════════
    comments_data = [
        [Paragraph("<b>CLASS TEACHER'S COMMENT:</b>", CLBL),
         Paragraph(ct_comment, CVAL)],
    ]
    cmt_tbl = Table(comments_data, colWidths=[52*mm, None],
                    rowHeights=[cmt_1_h])
    cmt_tbl.setStyle(TableStyle([
        ("GRID",          (0,0),(-1,-1), 0.5, rl_colors.HexColor("#bbbbbb")),
        ("BACKGROUND",    (0,0),(0,-1),  rl_colors.HexColor("#f0f7ff")),
        ("VALIGN",        (0,0),(-1,-1), "TOP"),
        ("TOPPADDING",    (0,0),(-1,-1), 5),
        ("BOTTOMPADDING", (0,0),(-1,-1), 5),
        ("LEFTPADDING",   (0,0),(-1,-1), 6),
    ]))
    elems.append(cmt_tbl)
    elems.append(Spacer(1, sp))

    # ════════════════════════════════════════════════════════════
    # 8. CLOSING DATE + NEXT TERM OPENING DATE — always shown
    # ════════════════════════════════════════════════════════════
    scd = school_closing_date() or ""
    scd_display = (f"<font color='#b45309'><b>{scd}</b></font>"
                   if scd else "______________________")
    ntd = next_term_date() or ""
    ntd_display = (f"<font color='#dc2626'><b>{ntd}</b></font>"
                   if ntd else "______________________")
    dates_data = [[
        Paragraph(f"<b>Date of School Closing:</b>  {scd_display}", NTDS),
        Paragraph(f"<b>Date of Reporting for Next Term:</b>  {ntd_display}", NTDS),
    ]]
    dates_tbl = Table(dates_data, colWidths=[W * 0.45, W * 0.55])
    dates_tbl.setStyle(TableStyle([
        ("GRID",          (0,0),(-1,-1), 0.4, rl_colors.HexColor("#cccccc")),
        ("TOPPADDING",    (0,0),(-1,-1), 5),
        ("BOTTOMPADDING", (0,0),(-1,-1), 5),
        ("LEFTPADDING",   (0,0),(-1,-1), 6),
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
        ("BACKGROUND",    (0,0),(0,-1),  rl_colors.HexColor("#fef3c7")),
        ("BACKGROUND",    (1,0),(1,-1),  rl_colors.HexColor("#fef2f2")),
    ]))
    elems.append(dates_tbl)
    elems.append(Spacer(1, sp))

    # ════════════════════════════════════════════════════════════
    # 9. SIGNATURES — Class Teacher | DOS | Head Teacher
    # ════════════════════════════════════════════════════════════
    _ct_name  = str(lrn["teacher"] or "").strip()
    _dos_name = str(CFG.get("dos_name", "")).strip()
    _ht_name  = str(CFG.get("headteacher_name", "")).strip()

    def _sig_cell(role, name=""):
        name_line = (f"Name: <b>{name}</b>" if name
                     else "Name: ________________________")
        return Paragraph(
            f"<b>{role}</b><br/>"
            "Sign: ________________________<br/>"
            f"{name_line}",
            SIGS
        )

    sig_data = [[
        _sig_cell("Class Teacher",             _ct_name),
        _sig_cell("Director of Studies (DOS)", _dos_name),
        _sig_cell("Head Teacher",              _ht_name),
    ]]

    sig_tbl = Table(sig_data, colWidths=[W * 0.33, W * 0.34, W * 0.33])
    sig_tbl.setStyle(TableStyle([
        ("GRID",          (0,0),(-1,-1), 0.4, rl_colors.HexColor("#cccccc")),
        ("BACKGROUND",    (0,0),(-1,-1), rl_colors.HexColor("#f8faff")),
        ("TOPPADDING",    (0,0),(-1,-1), 3),
        ("BOTTOMPADDING", (0,0),(-1,-1), 3),
        ("LEFTPADDING",   (0,0),(-1,-1), 5),
        ("RIGHTPADDING",  (0,0),(-1,-1), 4),
        ("VALIGN",        (0,0),(-1,-1), "TOP"),
    ]))
    elems.append(sig_tbl)
    elems.append(Spacer(1, sp))

    # Footer is drawn directly in the bottom margin via onPage canvas callback.
    return elems


def _build_report_pdf(lrn, rows, filepath, class_position=None, class_total=None, ct_comment=None, term="", year="", primary=False):
    """Write a single learner's full-page A4 report card to filepath — strictly ONE page."""
    from reportlab.platypus import BaseDocTemplate, PageTemplate, Frame
    from reportlab.platypus.flowables import KeepInFrame
    from reportlab.lib.pagesizes import A4 as _A4

    PAGE_W, PAGE_H = _A4
    LM = RM = 12 * mm
    TM = 6 * mm
    BM = 14 * mm   # raised from 6 mm → 14 mm so the footer line (at ~10.5 mm) is never covered

    def _draw_border(canvas, doc):
        """Draw border + footer in bottom margin on every page."""
        canvas.saveState()
        canvas.setStrokeColor(rl_colors.HexColor("#0a2540"))
        canvas.setLineWidth(2)
        canvas.rect(6*mm, 6*mm, PAGE_W - 12*mm, PAGE_H - 12*mm)
        # Footer: separator at 12 mm, text at 8 mm — both inside the 6–14 mm border zone
        canvas.setLineWidth(0.8)
        canvas.setStrokeColor(rl_colors.HexColor("#0a2540"))
        canvas.line(6*mm, 12*mm, PAGE_W - 6*mm, 12*mm)
        canvas.setFont("Helvetica-Bold", 6.5)
        canvas.setFillColor(rl_colors.HexColor("#0a2540"))
        canvas.drawString(8*mm, 8*mm, school_name())
        canvas.setFont("Helvetica-Oblique", 6.5)
        canvas.drawCentredString(PAGE_W / 2, 8*mm, school_motto())
        canvas.setFont("Helvetica", 6.5)
        canvas.drawRightString(PAGE_W - 8*mm, 8*mm,
                               f"iQ School Systems   |   Generated: {datetime.now().strftime('%d/%m/%Y  %H:%M')}")
        canvas.restoreState()

    frame_w = PAGE_W - LM - RM
    frame_h = PAGE_H - TM - BM

    frame = Frame(LM, BM, frame_w, frame_h,
                  leftPadding=0, rightPadding=0,
                  topPadding=0, bottomPadding=0)
    template = PageTemplate(id="report", frames=[frame], onPage=_draw_border)
    doc = BaseDocTemplate(filepath, pagesize=_A4, pageTemplates=[template])

    elems = _report_card_elements(lrn, rows,
                                  class_position=class_position,
                                  class_total=class_total,
                                  ct_comment=ct_comment,
                                  term=term, year=year, primary=primary)

    # Wrap all elements in a KeepInFrame so they are shrunk to fit one page
    # rather than flowing onto a second page.
    kif = KeepInFrame(frame_w, frame_h, elems, mode='shrink')
    doc.build([kif])



def _lv_label(lv):
    MAP={"EE1":"Exceeding Expectation 1","EE2":"Exceeding Expectation 2",
         "ME1":"Meeting Expectation 1","ME2":"Meeting Expectation 2",
         "AE1":"Approaching Expectation 1","AE2":"Approaching Expectation 2",
         "BE1":"Below Expectation 1","BE2":"Below Expectation 2","AB":"Absent"}
    return MAP.get(lv,"—")




