def _pr_btn(parent, text, cmd, style="primary", **kw):
    """Premium HTML-style action button (red or orange gradient approximation)."""
    if style == "primary":
        bg = _PR["red_btn"]; fg = _PR["white"]; abg = _PR["red_btn_hi"]
    elif style == "secondary":
        bg = _PR["orange_btn"]; fg = _PR["white"]; abg = _PR["orange_btn_hi"]
    elif style == "ghost":
        bg = _PR["navy_border"]; fg = _PR["text_sec"]; abg = _PR["tab_hover"]
    else:
        bg = _PR["blue_accent"]; fg = _PR["white"]; abg = "#2563eb"
    b = tk.Button(parent, text=text, command=cmd,
                  bg=bg, fg=fg, activebackground=abg, activeforeground=fg,
                  font=("Segoe UI", 10, "bold"), relief="flat", cursor="hand2",
                  padx=14, pady=6, **kw)
    b.bind("<Enter>", lambda e: b.configure(bg=abg))
    b.bind("<Leave>", lambda e: b.configure(bg=bg))
    return b


def _pr_select(parent, var, values, width=22):
    """Premium styled combobox."""
    cb = ttk.Combobox(parent, textvariable=var, values=values,
                      font=("Segoe UI", 10), state="readonly", width=width)
    return cb


def _pr_entry(parent, var, width=6):
    """Premium styled entry."""
    e = tk.Entry(parent, textvariable=var, width=width,
                 bg=_PR["navy_mid"], fg=_PR["text_pri"],
                 font=("Segoe UI", 10), relief="flat",
                 insertbackground=_PR["gold_light"],
                 highlightthickness=1, highlightbackground=_PR["navy_border_hi"],
                 highlightcolor=_PR["blue_accent"])
    return e


class ReportsPage(tk.Frame):
    """
    Premium Reports page — HTML reference design ported to Tkinter.
    Top bar: brand + section badges + school name.
    Main tabs: Broadsheet | Report Cards | Marksheet | Grade Ranking | Analytics
    Sub-tabs for each main tab (matching the HTML sub-tab pill design).
    """

    def __init__(self, parent, app):
        super().__init__(parent, bg=_PR["navy"])
        self.app = app
        self._build()

    def refresh(self):
        pass   # controls reload on user action

    # ══════════════════════════════════════════════════════════
    # TOP NAVBAR  (brand · section badges · school)
    # ══════════════════════════════════════════════════════════
    def _build_topbar(self):
        bar = tk.Frame(self, bg=_PR["navy_mid"], height=44)
        bar.pack(fill="x")
        bar.pack_propagate(False)

        # Thin gold accent line on bottom of topbar
        tk.Frame(self, bg=_PR["gold"], height=1).pack(fill="x")

        left = tk.Frame(bar, bg=_PR["navy_mid"])
        left.pack(side="left", padx=12, fill="y")

        # iQ School Systems brand
        tk.Label(left, text="iQ School Systems", bg=_PR["navy_mid"], fg=_PR["gold_light"],
                 font=("Georgia", 12, "bold")).pack(side="left", padx=(0, 10))

        # Separator + "Reports" label
        tk.Frame(left, bg=_PR["navy_border"], width=1).pack(side="left", fill="y", pady=8)
        tk.Label(left, text="  Reports", bg=_PR["navy_mid"], fg=_PR["text_sec"],
                 font=("Segoe UI", 10)).pack(side="left")

        # ── Section badges ──────────────────────────────────────
        badge_frame = tk.Frame(bar, bg=_PR["navy_mid"])
        badge_frame.pack(side="left", padx=16, fill="y")

        sec = self.app.current_section
        for key, (label, bbg, bfg, bbd) in _SEC_BADGE.items():
            is_active = (key == sec)
            f = tk.Frame(badge_frame, bg=bbg,
                         highlightthickness=1, highlightbackground=bbd)
            f.pack(side="left", padx=3, pady=10)
            lbl = tk.Label(f, text=label, bg=bbg, fg=bfg,
                           font=("Segoe UI", 8, "bold"), padx=7, pady=2,
                           cursor="hand2")
            lbl.pack()
            # Clicking a badge switches section
            lbl.bind("<Button-1>", lambda e, k=key: self.app.set_section(k, "Reports"))
            if not is_active:
                # Dim non-active badges slightly
                lbl.configure(fg=_darken_hex(bfg))

        # ── School name right ────────────────────────────────────
        tk.Label(bar, text=school_name().upper(), bg=_PR["navy_mid"],
                 fg=_PR["text_sec"],
                 font=("Segoe UI", 8, "bold"), anchor="e").pack(side="right", padx=16)

    # ══════════════════════════════════════════════════════════
    # SECTION HEADER  (section icon · grade label)
    # ══════════════════════════════════════════════════════════
    def _build_sec_header(self):
        meta = SECTIONS[self.app.current_section]
        hdr = tk.Frame(self, bg=_PR["navy_card"])
        hdr.pack(fill="x")
        tk.Frame(self, bg=_PR["navy_border"], height=1).pack(fill="x")

        left = tk.Frame(hdr, bg=_PR["navy_card"])
        left.pack(side="left", padx=14, pady=10, fill="y")

        # Back button (same style as HTML .back-btn)
        back = tk.Button(left, text="← Dashboard",
                         bg=_PR["navy_card"], fg=_PR["text_sec"],
                         font=("Segoe UI", 9), relief="flat", cursor="hand2",
                         highlightthickness=1, highlightbackground=_PR["navy_border"],
                         padx=10, pady=4,
                         command=lambda: self.app.show_page("Dashboard"))
        back.pack(side="left", padx=(0, 14))
        back.bind("<Enter>", lambda e: back.configure(bg=_PR["tab_hover"], fg=_PR["text_pri"]))
        back.bind("<Leave>", lambda e: back.configure(bg=_PR["navy_card"], fg=_PR["text_sec"]))

        # Title separator
        tk.Label(left, text=meta["icon"], bg=_PR["navy_card"], fg=meta["accent"],
                 font=("Segoe UI", 16)).pack(side="left")
        tk.Label(left, text=f"  {meta['label']}", bg=_PR["navy_card"], fg=_PR["gold_light"],
                 font=("Georgia", 14, "bold")).pack(side="left")
        tk.Label(left, text="  ›", bg=_PR["navy_card"], fg=_PR["text_dim"],
                 font=("Segoe UI", 11)).pack(side="left")
        tk.Label(left, text=f"  {meta['sub']}", bg=_PR["navy_card"], fg=_PR["text_sec"],
                 font=("Segoe UI", 10)).pack(side="left")

    # ══════════════════════════════════════════════════════════
    # MAIN TABS  (Broadsheet | Report Cards | Marksheet | Grade Ranking | Analytics)
    # ══════════════════════════════════════════════════════════
    def _build_main_tabs(self):
        # Tab bar background
        tab_bar = tk.Frame(self, bg=_PR["navy_mid"])
        tab_bar.pack(fill="x")
        tk.Frame(self, bg=_PR["navy_border"], height=1).pack(fill="x")

        # Content area
        self._content_area = tk.Frame(self, bg=_PR["navy"])
        self._content_area.pack(fill="both", expand=True)

        TABS = [
            ("📋", "Broadsheet",    self._build_broadsheet_panel),
            ("📄", "Report Cards",  self._build_report_cards_panel),
            ("📝", "Marksheet",     self._build_marksheet_panel),
            ("🏆", "Grade Ranking", self._build_grade_ranking_panel),
            ("📈", "Analytics",     self._build_analytics_panel),
        ]

        self._tab_frames = {}   # name -> content Frame
        self._tab_btns   = {}   # name -> Button
        self._active_tab = TABS[0][1]

        for ico, name, builder in TABS:
            btn = tk.Button(tab_bar,
                            text=f"{ico}  {name}",
                            bg=_PR["navy_mid"], fg=_PR["text_sec"],
                            font=("Segoe UI", 10, "bold"),
                            relief="flat", cursor="hand2",
                            padx=16, pady=10, bd=0,
                            activebackground=_PR["tab_hover"],
                            activeforeground=_PR["text_pri"])
            btn.pack(side="left")
            self._tab_btns[name] = btn

            # Build the frame (lazy)
            frm = tk.Frame(self._content_area, bg=_PR["navy"])
            self._tab_frames[name] = frm
            builder(frm)   # populate immediately

            btn.configure(command=lambda n=name: self._switch_main_tab(n))
            btn.bind("<Enter>", lambda e, b=btn, n=name: (
                b.configure(bg=_PR["tab_hover"], fg=_PR["text_pri"])
                if self._active_tab != n else None))
            btn.bind("<Leave>", lambda e, b=btn, n=name: (
                b.configure(bg=_PR["navy_mid"], fg=_PR["text_sec"])
                if self._active_tab != n else None))

        self._switch_main_tab(self._active_tab)

    def _switch_main_tab(self, name):
        # Hide all frames
        for n, frm in self._tab_frames.items():
            frm.place_forget()
        # Show selected
        self._tab_frames[name].place(relwidth=1, relheight=1)
        self._active_tab = name
        # Style tab buttons
        for n, btn in self._tab_btns.items():
            if n == name:
                btn.configure(bg=_PR["navy"], fg=_PR["gold_light"],
                               font=("Segoe UI", 10, "bold"),
                               relief="flat")
                # Draw bottom-border indicator via configure pady trick
                btn.configure(pady=8)
            else:
                btn.configure(bg=_PR["navy_mid"], fg=_PR["text_sec"],
                               font=("Segoe UI", 10),
                               relief="flat", pady=10)

    # ══════════════════════════════════════════════════════════
    # CONTROL PANEL HELPER  (the navy card row with controls)
    # ══════════════════════════════════════════════════════════
    def _ctrl_panel(self, parent):
        """Returns a styled navy card control panel frame."""
        outer = tk.Frame(parent, bg=_PR["gold"], pady=1)  # gold top border
        outer.pack(fill="x", padx=16, pady=(16, 0))
        panel = tk.Frame(outer, bg=_PR["navy_card"], padx=16, pady=12)
        panel.pack(fill="x")
        return panel

    def _ctrl_group(self, panel, label):
        """Returns (group_frame) after packing a label in it."""
        g = tk.Frame(panel, bg=_PR["navy_card"])
        g.pack(side="left", padx=(0, 16))
        tk.Label(g, text=label.upper(), bg=_PR["navy_card"], fg=_PR["text_dim"],
                 font=("Segoe UI", 8, "bold")).pack(anchor="w")
        return g

    def _divider(self, panel):
        tk.Frame(panel, bg=_PR["navy_border"], width=1).pack(side="left", fill="y", pady=4, padx=6)

    # ══════════════════════════════════════════════════════════
    # STAT CARDS (mini summary row)
    # ══════════════════════════════════════════════════════════
    def _stat_row(self, parent, stats):
        """
        stats: list of (label, value, sub, accent_color)
        """
        row = tk.Frame(parent, bg=_PR["navy"])
        row.pack(fill="x", padx=16, pady=(12, 4))
        for label, value, sub, accent in stats:
            card = tk.Frame(row, bg=_PR["navy_card"],
                            highlightthickness=1, highlightbackground=_PR["navy_border"])
            card.pack(side="left", padx=(0, 10), pady=2, fill="x", expand=True)
            # Accent stripe on top
            tk.Frame(card, bg=accent, height=3).pack(fill="x")
            tk.Label(card, text=label, bg=_PR["navy_card"], fg=_PR["text_sec"],
                     font=("Segoe UI", 8, "bold")).pack(anchor="w", padx=12, pady=(8, 0))
            tk.Label(card, text=str(value), bg=_PR["navy_card"], fg=_PR["text_pri"],
                     font=("Segoe UI", 22, "bold")).pack(anchor="w", padx=12)
            tk.Label(card, text=sub, bg=_PR["navy_card"], fg=_PR["text_dim"],
                     font=("Segoe UI", 8)).pack(anchor="w", padx=12, pady=(0, 10))

    # ══════════════════════════════════════════════════════════
    # TAB 1: BROADSHEET
    # ══════════════════════════════════════════════════════════
    def _build_broadsheet_panel(self, frm):
        classes = section_classes(self.app.current_section)

        # ── Control panel ──────────────────────────────────────
        ctrl = self._ctrl_panel(frm)

        g1 = self._ctrl_group(ctrl, "Class")
        self.bs_cls = tk.StringVar()
        _pr_select(g1, self.bs_cls, classes, width=28).pack(anchor="w")

        self._divider(ctrl)

        g2 = self._ctrl_group(ctrl, "Term")
        self.bs_term = tk.StringVar(value="Term 1")
        _pr_select(g2, self.bs_term, ["Term 1", "Term 2", "Term 3"], width=10).pack(anchor="w")

        g3 = self._ctrl_group(ctrl, "Year")
        self.bs_year = tk.StringVar(value=str(datetime.now().year))
        _pr_entry(g3, self.bs_year, 6).pack(anchor="w")

        # Rank method (Junior only)
        self._bs_rank_var = tk.StringVar(value="Points")
        if self.app.current_section == "junior":
            self._divider(ctrl)
            g4 = self._ctrl_group(ctrl, "Rank by")
            _pr_select(g4, self._bs_rank_var, ["Points", "Total Marks"], width=14).pack(anchor="w")

        # Action buttons (right-aligned)
        act = tk.Frame(ctrl, bg=_PR["navy_card"])
        act.pack(side="right", padx=(12, 0))
        _pr_btn(act, "▶  Generate",  self._gen_broadsheet, style="ghost").pack(side="left", padx=4)
        _pr_btn(act, "📄  PDF",      self._bs_pdf,         style="primary").pack(side="left", padx=4)
        _pr_btn(act, "⬇  CSV",      self._bs_csv,         style="ghost").pack(side="left", padx=4)

        # ── Stat cards ─────────────────────────────────────────
        self._bs_stat_frame = tk.Frame(frm, bg=_PR["navy"])
        self._bs_stat_frame.pack(fill="x", padx=16, pady=(10, 4))

        # ── Section label ───────────────────────────────────────
        sh = tk.Frame(frm, bg=_PR["navy"])
        sh.pack(fill="x", padx=16, pady=(4, 6))
        self._bs_sec_lbl = tk.Label(sh, text="Broadsheet · Select a class and generate",
                                     bg=_PR["navy"], fg=_PR["text_sec"],
                                     font=("Segoe UI", 11, "bold"), anchor="w")
        self._bs_sec_lbl.pack(side="left")

        # ── Data frame ─────────────────────────────────────────
        self.bs_frame = tk.Frame(frm, bg=_PR["navy"])
        self.bs_frame.pack(fill="both", expand=True, padx=16, pady=(0, 12))

    def _gen_broadsheet(self):
        for w in self.bs_frame.winfo_children(): w.destroy()
        for w in self._bs_stat_frame.winfo_children(): w.destroy()
        cls_v = self.bs_cls.get()
        if not cls_v:
            messagebox.showwarning("Select", "Select a class first."); return
        cls_id = int(cls_v.split("|")[0])
        term   = self.bs_term.get()
        year   = self.bs_year.get().strip()

        conn = get_conn()
        grade_row  = conn.execute("SELECT grade FROM classes WHERE id=?", (cls_id,)).fetchone()
        grade_str  = grade_row["grade"] if grade_row else ""
        _use_marks = is_primary_grade(grade_str)
        if self.app.current_section == "junior" and self._bs_rank_var.get() == "Total Marks":
            _use_marks = True
        subjects   = get_broadsheet_subjects(grade_str, conn)
        learners   = conn.execute(
            "SELECT id,admission_no,UPPER(first_name)||' '||UPPER(last_name) AS name "
            "FROM learners WHERE class_id=? AND status='Active' "
            "ORDER BY first_name,last_name", (cls_id,)).fetchall()

        if not learners:
            tk.Label(self.bs_frame, text="⚠  No active learners found in this class.",
                     bg=_PR["navy"], fg=_PR["gold_light"], font=("Segoe UI", 11), pady=30).pack()
            conn.close(); return
        if not subjects:
            tk.Label(self.bs_frame, text="⚠  No subjects found for this grade.",
                     bg=_PR["navy"], fg=_PR["gold_light"], font=("Segoe UI", 11), pady=30).pack()
            conn.close(); return

        rows = []
        for lrn in learners:
            row = [lrn["admission_no"], lrn["name"]]
            total = 0; n_present = 0
            for subj in subjects:
                is_comp = subj["is_composite"] if "is_composite" in subj.keys() else 0
                if is_comp:
                    sub_rows = get_sub_subjects(subj["id"], conn)
                    if sub_rows:
                        sub_marks = 0.0; sub_max_tot = 0.0; any_absent = False; has_data = False
                        for sr in sub_rows:
                            sres = conn.execute(
                                "SELECT r.marks,r.points,r.is_absent FROM results r "
                                "JOIN assessments a ON r.assessment_id=a.id "
                                "WHERE r.learner_id=? AND a.subject_id=? AND a.class_id=? AND a.term=? "
                                "ORDER BY r.id DESC LIMIT 1",
                                (lrn["id"], sr["id"], cls_id, term)).fetchone()
                            if sres is None:
                                sres = conn.execute(
                                    "SELECT r.marks,r.points,r.is_absent FROM results r "
                                    "JOIN assessments a ON r.assessment_id=a.id "
                                    "WHERE r.learner_id=? AND a.subject_id=? AND a.class_id=? "
                                    "ORDER BY r.id DESC LIMIT 1",
                                    (lrn["id"], sr["id"], cls_id)).fetchone()
                            if sres:
                                has_data = True
                                if sres["is_absent"]: any_absent = True
                                else:
                                    sub_marks += (sres["marks"] or 0)
                                    sub_max_tot += (sr["max_marks"] or 100)
                        if not has_data: row.append("—"); continue
                        if any_absent and sub_marks == 0: row.append("ABS"); continue
                        if _use_marks:
                            val_show = round(sub_marks, 1)
                        else:
                            _, _, val_show = get_cbc_level(sub_marks, sub_max_tot) if sub_max_tot else (None, None, 0)
                        val_show = val_show or 0
                        row.append(str(int(val_show)) if val_show == int(val_show) else str(val_show))
                        total += val_show; n_present += 1; continue
                res = conn.execute(
                    "SELECT r.marks,r.points,r.is_absent FROM results r "
                    "JOIN assessments a ON r.assessment_id=a.id "
                    "WHERE r.learner_id=? AND a.subject_id=? AND a.class_id=? AND a.term=? "
                    "ORDER BY r.id DESC LIMIT 1",
                    (lrn["id"], subj["id"], cls_id, term)).fetchone()
                if res is None:
                    res = conn.execute(
                        "SELECT r.marks,r.points,r.is_absent FROM results r "
                        "JOIN assessments a ON r.assessment_id=a.id "
                        "WHERE r.learner_id=? AND a.subject_id=? AND a.class_id=? "
                        "ORDER BY r.id DESC LIMIT 1",
                        (lrn["id"], subj["id"], cls_id)).fetchone()
                if res:
                    if res["is_absent"]: row.append("ABS")
                    else:
                        val_show = (res["marks"] if _use_marks else res["points"]) or 0
                        row.append(str(int(val_show)) if val_show == int(val_show) else str(val_show))
                        total += val_show; n_present += 1
                else: row.append("—")
            avg = round(total / n_present, 1) if n_present else 0
            row += [str(int(total) if total == int(total) else total), str(avg)]
            rows.append(row)

        conn.close()
        rows.sort(key=lambda r: float(r[-2]) if str(r[-2]).replace(".", "", 1).isdigit() else -1, reverse=True)
        for i, row in enumerate(rows): row.insert(0, str(i + 1))

        self.bs_data = rows; self.bs_subjects = subjects; self.bs_use_marks = _use_marks
        self._bs_cls_id = cls_id

        # ── Stat cards ─────────────────────────────────────────
        cls_name = cls_v.split("|", 1)[1].strip() if "|" in cls_v else cls_v
        n_lrn = len(rows)
        # Compute avg
        try:
            avgs = [float(r[-1]) for r in rows if str(r[-1]).replace(".", "", 1).isdigit()]
            cls_avg = round(sum(avgs) / len(avgs), 1) if avgs else "—"
        except Exception:
            cls_avg = "—"
        # EE count (points >= 7) or marks >= 70
        if _use_marks:
            ee_count = sum(1 for r in rows if str(r[-1]).replace(".", "", 1).isdigit() and float(r[-1]) >= 70)
        else:
            ee_count = sum(1 for r in rows if str(r[-1]).replace(".", "", 1).isdigit() and float(r[-1]) >= 7)

        self._stat_row(self._bs_stat_frame, [
            ("Total Learners",  n_lrn,    f"Active · {term}",         _PR["blue_accent"]),
            ("Class Average",   cls_avg,  f"{'Marks' if _use_marks else 'Points'} · {term}", _PR["gold"]),
            ("Top Performers",  ee_count, "EE/High achievers",         _PR["green_badge"]),
            ("Subjects",        len(subjects), "Assessed subjects",    _PR["purple"]),
        ])

        # ── Broadsheet table ────────────────────────────────────
        val_lbl = "MKS" if _use_marks else "PTS"
        cols    = ["RANK", "ADM NO", "NAME"] + [f"{s['code']}\n({val_lbl})" for s in subjects] + ["TOTAL", "AVG"]
        widths  = [48, 72, 180] + [64] * len(subjects) + [80, 64]
        tbl = StyledTable(self.bs_frame, cols, col_widths=widths, bg=_PR["navy"])
        tbl.pack(fill="both", expand=True)
        for row in rows:
            tbl.insert(row)

        self._bs_sec_lbl.configure(
            text=f"Broadsheet  ·  {cls_name}  ·  {term}  ·  {year}   ({n_lrn} learners)")

    def _bs_pdf(self):
        if not hasattr(self, "bs_data") or not self.bs_data:
            messagebox.showwarning("Empty", "Generate broadsheet first."); return
        path = filedialog.asksaveasfilename(defaultextension=".pdf",
                                            filetypes=[("PDF", "*.pdf")], initialfile="Broadsheet.pdf")
        if not path: return
        if not REPORTLAB_OK:
            messagebox.showerror("Missing Library", "reportlab is required for PDF export."); return
        subjects  = self.bs_subjects
        n_subj    = len(subjects)
        _use_marks = self.bs_use_marks

        def _numeric(v):
            try: return float(v)
            except (ValueError, TypeError): return None

        subj_vals  = [[] for _ in subjects]
        for row in self.bs_data:
            for si in range(n_subj):
                v = _numeric(row[3 + si])
                if v is not None: subj_vals[si].append(v)
        subj_means = [round(sum(vs) / len(vs), 1) if vs else "—" for vs in subj_vals]
        subj_maxs  = [max(vs, default="—") for vs in subj_vals]
        subj_mins  = [min(vs, default="—") for vs in subj_vals]
        ranked_means = sorted(
            [(i, m) for i, m in enumerate(subj_means) if isinstance(m, float)],
            key=lambda x: -x[1])
        subj_pos = ["—"] * n_subj
        for rank, (si, _) in enumerate(ranked_means, 1):
            subj_pos[si] = str(rank)
        n_data_rows_bs   = len(self.bs_data)
        analytics_start_bs = n_data_rows_bs + 1
        val_lbl  = "Marks" if _use_marks else "Points"
        tot_lbl  = f"Total {val_lbl}"; avg_lbl = f"Avg {val_lbl}"
        hdr_row  = (["RANK", "ADM NO", "NAME"] +
                    [f"{s['code']}\n({val_lbl})" for s in subjects] +
                    [tot_lbl, avg_lbl])
        mean_row = ["—", "—", "SUBJECT MEAN"] + [str(m) for m in subj_means] + ["—", "—"]
        high_row = ["—", "—", "HIGHEST SCORE"] + [str(m) for m in subj_maxs]  + ["—", "—"]
        low_row  = ["—", "—", "LOWEST SCORE"]  + [str(m) for m in subj_mins]  + ["—", "—"]
        pos_row  = ["—", "—", "SUBJECT POSITION"] + subj_pos                  + ["—", "—"]
        data     = [hdr_row] + self.bs_data + [mean_row, high_row, low_row, pos_row]

        _A4_W, _A4_H = A4
        _LM = 10 * mm; _RM = 10 * mm; _USABLE = _A4_W - _LM - _RM

        import tkinter.font as tkfont
        hdr_font = tkfont.Font(family="Helvetica", size=8, weight="bold")
        font     = tkfont.Font(family="Helvetica", size=8)
        _FS = 8; _PAD = 4

        def _sw(text, f, size):
            try: return f.measure(text)
            except Exception: return len(text) * size * 0.6

        def _col_w(ci, all_rows):
            max_w = 0
            for ri, row_d in enumerate(all_rows):
                if ci >= len(row_d): continue
                cell = str(row_d[ci]) if row_d[ci] is not None else ""
                f = hdr_font if ri == 0 else font
                for line in cell.split("\n"):
                    max_w = max(max_w, _sw(line, f, _FS))
            return max_w + _PAD * 2

        _all_rows = data
        _raw_cw   = [_col_w(ci, _all_rows) for ci in range(len(_all_rows[0]))]
        _raw_total = sum(_raw_cw)
        if _raw_total > 0:
            _scale = _USABLE / max(_raw_total, _USABLE)
            cw = [max(6 * mm, w * _scale) for w in _raw_cw]
            _adj = _USABLE / sum(cw)
            cw = [w * _adj for w in cw]
        else:
            _n_subj2 = max(n_subj, 1)
            _subj_w  = max(8 * mm, (_USABLE - (10 + 18 + 48 + 14 + 12) * mm) / _n_subj2)
            cw = [10 * mm, 18 * mm, 48 * mm] + [_subj_w] * n_subj + [14 * mm, 12 * mm]

        _bs_gen_date_s = datetime.now().strftime("%d %b %Y  %H:%M")
        doc = SimpleDocTemplate(path, pagesize=A4, topMargin=10 * mm, bottomMargin=22 * mm,
                                leftMargin=_LM, rightMargin=_RM)

        def _bs_footer(canvas_obj, doc_obj):
            canvas_obj.saveState()
            canvas_obj.setFont("Helvetica", 7)
            canvas_obj.setFillColor(rl_colors.HexColor("#555555"))
            canvas_obj.drawCentredString(
                A4[0] / 2, 10 * mm,
                f"iQ School Systems   |   Generated: {_bs_gen_date_s}   |   Page {doc_obj.page}")
            canvas_obj.restoreState()

        logo = get_logo_image(18, 18)
        cls_row = get_conn().execute("SELECT name FROM classes WHERE id=?", (self._bs_cls_id,)).fetchone()
        _hdr_style = ParagraphStyle("bh", fontSize=12, alignment=TA_CENTER,
                                    textColor=rl_colors.white,
                                    fontName="Helvetica-Bold", leading=18)
        hdr = [[logo or "",
                Paragraph(f"{school_name().upper()}<br/>"
                          f"<font size=9>CLASS BROADSHEET  |  CLASS: {cls_row['name'].upper() if cls_row else '—'}  |  "
                          f"{self.bs_term.get().upper()}  |  {self.bs_year.get()}</font>",
                          _hdr_style),
                ""]]
        ht = Table(hdr, colWidths=[20 * mm, None, 20 * mm])
        ht.setStyle(TableStyle([
            ("BACKGROUND", (0, 0), (-1, -1), rl_colors.HexColor("#0d1b2a")),
            ("TEXTCOLOR",  (0, 0), (-1, -1), rl_colors.white),
            ("FONTNAME",   (0, 0), (-1, -1), "Helvetica-Bold"),
            ("VALIGN",     (0, 0), (-1, -1), "MIDDLE"),
            ("TOPPADDING",    (0, 0), (-1, -1), 8),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 8),
        ]))
        ts_bs = [
            ("FONTNAME",   (0, 0), (-1, 0), "Helvetica-Bold"),
            ("FONTSIZE",   (0, 0), (-1, -1), 7),
            ("BACKGROUND", (0, 0), (-1, 0), rl_colors.HexColor("#0d1b2a")),
            ("TEXTCOLOR",  (0, 0), (-1, 0), rl_colors.white),
            ("ALIGN",      (0, 0), (-1, -1), "CENTER"),
            ("ALIGN",      (2, 1), (2, -1), "LEFT"),
            ("GRID",       (0, 0), (-1, -1), 0.3, rl_colors.grey),
            ("TOPPADDING",    (0, 0), (-1, -1), 3),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 3),
            ("FONTNAME",   (0, 1), (-1, -1), "Helvetica"),
            ("BACKGROUND", (0, analytics_start_bs), (-1, analytics_start_bs), rl_colors.HexColor("#d0eaff")),
            ("FONTNAME",   (0, analytics_start_bs), (-1, analytics_start_bs), "Helvetica-Bold"),
            ("BACKGROUND", (0, analytics_start_bs + 1), (-1, analytics_start_bs + 1), rl_colors.HexColor("#e8f4f8")),
            ("FONTNAME",   (0, analytics_start_bs + 1), (-1, analytics_start_bs + 1), "Helvetica-Bold"),
            ("BACKGROUND", (0, analytics_start_bs + 2), (-1, analytics_start_bs + 2), rl_colors.HexColor("#fff3cd")),
            ("FONTNAME",   (0, analytics_start_bs + 2), (-1, analytics_start_bs + 2), "Helvetica-Bold"),
            ("BACKGROUND", (0, analytics_start_bs + 3), (-1, analytics_start_bs + 3), rl_colors.HexColor("#e8ffe8")),
            ("FONTNAME",   (0, analytics_start_bs + 3), (-1, analytics_start_bs + 3), "Helvetica-Bold"),
        ]
        for ri in range(n_data_rows_bs):
            bg = rl_colors.white if ri % 2 == 0 else rl_colors.HexColor("#f0f7ff")
            ts_bs.append(("BACKGROUND", (0, ri + 1), (-1, ri + 1), bg))
        t = Table(data, colWidths=cw, repeatRows=1)
        t.setStyle(TableStyle(ts_bs))
        note = Paragraph(
            "<font size=7><b>Analytics rows:</b> SUBJECT MEAN = class average per subject | "
            "HIGHEST/LOWEST SCORE = best/worst mark | SUBJECT POSITION = rank by mean (1 = top).</font>",
            ParagraphStyle("note", fontSize=7, textColor=rl_colors.HexColor("#444444")))
        _bs_numeric_means = [(subjects[si]["code"], subj_means[si])
                              for si in range(n_subj) if isinstance(subj_means[si], (int, float))]
        _bs_elems = [ht, Spacer(1, 3 * mm), t, Spacer(1, 3 * mm), note]
        if _bs_numeric_means:
            _bs_elems += [Spacer(1, 5 * mm),
                           Paragraph("<font size=7 color='#0d1b2a'><b>SUBJECT MEAN BAR CHART</b></font>",
                                     ParagraphStyle("barlbl2", fontSize=7, spaceAfter=2)),
                           _make_subj_mean_bar_chart(_bs_numeric_means, _USABLE)]
        try:
            doc.build(_bs_elems, onFirstPage=_bs_footer, onLaterPages=_bs_footer)
            _cls_name_rp = get_conn().execute("SELECT name FROM classes WHERE id=?", (self._bs_cls_id,)).fetchone()
            _cls_name_rp = _cls_name_rp["name"] if _cls_name_rp else "class"
            _broadsheet_pdf_saved_dialog(self, path, _cls_name_rp, self.bs_term.get(), self.bs_year.get())
        except Exception as e:
            messagebox.showerror("Error", str(e))

    def _bs_csv(self):
        if not hasattr(self, "bs_data") or not self.bs_data:
            messagebox.showwarning("Empty", "Generate broadsheet first."); return
        path = filedialog.asksaveasfilename(defaultextension=".csv",
                                            filetypes=[("CSV", "*.csv")], initialfile="Broadsheet.csv")
        if not path: return
        subjects   = self.bs_subjects
        _use_marks = self.bs_use_marks
        val_lbl    = "Marks" if _use_marks else "Points"
        hdr        = ["RANK", "ADM NO", "NAME"] + [f"{s['code']} ({val_lbl})" for s in subjects] + ["Total", "Average"]
        with open(path, "w", newline="") as f:
            w = csv.writer(f); w.writerow(hdr); w.writerows(self.bs_data)
        messagebox.showinfo("Exported", f"Exported to:\n{path}")

