    def _rc_load_learners(self):
        cls_v = self.rc_cls.get()
        if not cls_v:
            messagebox.showwarning("Select", "Select a class first."); return
        for w in self._rc_list_inner.winfo_children(): w.destroy()
        for w in self._rc_stat_frame.winfo_children(): w.destroy()

        cls_id = int(cls_v.split("|")[0])
        term   = self.rc_term.get()
        conn   = get_conn()
        grade_row  = conn.execute("SELECT grade FROM classes WHERE id=?", (cls_id,)).fetchone()
        grade_str  = grade_row["grade"] if grade_row else ""
        _use_marks = is_primary_grade(grade_str)
        subjects   = get_broadsheet_subjects(grade_str, conn)
        learners   = conn.execute(
            "SELECT id,admission_no,UPPER(first_name)||' '||UPPER(last_name) AS name "
            "FROM learners WHERE class_id=? AND status='Active' "
            "ORDER BY first_name,last_name", (cls_id,)).fetchall()
        conn.close()

        if not learners:
            tk.Label(self._rc_list_inner, text="⚠  No active learners.",
                     bg=_PR["navy"], fg=_PR["gold_light"], font=("Segoe UI", 11), pady=20).pack()
            return

        cls_name = cls_v.split("|", 1)[1].strip() if "|" in cls_v else cls_v
        self._rc_sec_lbl.configure(text=f"Learner Report Cards  ·  {cls_name}  ·  {term}")

        # Stat summary
        self._stat_row(self._rc_stat_frame, [
            ("Total Learners", len(learners), f"Active · {term}", _PR["blue_accent"]),
            ("Subjects",       len(subjects), "Assessed subjects",  _PR["purple"]),
            ("Reports Ready",  len(learners), "All cards generated", _PR["green_badge"]),
        ])

        # Learner cards row-by-row
        BADGE_COLORS = {1: _PR["gold_light"], 2: "#94a3b8", 3: "#cd7f32"}
        for i, lrn in enumerate(learners):
            rank = i + 1
            card = tk.Frame(self._rc_list_inner, bg=_PR["navy_card"],
                            highlightthickness=1, highlightbackground=_PR["navy_border"],
                            cursor="hand2")
            card.pack(fill="x", pady=3)

            # Accent left stripe
            accent_color = BADGE_COLORS.get(rank, _PR["blue_accent"])
            tk.Frame(card, bg=accent_color, width=4).pack(side="left", fill="y")

            inner = tk.Frame(card, bg=_PR["navy_card"])
            inner.pack(side="left", fill="x", expand=True, padx=12, pady=8)

            top_row = tk.Frame(inner, bg=_PR["navy_card"])
            top_row.pack(fill="x")
            tk.Label(top_row, text=lrn["admission_no"], bg=_PR["navy_card"],
                     fg=_PR["text_dim"], font=("Segoe UI", 9)).pack(side="left")
            rank_lbl_text = f"#{rank}"
            tk.Label(top_row, text=rank_lbl_text, bg=_PR["navy_card"],
                     fg=accent_color, font=("Segoe UI", 9, "bold")).pack(side="right")

            tk.Label(inner, text=lrn["name"], bg=_PR["navy_card"],
                     fg=_PR["text_pri"], font=("Segoe UI", 11, "bold"), anchor="w").pack(anchor="w")

            # Action buttons
            btn_row = tk.Frame(card, bg=_PR["navy_card"])
            btn_row.pack(side="right", padx=12)
            _pr_btn(btn_row, "📋  Report Card",
                    lambda lid=lrn["id"], lname=lrn["name"]: self._single_rc(lid, lname),
                    style="ghost").pack(side="left", padx=4)

    def _single_rc(self, lrn_id, lrn_name):
        cls_v = self.rc_cls.get()
        if not cls_v: return
        cls_id = int(cls_v.split("|")[0])
        term   = self.rc_term.get()
        year   = self.rc_year.get().strip()
        if not REPORTLAB_OK:
            messagebox.showerror("Missing Library", "reportlab is required."); return
        path = filedialog.asksaveasfilename(
            defaultextension=".pdf", filetypes=[("PDF", "*.pdf")],
            initialfile=f"ReportCard_{lrn_name.replace(' ', '_')}.pdf")
        if not path: return

        conn = get_conn()
        lrn  = conn.execute("SELECT * FROM learners WHERE id=?", (lrn_id,)).fetchone()
        grade_row  = conn.execute("SELECT grade FROM classes WHERE id=?", (cls_id,)).fetchone()
        grade_str  = grade_row["grade"] if grade_row else ""
        _primary   = is_primary_grade(grade_str)
        rows = conn.execute(
            "SELECT s.name,s.code,r.marks,r.points,r.performance_level,r.is_absent,"
            "a.max_marks,a.term,s.sort_order "
            "FROM results r JOIN assessments a ON r.assessment_id=a.id "
            "JOIN subjects s ON a.subject_id=s.id "
            "WHERE r.learner_id=? AND a.class_id=? AND a.term=? "
            "ORDER BY s.sort_order,s.name",
            (lrn_id, cls_id, term)).fetchall()
        # class position
        stream_rank_data = conn.execute(
            "SELECT r.learner_id,SUM(r.points) AS tot FROM results r "
            "JOIN assessments a ON r.assessment_id=a.id "
            "JOIN learners l ON r.learner_id=l.id "
            "WHERE a.class_id=? AND a.term=? GROUP BY r.learner_id ORDER BY tot DESC",
            (cls_id, term)).fetchall()
        stream_total = len(stream_rank_data)
        # Standard competition ranking for stream position (ties share same rank)
        _sp_rank = 1
        stream_pos = None
        for _sp_i, _sp_row in enumerate(stream_rank_data):
            if _sp_i > 0 and stream_rank_data[_sp_i]["tot"] < stream_rank_data[_sp_i - 1]["tot"]:
                _sp_rank = _sp_i + 1
            if _sp_row["learner_id"] == lrn_id:
                stream_pos = _sp_rank
                break
        conn.close()

        if not rows:
            messagebox.showwarning("No Data", "No results found for this learner."); return

        from reportlab.platypus import BaseDocTemplate, PageTemplate, Frame, KeepInFrame
        _A4 = A4; PAGE_W, PAGE_H = _A4
        LM = 15 * mm; RM = 15 * mm; TM = 15 * mm; BM = 15 * mm
        frame_w = PAGE_W - LM - RM; frame_h = PAGE_H - TM - BM
        elems = _report_card_elements(lrn, rows,
                                      class_position=stream_pos, class_total=stream_total,
                                      term=term, year=year, primary=_primary)
        kif  = KeepInFrame(frame_w, frame_h, elems, mode="shrink")

        def _border(canvas, doc):
            canvas.saveState()
            canvas.setStrokeColor(rl_colors.HexColor("#0a2540"))
            canvas.setLineWidth(2)
            canvas.rect(6 * mm, 6 * mm, PAGE_W - 12 * mm, PAGE_H - 12 * mm)
            canvas.restoreState()

        frame  = Frame(LM, BM, frame_w, frame_h, leftPadding=0, rightPadding=0,
                       topPadding=0, bottomPadding=0)
        tmpl   = PageTemplate(id="rpt", frames=[frame], onPage=_border)
        doc    = BaseDocTemplate(path, pagesize=_A4, pageTemplates=[tmpl])
        try:
            doc.build([kif])
            messagebox.showinfo("PDF Saved", f"Report card saved:\n{path}")
        except Exception as e:
            messagebox.showerror("PDF Error", str(e))

    def _export_all_rc(self):
        cls_v = self.rc_cls.get()
        if not cls_v:
            messagebox.showwarning("Select", "Select a class first."); return
        cls_id = int(cls_v.split("|")[0])
        term   = self.rc_term.get()
        year   = self.rc_year.get().strip()
        if not REPORTLAB_OK:
            messagebox.showerror("Missing Library", "reportlab is required."); return

        conn = get_conn()
        learners_all = conn.execute(
            "SELECT id FROM learners WHERE class_id=? AND status='Active' "
            "ORDER BY first_name,last_name", (cls_id,)).fetchall()
        if not learners_all:
            conn.close(); messagebox.showwarning("Empty", "No learners."); return

        cls_info  = conn.execute("SELECT grade,name FROM classes WHERE id=?", (cls_id,)).fetchone()
        grade_str = cls_info["grade"] if cls_info else ""
        _primary  = is_primary_grade(grade_str)

        # Rank learners
        rank_data = conn.execute(
            "SELECT r.learner_id,"
            "SUM(CASE WHEN r.is_absent=0 THEN COALESCE(r.marks,0) END) AS tot_m,"
            "SUM(CASE WHEN r.is_absent=0 THEN COALESCE(r.points,0) END) AS tot_p "
            "FROM results r JOIN assessments a ON r.assessment_id=a.id "
            "WHERE a.class_id=? AND a.term=? GROUP BY r.learner_id "
            "ORDER BY CASE WHEN ? THEN tot_m ELSE tot_p END DESC",
            (cls_id, term, _primary)).fetchall()
        # Standard competition ranking: tied learners share the same rank
        rank_map = {}
        _rm_rank = 1
        for _rm_i, _rm_row in enumerate(rank_data):
            if _rm_i > 0 and rank_data[_rm_i]["tot_m" if _primary else "tot_p"] <                              rank_data[_rm_i - 1]["tot_m" if _primary else "tot_p"]:
                _rm_rank = _rm_i + 1
            rank_map[_rm_row["learner_id"]] = _rm_rank
        stream_total = len(rank_data)

        learner_list = [dict(lrn) for lrn in learners_all]
        learner_list.sort(key=lambda x: rank_map.get(x["id"], 9999))

        path = filedialog.asksaveasfilename(
            defaultextension=".pdf", filetypes=[("PDF", "*.pdf")],
            initialfile=f"ReportCards_{cls_info['name'] if cls_info else 'Class'}_{term}.pdf")
        if not path:
            conn.close(); return

        from reportlab.platypus import BaseDocTemplate, PageTemplate, Frame, KeepInFrame, PageBreak
        _A4 = A4; PAGE_W, PAGE_H = _A4
        LM = 15 * mm; RM = 15 * mm; TM = 15 * mm; BM = 15 * mm
        frame_w = PAGE_W - LM - RM; frame_h = PAGE_H - TM - BM

        all_elems = []
        for learner_idx, lrn_d in enumerate(learner_list):
            lrn_id = lrn_d["id"]
            lrn    = conn.execute("SELECT * FROM learners WHERE id=?", (lrn_id,)).fetchone()
            rows   = conn.execute(
                "SELECT s.name,s.code,r.marks,r.points,r.performance_level,r.is_absent,"
                "a.max_marks,a.term,s.sort_order "
                "FROM results r JOIN assessments a ON r.assessment_id=a.id "
                "JOIN subjects s ON a.subject_id=s.id "
                "WHERE r.learner_id=? AND a.class_id=? AND a.term=? "
                "ORDER BY s.sort_order,s.name",
                (lrn_id, cls_id, term)).fetchall()

            # grade rank
            grade_rank = rank_map.get(lrn_id)
            elems = _report_card_elements(lrn, rows,
                                          class_position=rank_map.get(lrn_id),
                                          class_total=stream_total,
                                          term=term, year=year, primary=_primary,
                                          learner_index=learner_idx,
                                          grade_position=grade_rank,
                                          grade_total=len(learner_list))
            kif = KeepInFrame(frame_w, frame_h, elems, mode="shrink")
            all_elems.append(kif)
            if learner_idx < len(learner_list) - 1:
                all_elems.append(PageBreak())

        conn.close()

        def _border(canvas, doc):
            canvas.saveState()
            canvas.setStrokeColor(rl_colors.HexColor("#0a2540"))
            canvas.setLineWidth(2)
            canvas.rect(6 * mm, 6 * mm, PAGE_W - 12 * mm, PAGE_H - 12 * mm)
            canvas.restoreState()

        frame = Frame(LM, BM, frame_w, frame_h, leftPadding=0, rightPadding=0,
                      topPadding=0, bottomPadding=0)
        tmpl  = PageTemplate(id="rpt", frames=[frame], onPage=_border)
        doc   = BaseDocTemplate(path, pagesize=_A4, pageTemplates=[tmpl])
        try:
            doc.build(all_elems)
            messagebox.showinfo("PDF Saved",
                f"Report cards ({len(learner_list)} learners) saved to:\n{path}")
        except Exception as e:
            messagebox.showerror("PDF Error", str(e))

