    def _gen_marksheet(self):
        cls_v = self.ms_cls.get()
        if not cls_v:
            messagebox.showwarning("Select", "Select a class first."); return
        if not REPORTLAB_OK:
            messagebox.showerror("Missing Library", "reportlab is required."); return
        cls_id = int(cls_v.split("|")[0])
        term   = self.ms_term.get()
        year   = self.ms_year.get().strip()
        path   = filedialog.asksaveasfilename(
            defaultextension=".pdf", filetypes=[("PDF", "*.pdf")], initialfile="Marksheet.pdf")
        if not path: return

        conn      = get_conn()
        grade_row = conn.execute("SELECT grade,name FROM classes WHERE id=?", (cls_id,)).fetchone()
        grade_str = grade_row["grade"] if grade_row else ""
        subjects  = get_section_subjects(grade_str, conn)
        learners  = conn.execute(
            "SELECT admission_no,UPPER(first_name)||' '||UPPER(last_name) AS name "
            "FROM learners WHERE class_id=? AND status='Active' ORDER BY first_name,last_name",
            (cls_id,)).fetchall()
        conn.close()

        _A4_W, _A4_H = A4
        _LM = 10 * mm; _RM = 10 * mm
        doc = SimpleDocTemplate(path, pagesize=A4, topMargin=10 * mm, bottomMargin=18 * mm,
                                leftMargin=_LM, rightMargin=_RM)
        _hdr_style = ParagraphStyle("mh", fontSize=11, alignment=TA_CENTER,
                                    textColor=rl_colors.white,
                                    fontName="Helvetica-Bold", leading=16)
        logo = get_logo_image(16, 16)
        cls_label = grade_row["name"] if grade_row else "—"
        hdr_tbl = Table([[logo or "",
                           Paragraph(f"{school_name().upper()}<br/>"
                                     f"<font size=8>BLANK MARKSHEET  |  CLASS: {cls_label.upper()}  |  "
                                     f"{term.upper()}  |  {year}</font>",
                                     _hdr_style),
                           ""]],
                         colWidths=[18 * mm, None, 18 * mm])
        hdr_tbl.setStyle(TableStyle([
            ("BACKGROUND", (0, 0), (-1, -1), rl_colors.HexColor("#0d1b2a")),
            ("TEXTCOLOR",  (0, 0), (-1, -1), rl_colors.white),
            ("VALIGN",     (0, 0), (-1, -1), "MIDDLE"),
            ("TOPPADDING", (0, 0), (-1, -1), 7),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 7),
        ]))
        n_subj     = len(subjects)
        _USABLE    = _A4_W - _LM - _RM
        _name_w    = 55 * mm
        _adm_w     = 22 * mm
        _no_w      = 10 * mm
        _subj_w    = max(8 * mm, (_USABLE - _no_w - _adm_w - _name_w) / max(n_subj, 1))
        col_widths  = [_no_w, _adm_w, _name_w] + [_subj_w] * n_subj
        ms_hdr      = ["#", "ADM NO", "LEARNER NAME"] + [s["code"] for s in subjects]
        ms_rows     = [ms_hdr]
        for i, lrn in enumerate(learners, 1):
            ms_rows.append([str(i), lrn["admission_no"], lrn["name"]] + [""] * n_subj)
        ts = [
            ("FONTNAME",   (0, 0), (-1, 0), "Helvetica-Bold"),
            ("FONTSIZE",   (0, 0), (-1, -1), 7),
            ("BACKGROUND", (0, 0), (-1, 0), rl_colors.HexColor("#0d1b2a")),
            ("TEXTCOLOR",  (0, 0), (-1, 0), rl_colors.white),
            ("ALIGN",      (0, 0), (-1, -1), "CENTER"),
            ("ALIGN",      (2, 1), (2, -1), "LEFT"),
            ("GRID",       (0, 0), (-1, -1), 0.4, rl_colors.grey),
            ("TOPPADDING", (0, 0), (-1, -1), 4),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 4),
            ("ROWBACKGROUNDS", (0, 1), (-1, -1), [rl_colors.white, rl_colors.HexColor("#f0f7ff")]),
        ]
        ms_tbl = Table(ms_rows, colWidths=col_widths, repeatRows=1)
        ms_tbl.setStyle(TableStyle(ts))
        try:
            doc.build([hdr_tbl, Spacer(1, 4 * mm), ms_tbl])
            messagebox.showinfo("Saved", f"Marksheet saved:\n{path}")
        except Exception as e:
            messagebox.showerror("Error", str(e))

