    def _add_item(self):
        self._item_form(edit_id=None)

    def _edit_item(self):
        sel = self._tbl.tree.selection()
        if not sel:
            messagebox.showinfo("Select Row", "Please select an item to edit.")
            return
        idx = self._tbl.tree.index(sel[0])
        if idx >= len(self._item_ids): return
        self._item_form(edit_id=self._item_ids[idx])

    def _delete_item(self):
        sel = self._tbl.tree.selection()
        if not sel:
            messagebox.showinfo("Select Row", "Please select an item to delete.")
            return
        idx = self._tbl.tree.index(sel[0])
        if idx >= len(self._item_ids): return
        eid = self._item_ids[idx]
        if not messagebox.askyesno("Confirm Delete", "Delete this repository item?"):
            return
        conn = get_conn()
        conn.execute("DELETE FROM repo_items WHERE id=?", (eid,))
        conn.commit(); conn.close()
        self._refresh_filters()
        self._load_items()

    def _open_file(self):
        sel = self._tbl.tree.selection()
        if not sel:
            messagebox.showinfo("Select Row", "Select an item with an attached file.")
            return
        idx = self._tbl.tree.index(sel[0])
        if idx >= len(self._item_ids): return
        rid = self._item_ids[idx]
        conn = get_conn()
        row = conn.execute(
            "SELECT file_path, file_name FROM repo_items WHERE id=?", (rid,)).fetchone()
        conn.close()
        if not row or not row[0]:
            messagebox.showinfo("No File", "No file attached to this item.")
            return
        fpath = row[0]
        if not os.path.exists(fpath):
            messagebox.showerror("File Not Found",
                f"The attached file could not be found:\n{fpath}")
            return
        try:
            import subprocess, platform as _pl
            if _pl.system() == "Windows":
                os.startfile(fpath)
            elif _pl.system() == "Darwin":
                subprocess.Popen(["open", fpath])
            else:
                subprocess.Popen(["xdg-open", fpath])
        except Exception as ex:
            messagebox.showerror("Error", str(ex))

