# FINANCE MODULE — Tuition Fee Payment Tracker
# ═══════════════════════════════════════════════════════════════

def _finance_init_db():
    """Ensure finance tables exist (safe migration)."""
    conn = get_conn()
    c = conn.cursor()
    c.executescript("""
    CREATE TABLE IF NOT EXISTS fee_structures (
        id          INTEGER PRIMARY KEY AUTOINCREMENT,
        class_id    INTEGER REFERENCES classes(id) ON DELETE CASCADE,
        term        TEXT NOT NULL DEFAULT 'Term 1',
        academic_year TEXT NOT NULL DEFAULT '',
        amount      REAL NOT NULL DEFAULT 0.0,
        description TEXT DEFAULT '',
        created_at  TEXT DEFAULT (date('now')),
        UNIQUE(class_id, term, academic_year)
    );
    CREATE TABLE IF NOT EXISTS expenditures (
        id           INTEGER PRIMARY KEY AUTOINCREMENT,
        date         TEXT NOT NULL DEFAULT (date('now')),
        category     TEXT NOT NULL DEFAULT 'General',
        description  TEXT NOT NULL DEFAULT '',
        amount       REAL NOT NULL DEFAULT 0.0,
        paid_to      TEXT DEFAULT '',
        receipt_no   TEXT DEFAULT '',
        payment_mode TEXT DEFAULT 'Cash',
        notes        TEXT DEFAULT '',
        recorded_at  TEXT DEFAULT (datetime('now'))
    );
    CREATE TABLE IF NOT EXISTS expenditure_categories (
        id   INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT UNIQUE NOT NULL
    );
    INSERT OR IGNORE INTO expenditure_categories(name) VALUES
        ('Salaries'), ('Utilities'), ('Maintenance'), ('Stationery'),
        ('Transport'), ('Food & Catering'), ('Events'), ('ICT Equipment'),
        ('Furniture'), ('Other');
    CREATE TABLE IF NOT EXISTS fee_payments (
        id          INTEGER PRIMARY KEY AUTOINCREMENT,
        learner_id  INTEGER REFERENCES learners(id) ON DELETE CASCADE,
        class_id    INTEGER REFERENCES classes(id) ON DELETE CASCADE,
        term        TEXT NOT NULL DEFAULT 'Term 1',
        academic_year TEXT NOT NULL DEFAULT '',
        amount_paid REAL NOT NULL DEFAULT 0.0,
        payment_date TEXT DEFAULT (date('now')),
        receipt_no  TEXT DEFAULT '',
        payment_mode TEXT DEFAULT 'Cash',
        notes       TEXT DEFAULT '',
        recorded_at TEXT DEFAULT (datetime('now'))
    );
    """)
    conn.commit()
    conn.close()


# ── Helper: get all fee payments for a class ─────────────────
def _fee_class_summary(class_id, term, academic_year):
    """Return list of dicts with learner fee status for a class/term."""
    conn = get_conn()
    # Get expected fee
    fs = conn.execute(
        "SELECT amount FROM fee_structures WHERE class_id=? AND term=? AND academic_year=?",
        (class_id, term, academic_year)
    ).fetchone()
    expected = fs["amount"] if fs else 0.0

    learners = conn.execute(
        """SELECT l.id, l.admission_no,
                  UPPER(l.first_name)||' '||UPPER(l.last_name) AS name,
                  l.gender, l.status
           FROM learners l WHERE l.class_id=? AND l.status='Active'
           ORDER BY l.last_name, l.first_name""",
        (class_id,)
    ).fetchall()

    rows = []
    for lrn in learners:
        paid_total = conn.execute(
            """SELECT COALESCE(SUM(amount_paid),0)
               FROM fee_payments
               WHERE learner_id=? AND class_id=? AND term=? AND academic_year=?""",
            (lrn["id"], class_id, term, academic_year)
        ).fetchone()[0]
        balance = expected - paid_total
        status = "Cleared" if balance <= 0 else ("Partial" if paid_total > 0 else "Unpaid")
        rows.append({
            "learner_id": lrn["id"],
            "admission_no": lrn["admission_no"],
            "name": lrn["name"],
            "gender": lrn["gender"],
            "expected": expected,
            "paid": paid_total,
            "balance": max(0, balance),
            "status": status,
        })
    conn.close()
    return rows, expected



def _auto_receipt_no():
    """Generate a sequential receipt number like RCT-20250426-0042."""
    conn = get_conn()
    count = conn.execute("SELECT COUNT(*) FROM fee_payments").fetchone()[0]
    conn.close()
    return f"RCT-{datetime.now().strftime('%Y%m%d')}-{count+1:04d}"


def _fee_generate_receipt(payment_id, filepath):
    """
    Generate a professional A5-portrait payment receipt PDF for a single payment.
    Returns True on success.
    """
    if not REPORTLAB_OK:
        messagebox.showerror("ReportLab Missing",
                             "Install reportlab to generate receipts.\n"
                             "Run:  pip install reportlab")
        return False

    from reportlab.lib.pagesizes import A5
    from reportlab.lib import colors as rl_colors
    from reportlab.lib.units import mm
    from reportlab.platypus import (SimpleDocTemplate, Table, TableStyle,
                                    Paragraph, Spacer, HRFlowable)
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_RIGHT
    from reportlab.graphics.shapes import Drawing, Rect, String, Line

    conn = get_conn()
    row = conn.execute(
        """SELECT fp.id, fp.amount_paid, fp.payment_date, fp.receipt_no,
                  fp.payment_mode, fp.notes, fp.term, fp.academic_year,
                  fp.recorded_at,
                  l.admission_no,
                  UPPER(l.first_name)||' '||UPPER(l.last_name) AS learner_name,
                  l.parent_name, l.parent_phone,
                  c.name AS class_name, c.grade,
                  fs.amount AS expected_fee,
                  COALESCE(
                      (SELECT SUM(fp2.amount_paid)
                       FROM fee_payments fp2
                       WHERE fp2.learner_id=fp.learner_id
                         AND fp2.class_id=fp.class_id
                         AND fp2.term=fp.term
                         AND fp2.academic_year=fp.academic_year
                         AND fp2.id <= fp.id), 0
                  ) AS cumulative_paid
           FROM fee_payments fp
           JOIN learners l  ON fp.learner_id = l.id
           JOIN classes  c  ON fp.class_id   = c.id
           LEFT JOIN fee_structures fs
                  ON fs.class_id=fp.class_id
                 AND fs.term=fp.term
                 AND fs.academic_year=fp.academic_year
           WHERE fp.id = ?""",
        (payment_id,)
    ).fetchone()
    conn.close()
    if not row:
        return False

    expected   = row["expected_fee"] or 0.0
    cum_paid   = row["cumulative_paid"] or 0.0
    balance    = max(0.0, expected - cum_paid)
    rcpt_no    = row["receipt_no"] or f"RCT-{payment_id:06d}"
    sname      = school_name() or "School"

    styles = getSampleStyleSheet()
    NAVY   = rl_colors.HexColor("#0d2844")
    GOLD   = rl_colors.HexColor("#FFB400")
    GREEN  = rl_colors.HexColor("#15803d")
    RED    = rl_colors.HexColor("#b91c1c")
    LGRAY  = rl_colors.HexColor("#f0f7ff")
