# PASSWORD SYSTEM
# ─────────────────────────────────────────────────────────────

PWD_PATH = os.path.join(BASE_DIR, "ems_pwd.dat")
FINANCE_PWD_PATH = os.path.join(BASE_DIR, "finance_pwd.dat")

def _finance_pwd_is_set() -> bool:
    return os.path.exists(FINANCE_PWD_PATH)

def _finance_check_pwd(pwd: str) -> bool:
    if not _finance_pwd_is_set(): return False
    with open(FINANCE_PWD_PATH) as f:
        return f.read().strip() == _hash_pwd(pwd)

def _finance_save_pwd(pwd: str):
    with open(FINANCE_PWD_PATH, "w") as f:
        f.write(_hash_pwd(pwd))


def _show_finance_pwd_dialog(parent, on_success):
    """Show a modal Finance PIN/password dialog.
    If no Finance password has been set yet, prompt to create one first."""
    ACCENT = "#06b6d4"
    NAVY   = "#0a1628"
    CARD   = "#112233"
    TEXT   = "#e2f0f7"
    RED    = "#ef4444"
    GOLD   = "#facc15"

    dlg = tk.Toplevel(parent)
    dlg.title("Finance — Restricted Access")
    dlg.configure(bg=NAVY)
    dlg.resizable(False, False)
    dlg.grab_set()
    dlg.focus_set()
    w, h = 380, 300
    dlg.update_idletasks()
    sw = parent.winfo_screenwidth(); sh = parent.winfo_screenheight()
    dlg.geometry(f"{w}x{h}+{(sw-w)//2}+{(sh-h)//2}")

    setting_up = not _finance_pwd_is_set()

    # Header
    hdr = tk.Frame(dlg, bg=ACCENT, pady=10)
    hdr.pack(fill="x")
    tk.Label(hdr, text="💰  Finance — Restricted Access",
             bg=ACCENT, fg=NAVY, font=("Segoe UI", 12, "bold")).pack()

    # Card body
    card = tk.Frame(dlg, bg=CARD, padx=24, pady=18)
    card.pack(fill="both", expand=True, padx=16, pady=14)

    if setting_up:
        tk.Label(card, text="Set a Finance Password",
                 bg=CARD, fg=GOLD, font=("Segoe UI", 11, "bold")).pack(anchor="w")
        tk.Label(card, text="No Finance password is set yet. Create one to protect this section.",
                 bg=CARD, fg=TEXT, font=("Segoe UI", 9)).pack(anchor="w", pady=(2, 10))
        tk.Label(card, text="New Password:", bg=CARD, fg=TEXT,
                 font=("Segoe UI", 9)).pack(anchor="w")
        e_new = tk.Entry(card, show="●", bg="#1e3a5f", fg=TEXT, insertbackground=TEXT,
                         font=("Segoe UI", 11), relief="flat", bd=4)
        e_new.pack(fill="x", pady=(2, 8))
        tk.Label(card, text="Confirm Password:", bg=CARD, fg=TEXT,
                 font=("Segoe UI", 9)).pack(anchor="w")
        e_conf = tk.Entry(card, show="●", bg="#1e3a5f", fg=TEXT, insertbackground=TEXT,
                          font=("Segoe UI", 11), relief="flat", bd=4)
        e_conf.pack(fill="x", pady=(2, 8))
        err_var = tk.StringVar()
        tk.Label(card, textvariable=err_var, bg=CARD, fg=RED,
                 font=("Segoe UI", 9)).pack(anchor="w")

        def _do_set(event=None):
            p1 = e_new.get().strip()
            p2 = e_conf.get().strip()
            if len(p1) < 4:
                err_var.set("Password must be at least 4 characters."); return
            if p1 != p2:
                err_var.set("Passwords do not match."); return
            _finance_save_pwd(p1)
            dlg.destroy()
            on_success()

        e_new.focus_set()
        e_conf.bind("<Return>", _do_set)
        btn_frame = tk.Frame(card, bg=CARD)
        btn_frame.pack(fill="x", pady=(6, 0))
        tk.Button(btn_frame, text="Cancel", bg="#1e3a5f", fg=TEXT,
                  font=("Segoe UI", 9), relief="flat", bd=0, padx=14, pady=6,
                  cursor="hand2", command=dlg.destroy).pack(side="right", padx=(6,0))
        tk.Button(btn_frame, text="Set Password & Open Finance", bg=ACCENT, fg=NAVY,
                  font=("Segoe UI", 9, "bold"), relief="flat", bd=0, padx=14, pady=6,
                  cursor="hand2", command=_do_set).pack(side="right")
    else:
        tk.Label(card, text="Enter Finance Password",
                 bg=CARD, fg=GOLD, font=("Segoe UI", 11, "bold")).pack(anchor="w")
        tk.Label(card, text="This section is password-protected.",
                 bg=CARD, fg=TEXT, font=("Segoe UI", 9)).pack(anchor="w", pady=(2, 12))
        tk.Label(card, text="Password:", bg=CARD, fg=TEXT,
                 font=("Segoe UI", 9)).pack(anchor="w")
        e_pwd = tk.Entry(card, show="●", bg="#1e3a5f", fg=TEXT, insertbackground=TEXT,
                         font=("Segoe UI", 11), relief="flat", bd=4)
        e_pwd.pack(fill="x", pady=(2, 8))
        err_var = tk.StringVar()
        tk.Label(card, textvariable=err_var, bg=CARD, fg=RED,
                 font=("Segoe UI", 9)).pack(anchor="w")

        def _do_check(event=None):
            if _finance_check_pwd(e_pwd.get()):
                dlg.destroy()
                on_success()
            else:
                err_var.set("Incorrect password. Try again.")
                e_pwd.delete(0, "end")
                e_pwd.focus_set()

        e_pwd.focus_set()
        e_pwd.bind("<Return>", _do_check)
        btn_frame = tk.Frame(card, bg=CARD)
        btn_frame.pack(fill="x", pady=(6, 0))
        tk.Button(btn_frame, text="Cancel", bg="#1e3a5f", fg=TEXT,
                  font=("Segoe UI", 9), relief="flat", bd=0, padx=14, pady=6,
                  cursor="hand2", command=dlg.destroy).pack(side="right", padx=(6,0))
        tk.Button(btn_frame, text="Unlock Finance", bg=ACCENT, fg=NAVY,
                  font=("Segoe UI", 9, "bold"), relief="flat", bd=0, padx=14, pady=6,
                  cursor="hand2", command=_do_check).pack(side="right")

def _hash_pwd(pwd: str) -> str:
    return hashlib.sha256(pwd.encode("utf-8")).hexdigest()

def _pwd_is_set() -> bool:
    return os.path.exists(PWD_PATH)

def _check_pwd(pwd: str) -> bool:
    if not _pwd_is_set(): return False
    with open(PWD_PATH) as f:
        return f.read().strip() == _hash_pwd(pwd)

def _save_pwd(pwd: str):
    with open(PWD_PATH, "w") as f:
        f.write(_hash_pwd(pwd))


class LoginDialog(tk.Tk):
    """Full-screen login / first-run password setup shown before IQApp."""

    BRAND_BG = "#0a1628"
    CARD_BG  = "#112233"
    ACCENT   = "#06b6d4"
    RED      = "#ef4444"
    TEXT     = "#e2f0f7"
    SUB      = "#6b9ab8"

    def __init__(self):
        super().__init__()
        self.title("iQ School Systems — Login")
        self.configure(bg=self.BRAND_BG)
        self.resizable(False, False)
        self._authenticated = False
        self._build()
        # Centre window
        self.update_idletasks()
        w, h = 460, 580
        sw = self.winfo_screenwidth(); sh = self.winfo_screenheight()
        self.geometry(f"{w}x{h}+{(sw-w)//2}+{(sh-h)//2}")
        self.protocol("WM_DELETE_WINDOW", self._cancel)

    # ── Build UI ──────────────────────────────────────────────
    def _build(self):
        # Logo / brand area
        brand = tk.Frame(self, bg=self.BRAND_BG, pady=18)
        brand.pack(fill="x")

        # ── Load logo: embedded ICO first, external logo.png as override ──
        self._logo = None
        try:
            import base64 as _b64, io as _io
            from PIL import Image as _PILImg, ImageTk as _ITk
            # Use external logo.png if present, otherwise fall back to embedded ICO
            if os.path.exists(LOGO_PATH):
                _raw = open(LOGO_PATH, "rb").read()
            else:
                _raw = _b64.b64decode(_LOGIN_LOGO_B64)
            _pil = _PILImg.open(_io.BytesIO(_raw)).convert("RGBA").resize((96, 96), _PILImg.LANCZOS)
            self._logo = _ITk.PhotoImage(_pil)
            tk.Label(brand, image=self._logo, bg=self.BRAND_BG).pack(pady=(0, 6))
        except Exception:
            pass

        tk.Label(brand, text="iQ School Systems", bg=self.BRAND_BG, fg=self.ACCENT,
                 font=("Segoe UI", 24, "bold")).pack()
        tk.Label(brand, text=school_name(), bg=self.BRAND_BG, fg=self.TEXT,
                 font=("Segoe UI", 9, "bold")).pack(pady=(4, 0))

        # Card
        card = tk.Frame(self, bg=self.CARD_BG, padx=36, pady=28,
                        highlightthickness=1, highlightbackground=self.ACCENT)
        card.pack(padx=36, pady=20, fill="x", expand=False)

        if not _pwd_is_set():
            self._build_setup(card)
        else:
            self._build_login(card)

        # Support note at the bottom
        tk.Label(self, text="For support contact iQTim @0722201538 or cheruiyottimothy48@gmail.com",
                 bg=self.BRAND_BG, fg=self.SUB, font=("Segoe UI", 7)).pack(side="bottom", pady=8)

    # ── First-run: set a new password ─────────────────────────
    def _build_setup(self, card):
        tk.Label(card, text="🔐  Set Application Password",
                 bg=self.CARD_BG, fg=self.ACCENT,
                 font=("Segoe UI", 13, "bold")).pack(anchor="w", pady=(0, 4))
        tk.Label(card,
                 text="No password has been set yet.\nCreate a password to protect this application.",
                 bg=self.CARD_BG, fg=self.SUB, font=("Segoe UI", 9),
                 justify="left").pack(anchor="w", pady=(0, 16))

        for lbl, attr in [("New Password:", "_e1"), ("Confirm Password:", "_e2")]:
            tk.Label(card, text=lbl, bg=self.CARD_BG, fg=self.TEXT,
                     font=("Segoe UI", 9, "bold"), anchor="w").pack(fill="x")
            ew = tk.Entry(card, show="●", font=("Segoe UI", 12),
                          bg="#1a2f45", fg=self.TEXT, insertbackground=self.ACCENT,
                          relief="flat", bd=0, highlightthickness=2,
                          highlightbackground=self.ACCENT, highlightcolor=self.ACCENT)
            ew.pack(fill="x", pady=(2, 12), ipady=8)
            setattr(self, attr, ew)

        self._err = tk.Label(card, text="", bg=self.CARD_BG, fg=self.RED,
                             font=("Segoe UI", 9)); self._err.pack(anchor="w")

        btn = tk.Button(card, text="  ✅  Set Password & Open App  ",
                        command=self._do_setup,
                        bg=self.ACCENT, fg=self.BRAND_BG,
                        font=("Segoe UI", 11, "bold"),
                        relief="flat", cursor="hand2", pady=8)
        btn.pack(fill="x", pady=(10, 0))
        self._e1.bind("<Return>", lambda ev: self._e2.focus())
        self._e2.bind("<Return>", lambda ev: self._do_setup())
        self._e1.focus()

    def _do_setup(self):
        p1 = self._e1.get(); p2 = self._e2.get()
        if len(p1) < 4:
            self._err.configure(text="⚠  Password must be at least 4 characters."); return
        if p1 != p2:
            self._err.configure(text="⚠  Passwords do not match."); return
        _save_pwd(p1)
        self._authenticated = True
        self.destroy()

    # ── Normal login ──────────────────────────────────────────
    def _build_login(self, card):
        tk.Label(card, text="🔐  Enter Password",
                 bg=self.CARD_BG, fg=self.ACCENT,
                 font=("Segoe UI", 13, "bold")).pack(anchor="w", pady=(0, 4))
        tk.Label(card, text="Enter your password to access iQ School Systems.",
                 bg=self.CARD_BG, fg=self.SUB, font=("Segoe UI", 9)).pack(anchor="w", pady=(0, 14))

        tk.Label(card, text="Password:", bg=self.CARD_BG, fg=self.TEXT,
                 font=("Segoe UI", 9, "bold"), anchor="w").pack(fill="x")
        self._pwd_entry = tk.Entry(card, show="●", font=("Segoe UI", 13),
                                   bg="#1a2f45", fg=self.TEXT,
                                   insertbackground=self.ACCENT,
                                   relief="flat", highlightthickness=1,
                                   highlightbackground=self.ACCENT,
                                   highlightcolor=self.ACCENT)
        self._pwd_entry.pack(fill="x", pady=(2, 10), ipady=8)

        # Show / hide toggle
        self._show_var = tk.BooleanVar(value=False)
        def _toggle_show():
            self._pwd_entry.configure(show="" if self._show_var.get() else "●")
        tk.Checkbutton(card, text="Show password", variable=self._show_var,
                       command=_toggle_show,
                       bg=self.CARD_BG, fg=self.SUB, selectcolor=self.CARD_BG,
                       activebackground=self.CARD_BG, activeforeground=self.ACCENT,
                       font=("Segoe UI", 8), cursor="hand2").pack(anchor="w")

        self._err = tk.Label(card, text="", bg=self.CARD_BG, fg=self.RED,
                             font=("Segoe UI", 9)); self._err.pack(anchor="w", pady=(6, 0))

        btn = tk.Button(card, text="  🔓  Login  ",
                        command=self._do_login,
                        bg=self.ACCENT, fg=self.BRAND_BG,
                        font=("Segoe UI", 12, "bold"),
                        relief="flat", cursor="hand2", pady=10)
        btn.pack(fill="x", pady=(10, 0))

        # Change password link
        tk.Button(card, text="Forgot / Change Password",
                  command=self._change_pwd_dialog,
                  bg=self.CARD_BG, fg=self.SUB,
                  font=("Segoe UI", 8, "underline"),
                  relief="flat", cursor="hand2").pack(pady=(10, 0))

        self._pwd_entry.bind("<Return>", lambda e: self._do_login())
        self._pwd_entry.focus()
        self._attempts = 0

    def _do_login(self):
        pwd = self._pwd_entry.get()
        if _check_pwd(pwd):
            self._authenticated = True
            self.destroy()
        else:
            self._attempts += 1
            if self._attempts >= 5:
                messagebox.showerror("Locked",
                    "Too many failed attempts. The application will now close.",
                    parent=self)
                self.destroy()
            else:
                remaining = 5 - self._attempts
                self._err.configure(
                    text=f"⚠  Incorrect password. {remaining} attempt(s) remaining.")
                self._pwd_entry.delete(0, "end")

    def _change_pwd_dialog(self):
        """Allow password reset using the current password."""
        win = tk.Toplevel(self); win.title("Change Password")
        win.configure(bg=self.CARD_BG); win.geometry("360x340")
        win.resizable(False, False); win.grab_set()
        tk.Label(win, text="Change Password", bg=self.CARD_BG, fg=self.ACCENT,
                 font=("Segoe UI", 13, "bold")).pack(pady=(16, 8))
        entries = {}
        for lbl, key in [("Current Password:", "cur"),
                          ("New Password:",     "new"),
                          ("Confirm New:",      "cnf")]:
            tk.Label(win, text=lbl, bg=self.CARD_BG, fg=self.TEXT,
                     font=("Segoe UI", 9), anchor="w").pack(fill="x", padx=24)
            e = tk.Entry(win, show="●", font=("Segoe UI", 11),
                         bg="#1a2f45", fg=self.TEXT,
                         insertbackground=self.ACCENT, relief="flat",
                         highlightthickness=1, highlightbackground=self.ACCENT)
            e.pack(fill="x", padx=24, pady=(2, 8), ipady=5)
            entries[key] = e
        err = tk.Label(win, text="", bg=self.CARD_BG, fg=self.RED, font=("Segoe UI", 9))
        err.pack()
        def _do_change():
            cur = entries["cur"].get(); nw = entries["new"].get(); cn = entries["cnf"].get()
            if not _check_pwd(cur):
                err.configure(text="⚠  Current password is incorrect."); return
            if len(nw) < 4:
                err.configure(text="⚠  New password must be at least 4 characters."); return
            if nw != cn:
                err.configure(text="⚠  New passwords do not match."); return
            _save_pwd(nw)
            messagebox.showinfo("Success", "Password changed successfully!", parent=win)
            win.destroy()
        tk.Button(win, text="✅ Save New Password", command=_do_change,
                  bg=self.ACCENT, fg=self.BRAND_BG,
                  font=("Segoe UI", 10, "bold"),
                  relief="flat", cursor="hand2", pady=7).pack(fill="x", padx=24, pady=(4, 0))
        tk.Button(win, text="Cancel", command=win.destroy,
                  bg="#1e3a52", fg=self.TEXT,
                  font=("Segoe UI", 9), relief="flat",
                  cursor="hand2", pady=5).pack(fill="x", padx=24, pady=(6, 0))

    def _cancel(self):
        self._authenticated = False
        self.destroy()


