# iQ CLOUD SERVER — Embedded (runs as separate process when --cloud-server arg)
# ══════════════════════════════════════════════════════════════════════════════
# To run as cloud server:  python iQ_Systems_v4.py --cloud-server
# Deploy this same file to Render.com with start command:
#   gunicorn "iQ_Systems_v4:_build_cloud_app()" --bind 0.0.0.0:$PORT
# Set env var:  IQ_ADMIN_TOKEN=yourSecretToken
# ══════════════════════════════════════════════════════════════════════════════

def _build_cloud_app():
    """
    Factory that builds and returns the Flask cloud server app.
    Called by gunicorn when deployed, or internally when --cloud-server is used.
    """
    import os, json, sqlite3, secrets, time, hashlib, logging
    from datetime import datetime, timezone
    from functools import wraps
    from flask import Flask, request, jsonify, abort, g

    # ── Configuration ─────────────────────────────────────────────────────────────
    ADMIN_TOKEN  = os.environ.get("IQ_ADMIN_TOKEN", "")
    DATABASE_URL = os.environ.get("DATABASE_URL", "")
    DB_PATH      = os.environ.get("DB_PATH", "/data/iq_cloud.db")

    # Fallback to local path if /data doesn't exist (local dev)
    if not os.path.exists("/data"):
        DB_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), "iq_cloud.db")

    USE_POSTGRES = bool(DATABASE_URL and DATABASE_URL.startswith("postgresql"))

    logging.basicConfig(level=logging.INFO)
    log = logging.getLogger("iQ-Cloud")

    app = Flask("iQ_Cloud_Server")
    app.secret_key = secrets.token_hex(32)

    # ── Database layer ─────────────────────────────────────────────────────────────
    def get_db():
        """Return a DB connection for this request context."""
        if "db" not in g:
            if USE_POSTGRES:
                import psycopg2, psycopg2.extras
                g.db = psycopg2.connect(DATABASE_URL, cursor_factory=psycopg2.extras.RealDictCursor)
            else:
                conn = sqlite3.connect(DB_PATH)
                conn.row_factory = sqlite3.Row
                conn.execute("PRAGMA journal_mode=WAL")
                conn.execute("PRAGMA foreign_keys=ON")
                g.db = conn
        return g.db

    @app.teardown_appcontext
    def close_db(exc):
        db = g.pop("db", None)
        if db is not None:
            try: db.close()
            except Exception: pass

    def _qmark(sql: str) -> str:
        """Convert ? placeholders to %s for PostgreSQL."""
        return sql.replace("?", "%s") if USE_POSTGRES else sql

    def _exec(sql, params=()):
        db  = get_db()
        cur = db.cursor()
        cur.execute(_qmark(sql), params)
        return cur

    def _fetchall(sql, params=()):
        cur = _exec(sql, params)
        rows = cur.fetchall()
        return [dict(r) for r in rows]

    def _fetchone(sql, params=()):
        cur = _exec(sql, params)
        row = cur.fetchone()
        return dict(row) if row else None

    def _commit():
        get_db().commit()

    def _lastrowid(cur):
        if USE_POSTGRES:
            return cur.fetchone()["id"] if cur.rowcount else None
        return cur.lastrowid

    # ── Schema bootstrap ──────────────────────────────────────────────────────────
    SCHEMA_SQL = """
    CREATE TABLE IF NOT EXISTS cloud_school (
        id      INTEGER PRIMARY KEY,
        name    TEXT DEFAULT 'iQ School',
        config  TEXT DEFAULT '{}'
    );
    CREATE TABLE IF NOT EXISTS cloud_classes (
        id      INTEGER PRIMARY KEY,
        name    TEXT NOT NULL,
        grade   TEXT NOT NULL,
        section TEXT NOT NULL
    );
    CREATE TABLE IF NOT EXISTS cloud_learners (
        id           INTEGER PRIMARY KEY,
        admission_no TEXT,
        first_name   TEXT,
        last_name    TEXT,
        class_id     INTEGER REFERENCES cloud_classes(id)
    );
    CREATE TABLE IF NOT EXISTS cloud_subjects (
        id           INTEGER PRIMARY KEY,
        code         TEXT,
        name         TEXT,
        max_marks    REAL DEFAULT 100,
        section_key  TEXT,
        sort_order   INTEGER DEFAULT 0,
        is_active    INTEGER DEFAULT 1
    );
    CREATE TABLE IF NOT EXISTS cloud_assessments (
        id           INTEGER PRIMARY KEY,
        name         TEXT,
        type         TEXT,
        class_id     INTEGER REFERENCES cloud_classes(id),
        subject_id   INTEGER REFERENCES cloud_subjects(id),
        term         TEXT,
        academic_year TEXT,
        max_marks    REAL DEFAULT 100,
        status       TEXT DEFAULT 'Ongoing'
    );
    CREATE TABLE IF NOT EXISTS cloud_results (
        id                INTEGER PRIMARY KEY,
        learner_id        INTEGER REFERENCES cloud_learners(id),
        assessment_id     INTEGER REFERENCES cloud_assessments(id),
        marks             REAL,
        performance_level TEXT,
        points            REAL DEFAULT 0,
        is_absent         INTEGER DEFAULT 0,
        entry_date        TEXT,
        submitted_by      TEXT DEFAULT 'teacher',
        synced_to_desktop INTEGER DEFAULT 0,
        created_at        TEXT DEFAULT (datetime('now')),
        UNIQUE(learner_id, assessment_id)
    );
    CREATE TABLE IF NOT EXISTS cloud_meta (
        key   TEXT PRIMARY KEY,
        value TEXT
    );
    """

    PG_SCHEMA_SQL = SCHEMA_SQL \
        .replace("INTEGER PRIMARY KEY", "SERIAL PRIMARY KEY") \
        .replace("datetime('now')", "NOW()") \
        .replace("date('now')", "NOW()")

    def init_db():
        db = get_db()
        cur = db.cursor()
        schema = PG_SCHEMA_SQL if USE_POSTGRES else SCHEMA_SQL
        for stmt in schema.split(";"):
            stmt = stmt.strip()
            if stmt:
                try: cur.execute(stmt)
                except Exception as e:
                    if "already exists" not in str(e).lower(): log.warning(f"Schema: {e}")
        db.commit()
        log.info(f"DB ready ({('PostgreSQL' if USE_POSTGRES else 'SQLite')})")

    # ── Auth ──────────────────────────────────────────────────────────────────────
    def _check_token(tok: str) -> bool:
        if not ADMIN_TOKEN:
            return True  # No token set — open (dev mode)
        return bool(tok) and secrets.compare_digest(tok, ADMIN_TOKEN)

    def require_token(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            tok = (request.args.get("token") or
                   (request.get_json(silent=True) or {}).get("token") or
                   request.headers.get("X-IQ-Token", ""))
            if not _check_token(tok):
                abort(403)
            return f(*args, **kwargs)
        return decorated

    # ── CBC level helper ──────────────────────────────────────────────────────────
    _DEFAULT_CBC_LEVELS = [
        {"level":"EE1","min":90,"max":100,"points":8},
        {"level":"EE2","min":75,"max":89, "points":7},
        {"level":"ME1","min":58,"max":74, "points":6},
        {"level":"ME2","min":41,"max":57, "points":5},
        {"level":"AE1","min":31,"max":40, "points":4},
        {"level":"AE2","min":21,"max":30, "points":3},
        {"level":"BE1","min":11,"max":20, "points":2},
        {"level":"BE2","min":0, "max":10, "points":1},
    ]

    def _cbc_levels():
        try:
            row = _fetchone("SELECT value FROM cloud_meta WHERE key='cbc_levels'")
            if row: return json.loads(row["value"])
        except Exception: pass
        return _DEFAULT_CBC_LEVELS

    def _cbc_level(marks, max_m=100):
        pct = (marks / max_m * 100) if max_m > 0 else 0
        for lv in _cbc_levels():
            if lv["min"] <= pct <= lv["max"]:
                return lv["level"], lv["points"]
        return "BE2", 1

    def _grade_to_section(grade: str) -> str:
        g = grade.lower().replace(" ","").replace("-","")
        if g in {"pp1","pp2","nursery","preprimary1","preprimary2"}: return "preprimary"
        try:
            n = int(g.replace("grade",""))
            if 1<=n<=3: return "lower"
            if 4<=n<=6: return "upper"
        except Exception: pass
        return "junior"

    # ── Teacher UI HTML ───────────────────────────────────────────────────────────
    _TEACHER_HTML = r"""<!DOCTYPE html>
    <html lang="en">
    <head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width,initial-scale=1.0">
    <title>iQ Cloud — Remote Marks Entry</title>
    <style>
    @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;600;700&display=swap');
    :root{--navy:#0a1628;--card:#0e2240;--accent:#1e90ff;--accent2:#00d4aa;--text:#e8f0fe;--sub:#7a9bbf;--border:#1e3a5a;--green:#00c875;--red:#ff4d5e;--yellow:#ffc93c}
    *{box-sizing:border-box;margin:0;padding:0}
    body{background:var(--navy);color:var(--text);font-family:'Outfit',sans-serif;min-height:100vh;padding-bottom:80px}
    header{background:linear-gradient(135deg,#0a1e3d,#0d2a52);border-bottom:1px solid var(--border);padding:14px 20px;display:flex;align-items:center;gap:12px;position:sticky;top:0;z-index:100}
    .logo{background:var(--accent);color:var(--navy);font-weight:700;font-size:13px;padding:4px 10px;border-radius:6px}
    h1{font-size:15px;font-weight:600}
    .cloud-badge{margin-left:auto;background:#0d3320;color:#00e676;font-size:11px;font-weight:700;padding:4px 10px;border-radius:20px;border:1px solid #00e676}
    .tabs{display:flex;gap:8px;padding:14px 16px 0;overflow-x:auto}
    .tab{background:var(--card);border:1.5px solid var(--border);color:var(--sub);font-size:13px;font-weight:600;padding:9px 16px;border-radius:8px;cursor:pointer;white-space:nowrap;transition:all .2s;font-family:inherit}
    .tab.active{background:var(--accent);border-color:var(--accent);color:var(--navy)}
    .main{padding:14px 16px}
    .card{background:var(--card);border:1px solid var(--border);border-radius:10px;padding:16px;margin-bottom:12px}
    .card-title{font-size:12px;font-weight:700;color:var(--accent);text-transform:uppercase;letter-spacing:.8px;margin-bottom:10px}
    .row{display:flex;gap:10px;flex-wrap:wrap}
    .field{display:flex;flex-direction:column;gap:5px;flex:1;min-width:130px}
    label{font-size:11px;color:var(--sub);font-weight:600;text-transform:uppercase;letter-spacing:.5px}
    select,input{background:var(--navy);border:1.5px solid var(--border);color:var(--text);font-family:inherit;font-size:14px;padding:9px 12px;border-radius:7px;outline:none;width:100%;transition:border-color .2s}
    select:focus,input:focus{border-color:var(--accent)}
    .btn{display:inline-flex;align-items:center;gap:6px;background:var(--accent);color:var(--navy);border:none;font-family:inherit;font-size:14px;font-weight:700;padding:10px 20px;border-radius:8px;cursor:pointer;white-space:nowrap;transition:opacity .15s}
    .btn:disabled{opacity:.4;cursor:not-allowed}
    .btn-green{background:var(--green)}
    .tbl-wrap{overflow-x:auto;border-radius:8px;border:1px solid var(--border)}
    table{border-collapse:collapse;width:100%;min-width:340px}
    thead th{background:#0d2844;color:var(--accent);font-size:11px;font-weight:700;text-transform:uppercase;padding:10px;text-align:left;border-bottom:1px solid var(--border);white-space:nowrap}
    tbody tr{border-bottom:1px solid var(--border)}
    tbody tr:hover{background:#0d2240}
    td{padding:8px 10px;font-size:14px}
    .mi{background:var(--navy);border:1.5px solid var(--border);color:var(--text);font-size:14px;padding:6px 8px;border-radius:6px;width:82px;text-align:center}
    .mi:focus{border-color:var(--accent);outline:none}
    .ab{width:18px;height:18px;cursor:pointer;accent-color:var(--red)}
    .toast{position:fixed;bottom:20px;left:50%;transform:translateX(-50%);background:#1e3a5a;color:var(--text);padding:12px 24px;border-radius:10px;font-size:14px;z-index:999;box-shadow:0 4px 20px #00000066;opacity:0;transition:opacity .3s;pointer-events:none}
    .toast.show{opacity:1}
    .lv-pill{font-size:11px;font-weight:700;padding:2px 7px;border-radius:4px;display:inline-block}
    </style>
    </head>
    <body>
    <header>
      <span class="logo">iQ</span>
      <h1>Remote Marks Entry</h1>
      <span class="cloud-badge">☁️ Cloud</span>
      <span style="margin-left:12px;font-size:12px;color:var(--sub)" id="school-name"></span>
    </header>
    <div class="tabs">
      <button class="tab active" onclick="setSection('junior',this)">🎓 Junior (Gr 7-9)</button>
      <button class="tab" onclick="setSection('upper',this)">📘 Upper Primary</button>
      <button class="tab" onclick="setSection('lower',this)">📗 Lower Primary</button>
      <button class="tab" onclick="setSection('preprimary',this)">🌱 Pre-Primary</button>
    </div>
    <div class="main">
      <div class="card">
        <div class="card-title">📋 Assessment Setup</div>
        <div class="row">
          <div class="field"><label>Class</label>
            <select id="cls" onchange="loadSubjects()"><option value="">— select —</option></select></div>
          <div class="field"><label>Subject</label>
            <select id="subj"><option value="">— select —</option></select></div>
          <div class="field"><label>Term</label>
            <select id="term"><option>Term 1</option><option>Term 2</option><option>Term 3</option></select></div>
          <div class="field"><label>Year</label>
            <input type="number" id="yr" min="2020" max="2099"></div>
          <div class="field"><label>Type</label>
            <select id="typ">
              <option>End of Term</option><option>Mid Term</option>
              <option>CAT 1</option><option>CAT 2</option><option>Assignment</option>
            </select></div>
        </div>
        <div style="margin-top:12px">
          <button class="btn" onclick="loadMarks()">📥 Load Learners</button>
        </div>
      </div>
      <div id="marks-area"></div>
    </div>
    <div class="toast" id="toast"></div>
    <script>
    const TOKEN   = "__TOKEN__";
    const SECTION = "__SECTION__";
    const LEVELS  = __LEVELS__;
    let curSec = SECTION, curMax = 100;

    function setSection(sec, btn) {
      curSec = sec;
      document.querySelectorAll('.tab').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      document.getElementById('marks-area').innerHTML = '';
      document.getElementById('cls').innerHTML = '<option value="">— select —</option>';
      document.getElementById('subj').innerHTML = '<option value="">— select —</option>';
      loadClasses();
    }

    async function loadClasses() {
      const r = await fetch(`/api/rmt/classes?token=${TOKEN}&section=${curSec}`);
      const d = await r.json();
      const sel = document.getElementById('cls');
      sel.innerHTML = '<option value="">— select class —</option>';
      (d.classes||[]).forEach(c => {
        const o = document.createElement('option');
        o.value=c.id; o.dataset.grade=c.grade;
        o.textContent=`${c.name} (${c.grade})`; sel.appendChild(o);
      });
    }

    async function loadSubjects() {
      const clsEl = document.getElementById('cls');
      const grade = clsEl.options[clsEl.selectedIndex]?.dataset.grade || '';
      const r = await fetch(`/api/rmt/subjects?token=${TOKEN}&grade=${encodeURIComponent(grade)}`);
      const d = await r.json();
      const sel = document.getElementById('subj');
      sel.innerHTML = '<option value="">— select subject —</option>';
      (d.subjects||[]).forEach(s => {
        const o = document.createElement('option');
        o.value=s.id; o.dataset.max=s.max_marks;
        o.textContent=`${s.code} — ${s.name} (/${s.max_marks})`; sel.appendChild(o);
      });
    }

    async function loadMarks() {
      const cls=document.getElementById('cls').value;
      const subjEl=document.getElementById('subj');
      const subj=subjEl.value;
      if(!cls||!subj){showToast('Select class and subject first');return;}
      curMax=Number(subjEl.options[subjEl.selectedIndex]?.dataset.max||100);
      const term=document.getElementById('term').value;
      const yr=document.getElementById('yr').value;
      const typ=document.getElementById('typ').value;
      const r=await fetch(`/api/rmt/marks?token=${TOKEN}&cls=${cls}&subj=${subj}&term=${encodeURIComponent(term)}&year=${yr}&type=${encodeURIComponent(typ)}`);
      const d=await r.json();
      render(d.learners||[], d.existing||{}, cls, subj, term, yr, typ);
    }

    const lvColors={EE1:'#00e676',EE2:'#00c875',ME1:'#1e90ff',ME2:'#42a5f5',AE1:'#ffc93c',AE2:'#ff9800',BE1:'#ff4d5e',BE2:'#c62828'};

    function getLevel(v) {
      const pct=v/curMax*100;
      for(const l of LEVELS){if(pct>=l.min&&pct<=l.max) return l;}
      return LEVELS[LEVELS.length-1];
    }

    function render(learners, existing, cls, subj, term, yr, typ) {
      if(!learners.length){
        document.getElementById('marks-area').innerHTML='<div class="card" style="color:var(--sub);text-align:center;padding:30px">No active learners found for this class.</div>';return;
      }
      const rows=learners.map(l=>{
        const ex=existing[String(l.id)]||{};
        const ab=ex.is_absent?'checked':'';
        const mv=ex.marks!==undefined&&ex.marks!==null?ex.marks:'';
        return `<tr>
          <td style="color:var(--sub);font-size:12px">${l.admission_no||''}</td>
          <td style="font-weight:600">${l.name}</td>
          <td><input class="mi" type="number" id="m_${l.id}" min="0" max="${curMax}" step="0.5" value="${mv}" oninput="updateLv(${l.id})"></td>
          <td><span id="lv_${l.id}"></span></td>
          <td style="text-align:center"><input class="ab" type="checkbox" id="ab_${l.id}" ${ab} onchange="toggleAb(${l.id})"></td>
        </tr>`;
      }).join('');
      document.getElementById('marks-area').innerHTML=`
      <div class="card">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;flex-wrap:wrap;gap:8px">
          <div class="card-title" style="margin:0">📝 Enter Marks — Max: ${curMax}</div>
          <button class="btn btn-green" onclick="saveAll(${cls},${subj},'${term}','${yr}','${typ}')">💾 Save All Marks</button>
        </div>
        <div class="tbl-wrap"><table>
          <thead><tr><th>Adm No</th><th>Learner Name</th><th>Marks /${curMax}</th><th>Level</th><th>Absent</th></tr></thead>
          <tbody>${rows}</tbody>
        </table></div>
      </div>`;
      learners.forEach(l=>updateLv(l.id));
    }

    function updateLv(lid) {
      const inp=document.getElementById('m_'+lid);
      const lv=document.getElementById('lv_'+lid);
      if(!inp||!lv) return;
      const v=parseFloat(inp.value);
      if(isNaN(v)){lv.innerHTML='';return;}
      const lobj=getLevel(v);
      lv.innerHTML=`<span class="lv-pill" style="background:${lvColors[lobj.level]||'#333'};color:#000">${lobj.level}</span>`;
    }

    function toggleAb(lid) {
      const ab=document.getElementById('ab_'+lid);
      const inp=document.getElementById('m_'+lid);
      inp.disabled=ab.checked;
      if(ab.checked) inp.value='';
      updateLv(lid);
    }

    async function saveAll(cls,subj,term,yr,typ) {
      const entries=[];
      document.querySelectorAll('tbody tr').forEach(tr=>{
        const inp=tr.querySelector('.mi');
        const ab=tr.querySelector('.ab');
        if(!inp) return;
        const lid=inp.id.replace('m_','');
        entries.push({learner_id:Number(lid),marks:inp.value===''?null:Number(inp.value),is_absent:ab?ab.checked:false});
      });
      const saveBtn=document.querySelector('.btn-green');
      if(saveBtn){saveBtn.disabled=true;saveBtn.textContent='⏳ Saving…';}
      try {
        const r=await fetch('/api/rmt/save',{
          method:'POST',headers:{'Content-Type':'application/json'},
          body:JSON.stringify({token:TOKEN,cls_id:cls,subj_id:subj,term,year:yr,atype:typ,entries})
        });
        const d=await r.json();
        showToast(`✅ Saved ${d.saved} marks · Absent: ${d.absent} · Skipped: ${d.skipped}`);
      } catch(e){showToast('❌ Error saving: '+e.message);}
      finally{if(saveBtn){saveBtn.disabled=false;saveBtn.textContent='💾 Save All Marks';}}
    }

    function showToast(msg,dur=3500){
      const t=document.getElementById('toast');
      t.textContent=msg;t.classList.add('show');
      setTimeout(()=>t.classList.remove('show'),dur);
    }

    document.getElementById('yr').value=new Date().getFullYear();
    fetch(`/api/rmt/school?token=${TOKEN}`).then(r=>r.json()).then(d=>{
      if(d.name) document.getElementById('school-name').textContent=d.name;
    }).catch(()=>{});
    loadClasses();
    </script>
    </body>
    </html>"""

    # ── Routes ────────────────────────────────────────────────────────────────────

    @app.route("/health")
    def health():
        # No auth required — used for liveness checks
        return jsonify({"status": "ok", "server": "iQ Cloud Marks Server",
                        "db": "postgresql" if USE_POSTGRES else "sqlite",
                        "token_required": bool(ADMIN_TOKEN)})

    @app.route("/")
    def index():
        return jsonify({"status": "ok", "service": "iQ Cloud Marks Server",
                        "message": "Server is running. Use the iQ desktop app to connect."})

    @app.route("/enter/<section>")
    def teacher_ui(section):
        if section not in ("junior","upper","lower","preprimary"):
            abort(404)
        tok = request.args.get("token","")
        if not _check_token(tok):
            abort(403)
        levels_json = json.dumps(_cbc_levels())
        html = (_TEACHER_HTML
                .replace("__TOKEN__", tok)
                .replace("__SECTION__", section)
                .replace("__LEVELS__", levels_json))
        return html

    @app.route("/api/rmt/school")
    @require_token
    def api_school():
        try:
            row = _fetchone("SELECT name FROM cloud_school WHERE id=1")
            return jsonify({"name": row["name"] if row else "iQ School"})
        except Exception:
            return jsonify({"name": "iQ School"})

    @app.route("/api/rmt/classes")
    @require_token
    def api_classes():
        section = request.args.get("section","junior")
        rows = _fetchall(
            "SELECT id,name,grade FROM cloud_classes WHERE section=? ORDER BY name",
            (section,)
        )
        return jsonify({"classes": rows})

    @app.route("/api/rmt/subjects")
    @require_token
    def api_subjects():
        grade   = request.args.get("grade","")
        sec_key = _grade_to_section(grade)
        rows = _fetchall(
            "SELECT id,code,name,max_marks,sort_order FROM cloud_subjects "
            "WHERE section_key=? AND is_active=1 ORDER BY sort_order,name",
            (sec_key,)
        )
        return jsonify({"subjects": rows})

    @app.route("/api/rmt/marks")
    @require_token
    def api_marks():
        cls_id  = int(request.args.get("cls",  0))
        subj_id = int(request.args.get("subj", 0))
        term    = request.args.get("term",  "Term 1")
        year    = request.args.get("year",  "")
        atype   = request.args.get("type",  "End of Term")

        learners = _fetchall(
            "SELECT id, admission_no, "
            "UPPER(first_name)||' '||UPPER(last_name) AS name "
            "FROM cloud_learners WHERE class_id=? ORDER BY first_name,last_name",
            (cls_id,)
        )
        ex_row = _fetchone(
            "SELECT id FROM cloud_assessments "
            "WHERE class_id=? AND subject_id=? AND term=? AND academic_year=? AND type=?",
            (cls_id, subj_id, term, year, atype)
        )
        existing = {}
        if ex_row:
            for r in _fetchall(
                "SELECT learner_id,marks,is_absent FROM cloud_results WHERE assessment_id=?",
                (ex_row["id"],)
            ):
                existing[str(r["learner_id"])] = {"marks": r["marks"], "is_absent": bool(r["is_absent"])}
        return jsonify({"learners": learners, "existing": existing})

    @app.route("/api/rmt/save", methods=["POST"])
    def api_save():
        data    = request.get_json(force=True) or {}
        tok     = data.get("token","")
        if not _check_token(tok): abort(403)
        cls_id  = int(data.get("cls_id",  0))
        subj_id = int(data.get("subj_id", 0))
        term    = data.get("term",  "Term 1")
        year    = data.get("year",  "")
        atype   = data.get("atype", "End of Term")
        entries = data.get("entries", [])

        s = _fetchone("SELECT max_marks FROM cloud_subjects WHERE id=?", (subj_id,))
        max_m = s["max_marks"] if s else 100

        ex = _fetchone(
            "SELECT id FROM cloud_assessments "
            "WHERE class_id=? AND subject_id=? AND term=? AND academic_year=? AND type=?",
            (cls_id, subj_id, term, year, atype)
        )
        if ex:
            aid = ex["id"]
        else:
            if USE_POSTGRES:
                cur = _exec(
                    "INSERT INTO cloud_assessments (name,type,class_id,subject_id,term,academic_year,max_marks,status) "
                    "VALUES (?,?,?,?,?,?,?,'Ongoing') RETURNING id",
                    (f"{atype} {term} {year}", atype, cls_id, subj_id, term, year, max_m)
                )
                aid = cur.fetchone()["id"]
            else:
                _exec(
                    "INSERT INTO cloud_assessments (name,type,class_id,subject_id,term,academic_year,max_marks,status) "
                    "VALUES (?,?,?,?,?,?,?,'Ongoing')",
                    (f"{atype} {term} {year}", atype, cls_id, subj_id, term, year, max_m)
                )
                aid = get_db().execute("SELECT last_insert_rowid()").fetchone()[0]
            _commit()

        saved = absent = skipped = 0
        now   = datetime.utcnow().strftime("%Y-%m-%d")
        for e in entries:
            lid = e["learner_id"]
            try:
                if e.get("is_absent"):
                    _exec(
                        "INSERT INTO cloud_results (learner_id,assessment_id,marks,performance_level,points,is_absent,entry_date,synced_to_desktop) "
                        "VALUES (?,?,NULL,'AB',0,1,?,0) "
                        "ON CONFLICT(learner_id,assessment_id) DO UPDATE SET "
                        "marks=NULL,performance_level='AB',points=0,is_absent=1,entry_date=?,synced_to_desktop=0",
                        (lid, aid, now, now)
                    )
                    absent += 1
                else:
                    mv = float(e["marks"]) if e.get("marks") is not None else None
                    if mv is None or mv < 0 or mv > max_m:
                        skipped += 1; continue
                    lv, pts = _cbc_level(mv, max_m)
                    _exec(
                        "INSERT INTO cloud_results (learner_id,assessment_id,marks,performance_level,points,is_absent,entry_date,synced_to_desktop) "
                        "VALUES (?,?,?,?,?,0,?,0) "
                        "ON CONFLICT(learner_id,assessment_id) DO UPDATE SET "
                        "marks=excluded.marks,performance_level=excluded.performance_level,"
                        "points=excluded.points,is_absent=0,entry_date=?,synced_to_desktop=0",
                        (lid, aid, mv, lv, pts, now, now)
                    )
                    saved += 1
            except Exception as ex2:
                log.warning(f"Save row error: {ex2}")
                skipped += 1
        _commit()
        return jsonify({"saved": saved, "absent": absent, "skipped": skipped})

    # ── Sync endpoints (desktop app ↔ cloud) ──────────────────────────────────────

    @app.route("/api/sync/pull")
    @require_token
    def sync_pull():
        """Desktop pulls marks submitted by teachers since last sync.
        Only returns records with submitted_by='teacher' (not ones the desktop pushed).
        Does NOT mark as synced here — desktop calls /api/sync/ack after saving.
        """
        since = request.args.get("since", "2000-01-01T00:00:00")
        try:
            rows = _fetchall(
                "SELECT cr.id, cr.marks, cr.performance_level, cr.points, "
                "cr.is_absent, cr.entry_date, "
                "cl.admission_no, cl.first_name, cl.last_name, "
                "cs.code as subject_code, cs.name as subject_name, "
                "cs.max_marks as s_max_marks, "
                "ca.term, ca.academic_year, ca.type as atype, ca.max_marks, "
                "cc.name as class_name, cc.grade "
                "FROM cloud_results cr "
                "JOIN cloud_assessments ca ON ca.id = cr.assessment_id "
                "JOIN cloud_learners    cl ON cl.id = cr.learner_id "
                "JOIN cloud_subjects    cs ON cs.id = ca.subject_id "
                "JOIN cloud_classes     cc ON cc.id = ca.class_id "
                "WHERE cr.synced_to_desktop = 0 "
                "  AND cr.submitted_by = 'teacher' "
                "ORDER BY cr.id LIMIT 2000",
                ()
            )
            return jsonify({"records": rows, "count": len(rows)})
        except Exception as e:
            log.error(f"sync/pull error: {e}")
            return jsonify({"records": [], "count": 0, "error": str(e)})

    @app.route("/api/sync/ack", methods=["POST"])
    @require_token
    def sync_ack():
        """Desktop calls this after successfully saving pulled records.
        Only then do we mark records as synced — prevents data loss on network drops.
        """
        data = request.get_json(force=True) or {}
        ids  = data.get("ids", [])
        if not ids:
            return jsonify({"ok": True, "acked": 0})
        try:
            placeholders = ",".join(["?"] * len(ids))
            _exec(
                f"UPDATE cloud_results SET synced_to_desktop=1 WHERE id IN ({placeholders})",
                ids
            )
            _commit()
            return jsonify({"ok": True, "acked": len(ids)})
        except Exception as e:
            log.error(f"sync/ack error: {e}")
            return jsonify({"ok": False, "error": str(e)}), 500

    @app.route("/api/sync/push", methods=["POST"])
    @require_token
    def sync_push():
        """Desktop pushes local marks up to cloud DB."""
        data    = request.get_json(force=True) or {}
        records = data.get("records", [])
        saved = errors = 0
        now   = datetime.utcnow().strftime("%Y-%m-%d")
        for rec in records:
            try:
                cls_id  = rec["class_id"]; subj_id = rec["subject_id"]
                term    = rec["term"];     year    = rec["academic_year"]
                atype   = rec.get("atype","End of Term")
                lid     = rec["learner_id"]; is_abs  = int(rec.get("is_absent",0))
                marks   = None if is_abs else rec.get("marks")

                ex = _fetchone(
                    "SELECT id FROM cloud_assessments "
                    "WHERE class_id=? AND subject_id=? AND term=? AND academic_year=? AND type=?",
                    (cls_id, subj_id, term, year, atype)
                )
                if ex:
                    aid = ex["id"]
                else:
                    max_m = rec.get("max_marks", 100)
                    if USE_POSTGRES:
                        cur = _exec(
                            "INSERT INTO cloud_assessments (name,type,class_id,subject_id,term,academic_year,max_marks,status) "
                            "VALUES (?,?,?,?,?,?,?,'Ongoing') RETURNING id",
                            (f"{atype} {term} {year}", atype, cls_id, subj_id, term, year, max_m)
                        )
                        aid = cur.fetchone()["id"]
                    else:
                        _exec(
                            "INSERT OR IGNORE INTO cloud_assessments "
                            "(name,type,class_id,subject_id,term,academic_year,max_marks,status) "
                            "VALUES (?,?,?,?,?,?,?,'Ongoing')",
                            (f"{atype} {term} {year}", atype, cls_id, subj_id, term, year, max_m)
                        )
                        row = _fetchone(
                            "SELECT id FROM cloud_assessments "
                            "WHERE class_id=? AND subject_id=? AND term=? AND academic_year=? AND type=?",
                            (cls_id, subj_id, term, year, atype)
                        )
                        aid = row["id"]
                    _commit()

                s = _fetchone("SELECT max_marks FROM cloud_subjects WHERE id=?", (subj_id,))
                max_m = s["max_marks"] if s else rec.get("max_marks", 100)
                if is_abs:
                    _exec(
                        "INSERT INTO cloud_results (learner_id,assessment_id,marks,performance_level,points,is_absent,entry_date,submitted_by) "
                        "VALUES (?,?,NULL,'AB',0,1,?,'desktop') "
                        "ON CONFLICT(learner_id,assessment_id) DO UPDATE SET "
                        "marks=NULL,performance_level='AB',points=0,is_absent=1,entry_date=?,synced_to_desktop=1",
                        (lid, aid, now, now)
                    )
                else:
                    lv, pts = _cbc_level(float(marks), max_m)
                    _exec(
                        "INSERT INTO cloud_results (learner_id,assessment_id,marks,performance_level,points,is_absent,entry_date,submitted_by) "
                        "VALUES (?,?,?,?,?,0,?,'desktop') "
                        "ON CONFLICT(learner_id,assessment_id) DO UPDATE SET "
                        "marks=excluded.marks,performance_level=excluded.performance_level,"
                        "points=excluded.points,is_absent=0,entry_date=?,synced_to_desktop=1",
                        (lid, aid, float(marks), lv, pts, now)
                    )
                _commit()
                saved += 1
            except Exception as e:
                log.warning(f"push row error: {e}")
                errors += 1
        return jsonify({"ok": True, "saved": saved, "errors": errors})

    @app.route("/api/sync/reset", methods=["POST"])
    @require_token
    def sync_reset():
        """Wipe all classes, learners, subjects, assessments and results from cloud DB."""
        try:
            for tbl in ("cloud_results","cloud_assessments","cloud_learners",
                        "cloud_subjects","cloud_classes","cloud_school"):
                try: _exec(f"DELETE FROM {tbl}")
                except Exception: pass
            _commit()
            return jsonify({"ok": True, "message": "Cloud DB wiped successfully"})
        except Exception as e:
            return jsonify({"ok": False, "error": str(e)}), 500

    @app.route("/api/sync/schema", methods=["POST"])
    @require_token
    def sync_schema():
        """
        Desktop uploads the school's classes, learners, subjects so teachers
        see real data. Call this once after first deploy, and whenever you add
        new learners/classes.
        """
        data = request.get_json(force=True) or {}
        try:
            # School info
            school = data.get("school", {})
            if school:
                try:
                    _exec("DELETE FROM cloud_school")
                    _exec("INSERT INTO cloud_school (id,name,config) VALUES (1,?,?)",
                          (school.get("name","iQ School"), json.dumps(school.get("config",{}))))
                except Exception: pass

            # CBC levels
            cbc_levels = data.get("cbc_levels", [])
            if cbc_levels:
                try:
                    _exec("INSERT INTO cloud_meta(key,value) VALUES('cbc_levels',?) "
                          "ON CONFLICT(key) DO UPDATE SET value=excluded.value",
                          (json.dumps(cbc_levels),))
                except Exception: pass

            # Classes
            classes = data.get("classes", [])
            for cl in classes:
                sec = _grade_to_section(cl.get("grade",""))
                try:
                    _exec(
                        "INSERT INTO cloud_classes(id,name,grade,section) VALUES(?,?,?,?) "
                        "ON CONFLICT(id) DO UPDATE SET name=excluded.name,grade=excluded.grade,section=excluded.section",
                        (cl["id"], cl["name"], cl["grade"], sec)
                    )
                except Exception as e:
                    log.warning(f"class insert: {e}")

            # Subjects
            subjects = data.get("subjects", [])
            for s in subjects:
                try:
                    _exec(
                        "INSERT INTO cloud_subjects(id,code,name,max_marks,section_key,sort_order,is_active) "
                        "VALUES(?,?,?,?,?,?,?) "
                        "ON CONFLICT(id) DO UPDATE SET code=excluded.code,name=excluded.name,"
                        "max_marks=excluded.max_marks,section_key=excluded.section_key,"
                        "sort_order=excluded.sort_order,is_active=excluded.is_active",
                        (s["id"], s.get("code",""), s["name"], s.get("max_marks",100),
                         s.get("section_key","junior"), s.get("sort_order",0), s.get("is_active",1))
                    )
                except Exception as e:
                    log.warning(f"subject insert: {e}")

            # Learners
            learners = data.get("learners", [])
            for l in learners:
                try:
                    _exec(
                        "INSERT INTO cloud_learners(id,admission_no,first_name,last_name,class_id) "
                        "VALUES(?,?,?,?,?) "
                        "ON CONFLICT(id) DO UPDATE SET admission_no=excluded.admission_no,"
                        "first_name=excluded.first_name,last_name=excluded.last_name,"
                        "class_id=excluded.class_id",
                        (l["id"], l.get("admission_no",""), l.get("first_name",""),
                         l.get("last_name",""), l.get("class_id"))
                    )
                except Exception as e:
                    log.warning(f"learner insert: {e}")

            _commit()
            return jsonify({
                "ok": True,
                "classes": len(classes),
                "subjects": len(subjects),
                "learners": len(learners),
            })
        except Exception as e:
            log.error(f"sync/schema error: {e}")
            return jsonify({"ok": False, "error": str(e)}), 500

    # ── Startup ───────────────────────────────────────────────────────────────────
    with app.app_context():
        try:
            init_db()
        except Exception as e:
            log.error(f"DB init failed: {e}")

    if not ADMIN_TOKEN:
        log.warning("⚠  IQ_ADMIN_TOKEN not set — server is open (set it in Render env vars!)")
    else:
        log.info(f"✅  Admin token configured ({len(ADMIN_TOKEN)} chars)")

    return app


